insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(6317, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with acute cardiogenic pulmonary oedema presents with pink frothy sputum, orthopnea, and bilateral crackles. Which hemodynamic mechanism best explains the fluid accumulation?', '["Decreased plasma oncotic pressure from hypoalbuminemia", "Increased pulmonary capillary hydrostatic pressure from left ventricular failure", "Increased pulmonary capillary permeability from sepsis", "Lymphatic obstruction from mediastinal malignancy"]'::jsonb, 1, 'Cardiogenic pulmonary oedema results from elevated left atrial and pulmonary capillary hydrostatic pressure due to LV failure, forcing fluid into the alveoli.', 'Pre-Council', '🎓', true),
(6318, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing intervention is the priority for a patient in acute pulmonary oedema with SpO2 88% on room air and audible crackles?', '["Position supine to reduce cardiac workload", "High-Fowler''s position and administer high-flow oxygen", "Encourage oral fluids to thin secretions", "Apply lower limb compression stockings"]'::jsonb, 1, 'Upright positioning reduces venous return and improves lung expansion; high-flow oxygen addresses hypoxemia. Both are first-line priority actions in acute pulmonary oedema.', 'Pre-Council', '🎓', true),
(6319, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'IV furosemide is administered for acute pulmonary oedema. Besides diuresis, what additional early therapeutic effect makes it useful in this emergency?', '["Bronchodilation", "Venodilation reducing preload", "Positive inotropy", "Afterload reduction via arterial vasodilation"]'::jsonb, 1, 'Furosemide causes venodilation within minutes, before diuresis begins, which reduces preload and pulmonary venous congestion.', 'Pre-Council', '🎓', true),
(6320, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient receiving IV nitroglycerin for cardiogenic pulmonary oedema develops a blood pressure of 82/50 mmHg. What is the nurse''s priority action?', '["Increase the infusion rate to improve cardiac output", "Stop or slow the infusion and reassess blood pressure", "Administer a fluid bolus and continue the infusion unchanged", "Switch to sublingual nitroglycerin"]'::jsonb, 1, 'Nitroglycerin causes venodilation and arterial dilation and can precipitate hypotension; the infusion should be slowed or stopped and blood pressure reassessed to prevent hypoperfusion.', 'Pre-Council', '🎓', true),
(6321, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Noncardiogenic pulmonary oedema (ARDS-type) differs from cardiogenic pulmonary oedema primarily in that it has:', '["Normal or low pulmonary capillary wedge pressure with increased capillary permeability", "Elevated BNP with an S3 gallop", "Response to diuretics as first-line treatment", "Presence of jugular venous distension as the dominant sign"]'::jsonb, 0, 'Noncardiogenic oedema arises from increased alveolar-capillary membrane permeability (e.g., sepsis, ARDS) with a normal or low pulmonary capillary wedge pressure, unlike cardiogenic oedema.', 'Pre-Council', '🎓', true),
(6322, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which ABG pattern is most expected in the early stage of acute pulmonary oedema?', '["Respiratory acidosis with hypercapnia", "Respiratory alkalosis with hypoxemia", "Metabolic acidosis with compensatory hyperventilation", "Normal ABG values"]'::jsonb, 1, 'Early pulmonary oedema causes hyperventilation from hypoxemia and anxiety, producing respiratory alkalosis (low CO2) with hypoxemia; hypercapnia develops later as the patient fatigues.', 'Pre-Council', '🎓', true),
(6323, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with pulmonary oedema is started on BiPAP. What is the expected physiological benefit?', '["Increases preload to improve cardiac output", "Reduces work of breathing and improves alveolar recruitment via positive pressure", "Eliminates the need for diuretic therapy", "Increases venous return to the right heart"]'::jsonb, 1, 'Positive pressure ventilation recruits collapsed, fluid-filled alveoli, decreases work of breathing, and reduces preload/afterload, improving oxygenation in cardiogenic pulmonary oedema.', 'Pre-Council', '🎓', true),
(6324, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Morphine sulfate, historically used in acute pulmonary oedema, provides therapeutic benefit primarily through:', '["Bronchodilation and a mucolytic effect", "Venodilation reducing preload and reducing anxiety-driven tachypnea", "Direct diuretic action on the renal tubule", "Positive inotropic effect on the myocardium"]'::jsonb, 1, 'Morphine reduces preload through venodilation and reduces sympathetic drive/anxiety, though its routine use is now more cautious due to respiratory depression risk.', 'Pre-Council', '🎓', true),
(6325, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which finding on chest assessment is a hallmark of pulmonary oedema versus pneumonia?', '["Bilateral bibasilar crackles with symmetric distribution", "Unilateral dullness to percussion with bronchial breath sounds", "Localized wheeze over one lobe", "Absent breath sounds unilaterally"]'::jsonb, 0, 'Pulmonary oedema classically produces bilateral, symmetric crackles reflecting diffuse alveolar fluid, unlike the localized findings typical of pneumonia.', 'Pre-Council', '🎓', true),
(6326, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with flash pulmonary oedema secondary to a hypertensive emergency should receive which class of medication as a primary intervention?', '["Beta-blockers to slow heart rate", "IV vasodilators (e.g., nitroglycerin, nitroprusside) to rapidly reduce afterload", "Oral ACE inhibitors", "IV antibiotics"]'::jsonb, 1, 'Flash pulmonary oedema from a hypertensive crisis is treated with rapid-acting IV vasodilators to reduce afterload and pulmonary venous pressure quickly.', 'Pre-Council', '🎓', true),
(6327, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which laboratory marker helps differentiate cardiogenic pulmonary oedema from ARDS?', '["Elevated BNP (B-type natriuretic peptide)", "Elevated white cell count", "Positive blood culture", "Elevated D-dimer alone"]'::jsonb, 0, 'BNP is elevated in cardiogenic pulmonary oedema due to ventricular wall stress; it is typically normal or only mildly elevated in noncardiogenic (ARDS) oedema.', 'Pre-Council', '🎓', true),
(6328, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient in acute pulmonary oedema requires intubation. Which ventilator strategy is most appropriate initially?', '["Zero PEEP to avoid barotrauma", "Application of PEEP to improve oxygenation and reduce venous return", "Permissive hypercapnia with low tidal volumes chosen purely for haemodynamic benefit", "High tidal volumes above 10 mL/kg to maximize alveolar recruitment"]'::jsonb, 1, 'PEEP recruits fluid-filled alveoli, improves oxygenation, and reduces venous return/preload, which is beneficial in cardiogenic pulmonary oedema.', 'Pre-Council', '🎓', true),
(6329, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which underlying cause is a common precipitant of noncardiogenic pulmonary oedema in the ICU?', '["Mitral valve stenosis", "Sepsis / systemic inflammatory response", "Left ventricular hypertrophy", "Constrictive pericarditis"]'::jsonb, 1, 'Sepsis triggers systemic inflammation causing increased capillary permeability, leading to noncardiogenic (ARDS-type) pulmonary oedema.', 'Pre-Council', '🎓', true),
(6330, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During assessment of a patient with pulmonary oedema, the nurse notes an S3 heart sound. This finding suggests:', '["A normal physiological variant in older adults", "Volume overload or left ventricular dysfunction", "Aortic stenosis", "Complete heart block"]'::jsonb, 1, 'An S3 gallop reflects rapid ventricular filling in the setting of volume overload or reduced ventricular compliance, common in heart-failure-induced pulmonary oedema.', 'Pre-Council', '🎓', true),
(6331, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with acute pulmonary oedema on strict intake and output monitoring produces only 20 mL of urine in 2 hours despite IV furosemide 80 mg. What is the priority nursing action?', '["Administer another diuretic dose without further assessment", "Assess for hypotension and reassess renal perfusion, and notify the physician", "Increase IV fluids to promote diuresis", "Discontinue oxygen therapy"]'::jsonb, 1, 'Poor diuretic response may indicate inadequate renal perfusion (e.g., cardiogenic shock), requiring reassessment of hemodynamic status before further diuretic dosing.', 'Pre-Council', '🎓', true),
(6332, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A post-operative patient develops sudden dyspnea, pleuritic chest pain, and tachycardia. Which finding would most increase clinical suspicion of PE using the Wells criteria?', '["Clinical signs of DVT (leg swelling, tenderness)", "Productive cough with green sputum", "Fever of 38.9\u00b0C", "Bilateral ankle oedema"]'::jsonb, 0, 'Clinical signs of DVT are a major weighted component of the Wells score for PE, strongly increasing pretest probability.', 'Pre-Council', '🎓', true),
(6333, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with suspected PE has a low Wells score. Which test is the appropriate next step?', '["Immediate CT pulmonary angiography regardless of score", "D-dimer testing to help rule out PE", "V/Q scan only", "Pulmonary angiography"]'::jsonb, 1, 'In low pretest probability, a negative D-dimer has high negative predictive value and can safely rule out PE without further imaging.', 'Pre-Council', '🎓', true),
(6334, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which ECG finding, though neither sensitive nor specific, is classically associated with acute PE and right heart strain?', '["S1Q3T3 pattern", "Delta wave", "U waves", "Prolonged QT interval"]'::jsonb, 0, 'The S1Q3T3 pattern (S wave in lead I, Q wave and inverted T wave in lead III) reflects acute right ventricular strain seen in some PE cases.', 'Pre-Council', '🎓', true),
(6335, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A massive PE causes obstructive shock. What is the primary hemodynamic mechanism?', '["Left ventricular failure from myocardial infarction", "Acute right ventricular failure from increased pulmonary vascular resistance", "Hypovolemia from third-spacing", "Distributive shock from vasodilation"]'::jsonb, 1, 'A large embolus obstructs pulmonary blood flow, acutely increasing RV afterload, causing RV failure/dilation and decreased LV preload, producing obstructive shock.', 'Pre-Council', '🎓', true),
(6336, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which patient is at highest risk for pulmonary embolism based on the components of Virchow''s triad?', '["An ambulatory patient on daily aspirin", "A post-operative orthopedic surgery patient with prolonged immobility", "A patient with well-controlled hypertension", "A patient on a low-fat diet"]'::jsonb, 1, 'Prolonged immobility after major orthopedic surgery causes venous stasis, one of the three components of Virchow''s triad, a major risk factor for PE.', 'Pre-Council', '🎓', true),
(6337, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'For a hemodynamically unstable patient with confirmed massive PE and no contraindications, which treatment is indicated?', '["Unfractionated heparin infusion alone", "Systemic thrombolytic therapy (e.g., alteplase)", "Oral warfarin loading dose", "Aspirin 325 mg alone"]'::jsonb, 1, 'Thrombolytics are indicated in massive PE with hemodynamic instability to rapidly dissolve the clot and reverse RV failure/shock, when no contraindications exist.', 'Pre-Council', '🎓', true),
(6338, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient receiving unfractionated heparin for PE has an aPTT of 110 seconds. What is the priority nursing action?', '["Increase the heparin infusion rate", "Hold or slow the infusion per protocol and notify the physician", "Administer protamine sulfate immediately without an order", "Continue the infusion unchanged, as this is therapeutic"]'::jsonb, 1, 'An aPTT of 110 seconds is supratherapeutic and increases bleeding risk; the infusion should be held/adjusted per protocol and the physician notified.', 'Pre-Council', '🎓', true),
(6339, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which clinical sign suggests right ventricular strain in a patient with acute PE?', '["Bounding peripheral pulses", "Jugular venous distension and hepatomegaly", "Hyperresonance on lung percussion", "Bradycardia"]'::jsonb, 1, 'Acute RV strain from PE causes systemic venous congestion, manifesting as jugular venous distension, hepatomegaly, and peripheral oedema.', 'Pre-Council', '🎓', true),
(6340, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with a confirmed DVT has a contraindication to anticoagulation and is at risk for PE. Which intervention is most appropriate?', '["Inferior vena cava (IVC) filter placement", "High-dose aspirin therapy", "Elastic compression stockings alone", "Bed rest until symptoms resolve"]'::jsonb, 0, 'An IVC filter mechanically prevents emboli from traveling to the lungs when anticoagulation is contraindicated, such as with active bleeding.', 'Pre-Council', '🎓', true),
(6341, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which ABG finding is most classic in acute PE?', '["Hypoxemia with hypocapnia (respiratory alkalosis)", "Hypoxemia with hypercapnia (respiratory acidosis)", "Normal PaO2 with metabolic acidosis", "Hyperoxemia with hypercapnia"]'::jsonb, 0, 'PE typically causes hyperventilation from hypoxemia and pain/anxiety, resulting in hypocapnia and respiratory alkalosis alongside hypoxemia from V/Q mismatch.', 'Pre-Council', '🎓', true),
(6342, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The gold-standard diagnostic imaging for confirming PE in a hemodynamically stable patient with adequate renal function is:', '["Chest X-ray", "CT pulmonary angiography", "Echocardiography", "12-lead ECG"]'::jsonb, 1, 'CT pulmonary angiography (CTPA) is the first-line diagnostic imaging test for PE in most patients due to its high sensitivity and specificity.', 'Pre-Council', '🎓', true),
(6343, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient on IV heparin for PE develops a sudden drop in platelet count and new limb ischemia. This suggests:', '["Heparin-induced thrombocytopenia (HIT)", "A normal expected heparin effect", "Disseminated intravascular coagulation from the PE itself", "Vitamin K deficiency"]'::jsonb, 0, 'HIT is an immune-mediated reaction to heparin causing thrombocytopenia and paradoxical thrombosis; heparin must be stopped immediately and an alternative anticoagulant started.', 'Pre-Council', '🎓', true),
(6344, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ''saddle embolus'' is best described as:', '["A small peripheral embolus lodged in a subsegmental artery", "A large embolus straddling the bifurcation of the main pulmonary artery", "An embolus confined to the bronchial circulation", "A chronic organized thrombus in a pulmonary vein"]'::jsonb, 1, 'A saddle embolus lodges at the bifurcation of the main pulmonary artery into its right and left branches, often causing severe hemodynamic compromise.', 'Pre-Council', '🎓', true),
(6345, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing measure is most effective for PE prophylaxis in immobile ICU patients?', '["Strict bed rest with legs elevated only", "Sequential compression devices and/or pharmacologic prophylaxis such as LMWH", "High-flow oxygen therapy", "Daily chest X-rays"]'::jsonb, 1, 'Mechanical (sequential compression devices) and pharmacologic (LMWH/heparin) prophylaxis reduce venous stasis and clot formation, the mainstay of PE prevention in immobile patients.', 'Pre-Council', '🎓', true),
(6346, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient post-PE thrombolysis develops a sudden severe headache and decreased level of consciousness. The nurse should suspect:', '["A migraine caused by stress", "Intracranial hemorrhage", "An expected medication side effect requiring no action", "Hypoglycemia"]'::jsonb, 1, 'Thrombolytics carry a significant risk of intracranial hemorrhage; new neurological changes after thrombolysis are a medical emergency requiring immediate evaluation.', 'Pre-Council', '🎓', true),
(6347, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In a patient with submassive PE (right ventricular dysfunction but hemodynamically stable), the primary treatment approach is:', '["Systemic thrombolytics for all patients", "Therapeutic anticoagulation with close monitoring for deterioration", "Surgical embolectomy as first-line therapy", "Observation without anticoagulation"]'::jsonb, 1, 'Submassive PE with preserved blood pressure is generally managed with anticoagulation; thrombolytics are reserved for those who deteriorate, given the bleeding risk.', 'Pre-Council', '🎓', true),
(6348, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A nurse is caring for a patient with acute PE who suddenly becomes pulseless with pulseless electrical activity (PEA). This is most consistent with:', '["A small subsegmental embolus", "Massive PE causing acute obstructive cardiac arrest", "A vasovagal response", "A hypoglycemic episode"]'::jsonb, 1, 'Massive PE can acutely obstruct right ventricular outflow, causing sudden cardiovascular collapse and PEA arrest due to loss of cardiac output.', 'Pre-Council', '🎓', true),
(6349, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Long-term anticoagulation with a DOAC (e.g., rivaroxaban) after a first provoked PE is typically continued for a minimum of:', '["3 days", "3 to 6 months, depending on provoking factors", "24 hours", "Lifelong regardless of cause"]'::jsonb, 1, 'Standard duration for a first provoked PE is generally at least 3 to 6 months; the duration varies with recurrence risk and whether the PE was provoked or unprovoked.', 'Pre-Council', '🎓', true),
(6350, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Pulmonary hypertension is hemodynamically defined as a mean pulmonary artery pressure at rest greater than:', '["10 mmHg", "20 mmHg", "40 mmHg", "60 mmHg"]'::jsonb, 1, 'The current hemodynamic definition of pulmonary hypertension is a mean pulmonary artery pressure greater than 20 mmHg at rest, measured by right heart catheterization.', 'Pre-Council', '🎓', true),
(6351, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which physical exam finding is characteristic of pulmonary hypertension?', '["Bounding carotid pulses", "A loud or accentuated P2 (pulmonic component of S2)", "A diastolic murmur at the apex", "Pulsus paradoxus"]'::jsonb, 1, 'Increased pulmonary artery pressure causes a loud, often palpable P2 heart sound, a classic finding in pulmonary hypertension.', 'Pre-Council', '🎓', true),
(6352, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Chronic pulmonary hypertension leading to right ventricular hypertrophy and eventual failure is termed:', '["Cor pulmonale", "Cardiac tamponade", "Eisenmenger syndrome", "Left ventricular hypertrophy"]'::jsonb, 0, 'Cor pulmonale refers to right ventricular enlargement or failure secondary to pulmonary hypertension caused by lung or pulmonary vascular disease.', 'Pre-Council', '🎓', true),
(6353, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which class of medication is used to selectively reduce pulmonary vascular resistance in pulmonary arterial hypertension?', '["Endothelin receptor antagonists (e.g., bosentan)", "Loop diuretics alone", "Beta-blockers", "Calcium channel blockers in all patients regardless of vasoreactivity testing"]'::jsonb, 0, 'Endothelin receptor antagonists block endothelin-1-mediated vasoconstriction and smooth muscle proliferation in the pulmonary vasculature, a mainstay of targeted PAH therapy.', 'Pre-Council', '🎓', true),
(6354, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with pulmonary hypertension is prescribed a phosphodiesterase-5 inhibitor such as sildenafil. Its mechanism of action is:', '["Direct pulmonary vasodilation via increased cGMP/nitric oxide pathway activity", "Beta-adrenergic blockade", "Direct renin inhibition", "Diuresis via the loop of Henle"]'::jsonb, 0, 'PDE-5 inhibitors prevent breakdown of cGMP, enhancing nitric-oxide-mediated pulmonary vasodilation and reducing pulmonary vascular resistance.', 'Pre-Council', '🎓', true),
(6355, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Inhaled nitric oxide is used in pulmonary hypertensive crisis primarily because it:', '["Selectively dilates the pulmonary vasculature with minimal systemic hypotension", "Increases systemic vascular resistance", "Acts as a potent bronchoconstrictor", "Directly increases myocardial contractility"]'::jsonb, 0, 'Inhaled nitric oxide is delivered directly to ventilated alveoli, causing selective pulmonary vasodilation without significant systemic effects, useful in acute pulmonary hypertensive crises.', 'Pre-Council', '🎓', true),
(6356, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which assessment finding would indicate worsening right heart failure in a patient with severe pulmonary hypertension?', '["Jugular venous distension, peripheral oedema, and hepatomegaly", "Bibasilar crackles with pink frothy sputum", "Orthopnea relieved only by sitting upright", "An S3 gallop with a mitral regurgitation murmur"]'::jsonb, 0, 'Right heart failure from pulmonary hypertension causes systemic venous congestion: jugular venous distension, peripheral oedema, ascites, and hepatomegaly, distinct from left-sided failure''s pulmonary congestion.', 'Pre-Council', '🎓', true),
(6357, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which condition is a common secondary cause of pulmonary hypertension in ICU patients?', '["Chronic hypoxic lung disease (e.g., COPD)", "Peptic ulcer disease", "Acute appendicitis", "Benign prostatic hyperplasia"]'::jsonb, 0, 'Chronic hypoxia from lung disease causes hypoxic pulmonary vasoconstriction and vascular remodeling, leading to secondary (Group 3) pulmonary hypertension.', 'Pre-Council', '🎓', true),
(6358, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Anticoagulation is sometimes used in idiopathic pulmonary arterial hypertension because:', '["It reverses pulmonary vascular remodeling", "In situ thrombosis in the small pulmonary vessels may contribute to disease progression", "It directly lowers pulmonary artery pressure", "It prevents right ventricular hypertrophy"]'::jsonb, 1, 'In situ microthrombosis within the pulmonary vasculature can contribute to progressive vascular obstruction in PAH, providing rationale for anticoagulation in select patients.', 'Pre-Council', '🎓', true),
(6359, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with pulmonary hypertension should avoid which of the following due to risk of acute decompensation?', '["Slow, gradual increases in activity", "Sudden strenuous exertion or Valsalva maneuvers", "Prescribed pulmonary vasodilator therapy", "Supplemental oxygen for hypoxemia"]'::jsonb, 1, 'Sudden increases in right ventricular workload, such as straining or heavy exertion, can precipitate acute RV failure or syncope in patients with fixed elevated pulmonary vascular resistance.', 'Pre-Council', '🎓', true),
(6360, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Syncope in a patient with known pulmonary hypertension is a concerning sign because it suggests:', '["A simple vasovagal response requiring no further workup", "The right ventricle cannot generate adequate output against elevated pulmonary pressures, risking sudden death", "A normal medication side effect", "Dehydration alone"]'::jsonb, 1, 'Exertional syncope in pulmonary hypertension indicates the right ventricle is failing to maintain cardiac output against high afterload, a poor prognostic sign associated with sudden cardiac death.', 'Pre-Council', '🎓', true),
(6361, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Oxygen therapy is recommended in patients with pulmonary hypertension and hypoxemia primarily to:', '["Cure the underlying vascular remodeling", "Reduce hypoxic pulmonary vasoconstriction and pulmonary vascular resistance", "Replace the need for pulmonary vasodilator therapy", "Increase systemic blood pressure"]'::jsonb, 1, 'Correcting hypoxemia reduces hypoxia-driven pulmonary vasoconstriction, helping to lower pulmonary vascular resistance and reduce right ventricular strain.', 'Pre-Council', '🎓', true),
(6362, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Emphysema is pathologically characterized by:', '["Permanent destruction of alveolar walls with airspace enlargement distal to the terminal bronchioles", "Reversible bronchospasm and mucosal oedema", "Excess mucus production in the bronchi with chronic cough", "Fibrotic scarring of the pulmonary interstitium"]'::jsonb, 0, 'Emphysema involves irreversible destruction of alveolar septa, causing enlarged airspaces and loss of elastic recoil, distinguishing it from chronic bronchitis with its mucus hypersecretion.', 'Pre-Council', '🎓', true),
(6363, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with severe emphysema is classically described as a ''pink puffer.'' This term reflects:', '["Cyanosis with peripheral oedema", "A thin body habitus, pursed-lip breathing, and relatively preserved oxygenation until late disease", "Obesity with cor pulmonale", "A productive cough with copious purulent sputum"]'::jsonb, 1, '''Pink puffers'' (emphysema-predominant COPD) tend to be thin and dyspneic with pursed-lip breathing, maintaining near-normal PaO2 longer by increasing ventilation, unlike ''blue bloaters.''', 'Pre-Council', '🎓', true),
(6364, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which mechanism explains pursed-lip breathing''s benefit in patients with emphysema?', '["It increases airway resistance to slow expiratory flow, preventing early airway collapse", "It decreases dead space ventilation", "It increases tidal volume directly", "It reduces oxygen consumption by the diaphragm"]'::jsonb, 0, 'Pursed-lip breathing creates back-pressure that splints the airways open during expiration, preventing dynamic airway collapse caused by loss of elastic recoil.', 'Pre-Council', '🎓', true),
(6365, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A hallmark chest X-ray finding in emphysema includes:', '["Flattened diaphragms and hyperinflated lung fields", "Bilateral pleural effusions", "Consolidation with air bronchograms", "Mediastinal shift toward the affected side"]'::jsonb, 0, 'Loss of elastic recoil and air trapping cause hyperinflation, seen as flattened diaphragms, an increased retrosternal air space, and a barrel chest on imaging.', 'Pre-Council', '🎓', true),
(6366, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Alpha-1 antitrypsin deficiency is a known genetic cause of emphysema because this enzyme normally:', '["Inhibits neutrophil elastase, protecting alveolar tissue from proteolytic damage", "Promotes mucus clearance via ciliary function", "Prevents bronchospasm", "Regulates surfactant production"]'::jsonb, 0, 'Alpha-1 antitrypsin normally inhibits neutrophil elastase; its deficiency allows unchecked elastase activity to destroy alveolar elastin, causing early-onset emphysema.', 'Pre-Council', '🎓', true),
(6367, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with severe emphysema has chronic CO2 retention. Supplemental oxygen should be titrated cautiously because:', '["High-flow oxygen can blunt the hypoxic respiratory drive in chronic CO2 retainers", "Oxygen worsens bronchospasm directly", "Oxygen has no effect on respiratory drive", "Oxygen causes immediate pulmonary oedema"]'::jsonb, 0, 'Chronic hypercapnic patients may rely on hypoxic drive for ventilatory stimulus; excessive oxygen can reduce respiratory drive and worsen CO2 retention, so controlled titration is used.', 'Pre-Council', '🎓', true),
(6368, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which spirometry finding confirms an obstructive pattern consistent with emphysema?', '["FEV1/FVC ratio less than 70% with reduced FEV1", "A normal FEV1/FVC ratio with reduced total lung capacity", "An increased FEV1/FVC ratio above 90%", "Normal spirometry with reduced diffusion capacity only"]'::jsonb, 0, 'Obstructive diseases like emphysema show a reduced FEV1/FVC ratio (below 70%) reflecting airflow limitation, along with a reduced FEV1.', 'Pre-Council', '🎓', true),
(6369, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Diffusion capacity of carbon monoxide (DLCO) in emphysema is typically:', '["Increased due to enhanced alveolar surface area", "Decreased due to loss of alveolar-capillary surface area", "Unaffected by the disease process", "Only affected in chronic bronchitis, not emphysema"]'::jsonb, 1, 'Destruction of alveolar septa reduces the surface area available for gas exchange, lowering DLCO, a key feature distinguishing emphysema from chronic bronchitis where DLCO is typically normal.', 'Pre-Council', '🎓', true),
(6370, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Pursed-lip breathing and diaphragmatic breathing exercises are taught to emphysema patients primarily to:', '["Reduce air trapping and improve ventilation efficiency", "Strengthen cardiac output directly", "Eliminate the need for bronchodilators", "Cure alveolar destruction"]'::jsonb, 0, 'These breathing techniques help reduce dynamic hyperinflation and improve the efficiency of ventilation, reducing dyspnea, though they do not reverse structural lung damage.', 'Pre-Council', '🎓', true),
(6371, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with end-stage emphysema is being evaluated for lung volume reduction surgery. The rationale is to:', '["Remove nonfunctional hyperinflated tissue to improve the mechanics of the remaining lung", "Cure the underlying alveolar destruction throughout the lung", "Replace the need for long-term oxygen therapy in all patients", "Prevent pneumothorax entirely"]'::jsonb, 0, 'Removing severely hyperinflated, poorly functioning lung tissue allows the diaphragm and remaining lung to function more effectively, improving mechanics and symptoms in select patients.', 'Pre-Council', '🎓', true),
(6372, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which complication should the ICU nurse monitor for in a mechanically ventilated patient with severe emphysema due to air trapping?', '["Auto-PEEP (intrinsic PEEP) and breath stacking", "Immediate pulmonary oedema", "Hyperkalemia from hyperventilation", "Reduced airway resistance"]'::jsonb, 0, 'Emphysema patients are prone to incomplete exhalation on the ventilator, causing air trapping and auto-PEEP, which can lead to barotrauma and hemodynamic compromise if not recognized.', 'Pre-Council', '🎓', true),
(6373, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'On auscultation, a patient with advanced emphysema is most likely to have which breath sounds?', '["Loud bronchial breath sounds throughout", "Diminished, distant breath sounds with a prolonged expiratory phase", "Fine crackles at the apices only", "Normal vesicular breath sounds"]'::jsonb, 1, 'Hyperinflation and reduced airflow in emphysema cause diminished, distant breath sounds with a prolonged expiratory phase due to air trapping and loss of elastic recoil.', 'Pre-Council', '🎓', true),
(6374, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Status asthmaticus is best defined as:', '["A mild asthma exacerbation responsive to a single bronchodilator treatment", "A severe, prolonged asthma attack that fails to respond to standard bronchodilator therapy", "Chronic stable asthma with daily symptoms", "Exercise-induced bronchospasm"]'::jsonb, 1, 'Status asthmaticus is a life-threatening asthma exacerbation that persists despite aggressive standard treatment, requiring emergent escalation of care.', 'Pre-Council', '🎓', true),
(6375, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient in status asthmaticus initially has audible wheezing. Suddenly the wheezing disappears and breath sounds become nearly silent. This finding indicates:', '["Improvement and resolution of bronchospasm", "Critical airflow obstruction (''silent chest''), an ominous sign of impending respiratory failure", "An effective bronchodilator response", "A normal resolution phase of an asthma attack"]'::jsonb, 1, 'A silent chest indicates airflow is so severely reduced that wheezing, which requires airflow, can no longer be generated, a life-threatening sign requiring immediate intervention.', 'Pre-Council', '🎓', true),
(6376, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which ABG pattern in a patient with severe asthma exacerbation is most alarming, suggesting impending respiratory failure?', '["Respiratory alkalosis with mild hypoxemia", "A rising or normalizing PaCO2 in a previously hyperventilating patient", "Persistent hypocapnia", "Metabolic alkalosis"]'::jsonb, 1, 'Early asthma exacerbation causes hyperventilation and a low PaCO2; a rising or normalizing PaCO2 indicates the patient is fatiguing and can no longer sustain the increased work of breathing, a red flag.', 'Pre-Council', '🎓', true),
(6377, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'First-line pharmacologic treatment for an acute asthma exacerbation includes:', '["A short-acting beta-2 agonist (e.g., albuterol) via nebulizer", "A long-acting beta agonist alone", "An oral leukotriene receptor antagonist", "An inhaled corticosteroid alone as monotherapy for acute symptoms"]'::jsonb, 0, 'Short-acting beta-2 agonists provide rapid bronchodilation and are first-line for acute asthma symptom relief; long-acting agonists and inhaled corticosteroids are for maintenance, not acute rescue.', 'Pre-Council', '🎓', true),
(6378, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'IV magnesium sulfate may be used in severe status asthmaticus because it:', '["Directly reverses airway inflammation", "Causes bronchial smooth muscle relaxation", "Increases mucus production to protect airways", "Acts as a potent antihistamine"]'::jsonb, 1, 'Magnesium sulfate relaxes bronchial smooth muscle via calcium channel blockade, providing additional bronchodilation in severe exacerbations unresponsive to beta-agonists alone.', 'Pre-Council', '🎓', true),
(6379, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with status asthmaticus is requiring increasing FiO2 and shows a rising respiratory rate, use of accessory muscles, and diaphoresis. What is the priority nursing consideration?', '["Continue current therapy and reassess in 4 hours", "Prepare for possible intubation and escalate care immediately", "Begin discharge planning", "Discontinue bronchodilator therapy"]'::jsonb, 1, 'Worsening respiratory distress despite treatment signals impending respiratory failure; the nurse must anticipate and prepare for advanced airway management.', 'Pre-Council', '🎓', true),
(6380, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Corticosteroids are administered in status asthmaticus primarily to:', '["Provide immediate bronchodilation within minutes", "Reduce airway inflammation and oedema, though onset is delayed by hours", "Replace the need for beta-agonist therapy", "Directly thin mucus secretions"]'::jsonb, 1, 'Corticosteroids reduce the underlying airway inflammation but have a delayed onset of several hours, so they are given early alongside rapid-acting bronchodilators.', 'Pre-Council', '🎓', true),
(6381, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Pulsus paradoxus (a greater than 10-12 mmHg drop in systolic blood pressure during inspiration) in a patient with severe asthma indicates:', '["A normal finding requiring no concern", "Significant intrathoracic pressure swings reflecting severe airway obstruction", "Left ventricular hypertrophy", "An effective bronchodilator therapy response"]'::jsonb, 1, 'Pulsus paradoxus reflects exaggerated negative intrathoracic pressure during inspiration from severe airflow obstruction, correlating with exacerbation severity.', 'Pre-Council', '🎓', true),
(6382, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which ventilator practice should be avoided in a hemodynamically unstable patient with status asthmaticus, due to risk of breath stacking?', '["A permissive hypercapnia strategy", "High respiratory rates with short expiratory time", "Low tidal volume ventilation", "Adequate sedation to reduce patient-ventilator dyssynchrony"]'::jsonb, 1, 'Rapid respiratory rates shorten expiratory time, which in severe bronchospasm causes incomplete exhalation, air trapping, auto-PEEP, and risk of barotrauma or hemodynamic collapse.', 'Pre-Council', '🎓', true),
(6383, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A mechanically ventilated patient in status asthmaticus develops sudden hypotension and increased peak airway pressures. The nurse should first suspect:', '["Auto-PEEP causing decreased venous return (breath stacking)", "Ventilator-associated pneumonia", "Hypoglycemia", "A normal expected ventilator finding"]'::jsonb, 0, 'Air trapping/auto-PEEP increases intrathoracic pressure, reducing venous return and cardiac output, causing hypotension, often managed by briefly disconnecting the ventilator to allow exhalation.', 'Pre-Council', '🎓', true),
(6384, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Ipratropium bromide, often combined with albuterol in severe asthma exacerbations, works via which mechanism?', '["Anticholinergic-mediated bronchodilation", "Beta-2 adrenergic stimulation", "Mast cell stabilization", "Leukotriene receptor blockade"]'::jsonb, 0, 'Ipratropium is an anticholinergic that blocks vagally mediated bronchoconstriction, providing additive bronchodilation when combined with beta-agonists in severe exacerbations.', 'Pre-Council', '🎓', true),
(6385, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which trigger is a common precipitant of status asthmaticus that the nurse should assess for in history-taking?', '["A recent viral respiratory infection or allergen exposure", "A recent tetanus vaccination", "Mild dehydration", "Recent orthopedic surgery"]'::jsonb, 0, 'Viral respiratory infections and allergen exposure are common triggers precipitating severe asthma exacerbations and status asthmaticus.', 'Pre-Council', '🎓', true),
(6386, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Continuous nebulized albuterol therapy in status asthmaticus should be monitored closely for which adverse effect?', '["Bradycardia and hypotension", "Tachycardia, tremors, and hypokalemia", "Respiratory depression", "Hyperkalemia"]'::jsonb, 1, 'Beta-2 agonists stimulate beta-1 receptors at high doses causing tachycardia and tremors, and drive potassium intracellularly causing hypokalemia; both require monitoring with continuous therapy.', 'Pre-Council', '🎓', true),
(6387, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient in status asthmaticus requiring intubation should ideally be intubated by:', '["The most inexperienced available provider for training purposes", "The most experienced provider available, given the high risk of a difficult airway and hemodynamic collapse", "Only after prolonged attempts at noninvasive ventilation regardless of deterioration", "A provider who skips pre-oxygenation to save time"]'::jsonb, 1, 'Intubating a severely bronchospastic, often hemodynamically labile patient is high-risk; the most experienced airway provider should perform it with adequate preparation and pre-oxygenation.', 'Pre-Council', '🎓', true),
(6388, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Heliox (a helium-oxygen mixture) may be used in severe status asthmaticus because:', '["It has a lower density than air, reducing turbulent airflow and work of breathing", "It provides a higher FiO2 than standard oxygen", "It has direct bronchodilator properties", "It cures the underlying airway inflammation"]'::jsonb, 0, 'Helium''s low density reduces airway resistance and turbulent flow through narrowed airways, temporarily decreasing work of breathing while other therapies take effect.', 'Pre-Council', '🎓', true),
(6389, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which assessment finding differentiates a life-threatening asthma exacerbation from a moderate one?', '["A peak expiratory flow rate less than 50% of predicted with altered mental status", "Mild wheezing with normal speech", "A peak expiratory flow rate greater than 80% of predicted", "A respiratory rate of 18 breaths per minute"]'::jsonb, 0, 'A peak expiratory flow rate under 50% of predicted combined with signs like altered mental status, silent chest, or exhaustion indicates a life-threatening exacerbation requiring emergent intervention.', 'Pre-Council', '🎓', true),
(6390, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Tension pneumothorax occurs when air enters the pleural space via a one-way valve mechanism, causing:', '["Progressive lung collapse with mediastinal shift away from the affected side", "Fluid accumulation in the pleural space only", "Bilateral lung collapse simultaneously", "Complete resolution without intervention"]'::jsonb, 0, 'The one-way valve allows air in but not out, progressively increasing intrapleural pressure, collapsing the ipsilateral lung and shifting the mediastinum toward the contralateral side, compromising venous return.', 'Pre-Council', '🎓', true),
(6391, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which clinical finding is a hallmark of tension pneumothorax requiring emergency intervention?', '["Tracheal deviation away from the affected side, absent breath sounds, and hypotension", "Bilateral wheezing with a productive cough", "Symmetric chest expansion with normal breath sounds", "Bradycardia with hypertension"]'::jsonb, 0, 'Tension pneumothorax classically presents with tracheal deviation away from the affected side, unilateral absent breath sounds, hyperresonance, jugular venous distension, and obstructive shock.', 'Pre-Council', '🎓', true),
(6392, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The emergency priority treatment for tension pneumothorax is:', '["Immediate needle decompression of the affected hemithorax", "Chest X-ray confirmation before any intervention", "Immediate administration of IV antibiotics", "Elective chest tube placement within 24 hours"]'::jsonb, 0, 'Tension pneumothorax is a clinical diagnosis requiring immediate needle decompression to relieve pressure before imaging, as delay can be fatal.', 'Pre-Council', '🎓', true),
(6393, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why does tension pneumothorax cause obstructive shock?', '["Increased intrathoracic pressure compresses the vena cava and heart, reducing venous return and cardiac output", "Direct myocardial infarction from chest trauma", "Massive blood loss into the pleural space", "Cardiac tamponade from a pericardial effusion"]'::jsonb, 0, 'The progressively rising intrapleural pressure compresses the great vessels and heart, drastically reducing venous return and cardiac output, producing obstructive shock.', 'Pre-Council', '🎓', true),
(6394, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'After needle decompression for tension pneumothorax, the nurse should anticipate which next intervention?', '["Immediate discharge planning", "Chest tube (tube thoracostomy) insertion for definitive management", "Discontinuation of oxygen therapy", "Administration of thrombolytics"]'::jsonb, 1, 'Needle decompression is a temporizing measure; definitive management requires chest tube placement to allow continuous evacuation of air and lung re-expansion.', 'Pre-Council', '🎓', true),
(6395, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which patient undergoing mechanical ventilation is at increased risk for developing tension pneumothorax?', '["A patient receiving positive pressure ventilation with high peak airway pressures and underlying bullous lung disease", "A patient on low-flow nasal cannula", "A patient receiving oral medications only", "An ambulatory patient with no respiratory support"]'::jsonb, 0, 'Positive pressure ventilation can force air through a weakened area of lung, such as a ruptured bleb, into the pleural space, and the ventilator continues forcing air in, precipitating tension physiology.', 'Pre-Council', '🎓', true),
(6396, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A trauma patient develops sudden severe respiratory distress, distended neck veins, and hyperresonance on the left chest with decreased breath sounds. Vital signs show blood pressure 78/50 mmHg and heart rate 132/min. What is the nurse''s immediate priority?', '["Obtain a chest X-ray before any treatment", "Notify the physician for immediate needle decompression and chest tube placement", "Administer an IV fluid bolus only and reassess in 30 minutes", "Position the patient supine and wait for spontaneous resolution"]'::jsonb, 1, 'This presentation is classic for tension pneumothorax with obstructive shock, a clinical emergency requiring immediate decompression, not delayed imaging.', 'Pre-Council', '🎓', true),
(6397, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Following chest tube insertion for a pneumothorax, continuous bubbling in the water-seal chamber that persists beyond the initial insertion period indicates:', '["A normal expected finding requiring no action", "A persistent air leak from the lung or a loose connection in the system", "Resolution of the pneumothorax", "Suction malfunction that should be corrected by increasing suction"]'::jsonb, 1, 'Continuous bubbling in the water-seal chamber beyond initial insertion indicates an ongoing air leak, either from the lung parenchyma or a loose tubing connection, requiring assessment.', 'Pre-Council', '🎓', true),
(6398, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Tidaling (fluctuation) of fluid in the water-seal chamber with respiration indicates:', '["A malfunctioning chest tube system requiring immediate replacement", "Normal function; the tube is patent and communicating with the pleural space", "Active hemorrhage into the chest tube", "Complete lung re-expansion with no further monitoring needed"]'::jsonb, 1, 'Tidaling reflects normal pressure changes transmitted through a patent tube during respiration; its absence may indicate tube obstruction or full lung re-expansion.', 'Pre-Council', '🎓', true),
(6399, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'If a chest tube becomes accidentally dislodged from the chest wall, the nurse''s immediate action is to:', '["Reinsert the tube immediately without sterile technique", "Cover the insertion site with an occlusive dressing taped on three sides and notify the physician immediately", "Leave the wound completely open to air", "Apply a fully sealed four-sided occlusive dressing"]'::jsonb, 1, 'A three-sided (flutter-valve) occlusive dressing allows air to escape during expiration while preventing air entry during inspiration, reducing the risk of a tension pneumothorax while awaiting reinsertion.', 'Pre-Council', '🎓', true),
(6400, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When transporting a patient with a chest tube, the drainage system should always be kept:', '["Above the level of the chest to promote gravity drainage", "Below the level of the chest to prevent fluid backflow into the pleural space", "Clamped during all transport", "Disconnected from suction and left open to air"]'::jsonb, 1, 'The drainage system must remain below chest level to allow gravity-dependent drainage and prevent retrograde flow of fluid or air back into the pleural space.', 'Pre-Council', '🎓', true),
(6401, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Routine clamping of a chest tube during patient transport or ambulation is:', '["Standard practice for all patients", "Generally avoided, as it risks re-accumulation of a tension pneumothorax if an air leak is present", "Required to prevent infection", "Necessary only for haemothorax, not pneumothorax"]'::jsonb, 1, 'Clamping a chest tube with an ongoing air leak prevents air from escaping, risking rapid development of a tension pneumothorax; clamping is generally avoided except in specific protocol-defined circumstances.', 'Pre-Council', '🎓', true),
(6402, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which underlying condition predisposes a patient to spontaneous tension pneumothorax without trauma?', '["A ruptured subpleural bleb in a patient with emphysema", "Chronic stable angina", "Peptic ulcer disease", "Well-controlled type 2 diabetes"]'::jsonb, 0, 'Patients with underlying bullous lung disease such as emphysema can develop spontaneous pneumothorax from a ruptured bleb, which may progress to tension physiology, especially with positive pressure ventilation.', 'Pre-Council', '🎓', true),
(6403, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key difference between simple pneumothorax and tension pneumothorax is that:', '["Simple pneumothorax involves progressive mediastinal shift and hemodynamic compromise", "Tension pneumothorax involves a one-way valve causing progressive pressure buildup and hemodynamic instability, unlike simple pneumothorax", "There is no clinical difference between the two", "Simple pneumothorax always requires needle decompression"]'::jsonb, 1, 'Simple pneumothorax involves air in the pleural space without progressive pressure buildup or major hemodynamic effect, whereas tension pneumothorax''s one-way valve mechanism causes life-threatening pressure accumulation.', 'Pre-Council', '🎓', true),
(6404, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Haemothorax is defined as:', '["Accumulation of blood in the pleural space", "Accumulation of air in the pleural space", "Accumulation of lymphatic fluid in the pleural space", "Accumulation of pus in the pleural space"]'::jsonb, 0, 'Haemothorax specifically refers to blood accumulation within the pleural cavity, most commonly from chest trauma or surgery.', 'Pre-Council', '🎓', true),
(6405, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with a massive haemothorax (greater than 1500 mL of blood loss into the chest) is at highest risk for which complication?', '["Hypovolemic shock", "A hypertensive crisis", "Diabetic ketoacidosis", "Pulmonary embolism exclusively"]'::jsonb, 0, 'Massive haemothorax represents significant blood loss into the pleural space, which can rapidly lead to hypovolemic shock requiring urgent volume resuscitation and surgical intervention.', 'Pre-Council', '🎓', true),
(6406, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Following chest tube placement for haemothorax, immediate drainage of 1200 mL of blood is noted. What is the priority nursing action?', '["Clamp the tube immediately to stop drainage", "Notify the physician immediately, as this may indicate the need for surgical intervention (thoracotomy)", "Discontinue the chest tube", "Take no action, as this is expected"]'::jsonb, 1, 'Initial drainage over 1000-1500 mL, or ongoing drainage over 200 mL/hr for several hours, suggests a significant vascular injury and typically warrants surgical exploration.', 'Pre-Council', '🎓', true),
(6407, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In managing a chest tube for haemothorax, continuous output greater than 200 mL/hr for 2-4 consecutive hours suggests:', '["Normal resolution of the haemothorax", "Ongoing active bleeding requiring surgical consultation", "The chest tube should be removed", "The patient can be discharged"]'::jsonb, 1, 'Persistent high-volume drainage indicates active hemorrhage, a criterion often used to determine the need for surgical intervention rather than continued conservative management.', 'Pre-Council', '🎓', true),
(6408, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Autotransfusion (blood salvage/reinfusion) may be used in trauma patients with haemothorax to:', '["Discard collected blood safely", "Reinfuse the patient''s own shed blood collected from the chest drainage system, reducing the need for donor transfusion", "Replace the need for chest tube insertion", "Treat pneumothorax specifically"]'::jsonb, 1, 'Autotransfusion systems collect and filter blood drained from the chest, allowing reinfusion to the patient, which conserves blood volume and reduces allogeneic transfusion requirements.', 'Pre-Council', '🎓', true),
(6409, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which breath sound finding is expected on the affected side in a patient with significant haemothorax?', '["Hyperresonance with increased breath sounds", "Dullness to percussion with diminished or absent breath sounds", "Wheezing throughout", "Normal vesicular breath sounds"]'::jsonb, 1, 'Blood accumulation in the pleural space causes dullness to percussion, unlike the hyperresonance of pneumothorax, and diminished breath sounds over the affected area.', 'Pre-Council', '🎓', true),
(6410, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with a haemothorax and hypovolemic shock requires which priority intervention alongside chest tube drainage?', '["Diuretic therapy", "Fluid resuscitation and blood product transfusion as indicated", "Immediate extubation", "Withholding IV access until surgery"]'::jsonb, 1, 'Significant blood loss requires prompt volume resuscitation, including crystalloids and blood products following massive transfusion protocols if needed, alongside source control via chest tube or surgery.', 'Pre-Council', '🎓', true),
(6411, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Coagulopathy in a trauma patient with ongoing haemothorax can be worsened by which ''lethal triad'' of trauma?', '["Hypothermia, acidosis, and coagulopathy", "Hyperthermia, alkalosis, and hypercoagulability", "Hypertension, bradycardia, and hyperglycemia", "Hyperkalemia, hypernatremia, and hypoxemia"]'::jsonb, 0, 'The trauma ''lethal triad'' of hypothermia, acidosis, and coagulopathy creates a vicious cycle that worsens bleeding and mortality; all three must be actively managed in massive haemothorax.', 'Pre-Council', '🎓', true),
(6412, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A haemothorax that is not adequately drained may progress to which chronic complication?', '["Fibrothorax with a trapped lung", "Immediate resolution without sequelae", "Acute pulmonary embolism directly", "A spontaneous pneumothorax"]'::jsonb, 0, 'Retained or clotted blood in the pleural space that is not evacuated can organize into fibrous tissue, causing a fibrothorax that restricts lung expansion and requires surgical decortication.', 'Pre-Council', '🎓', true),
(6413, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which diagnostic tool is most useful at the bedside for rapid assessment of haemothorax in a trauma patient?', '["Bedside ultrasound (eFAST examination)", "Pulmonary function testing", "Echocardiography stress test", "Colonoscopy"]'::jsonb, 0, 'The extended FAST (eFAST) ultrasound exam allows rapid bedside detection of pleural fluid (blood) and pneumothorax in trauma patients without delay for CT imaging.', 'Pre-Council', '🎓', true),
(6414, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'For a stable patient with a small haemothorax managed with chest tube drainage, which nursing assessment finding indicates the drainage system is functioning appropriately?', '["Absence of tidaling and no drainage output", "Gradually decreasing serosanguinous drainage output over time with tidaling present", "Sudden cessation of all drainage after an initial large volume", "Continuous bright red bleeding without change"]'::jsonb, 1, 'A gradual decrease in drainage that becomes more serous over time, along with tidaling confirming tube patency, reflects appropriate resolution of the haemothorax.', 'Pre-Council', '🎓', true),
(6415, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In a retained haemothorax not resolving with standard chest tube drainage, which intervention may be indicated?', '["Video-assisted thoracoscopic surgery (VATS) for evacuation of clotted blood", "Increased oral fluid intake", "Nebulized bronchodilators", "Discontinuation of the chest tube without further evaluation"]'::jsonb, 0, 'VATS allows direct visualization and evacuation of retained clotted blood that a standard chest tube cannot adequately drain, preventing complications like fibrothorax or empyema.', 'Pre-Council', '🎓', true),
(6416, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Type I (hypoxemic) respiratory failure is defined by:', '["PaO2 less than 60 mmHg with a normal or low PaCO2", "PaCO2 greater than 50 mmHg with a normal PaO2", "PaO2 greater than 80 mmHg with an elevated PaCO2", "Normal ABG values with clinical dyspnea"]'::jsonb, 0, 'Type I respiratory failure is primarily a failure of oxygenation, defined by a PaO2 below 60 mmHg on room air, with normal or low PaCO2, typically from V/Q mismatch or shunt.', 'Pre-Council', '🎓', true),
(6417, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Type II (hypercapnic) respiratory failure is defined by:', '["A PaO2 less than 60 mmHg alone", "A PaCO2 greater than 50 mmHg with accompanying respiratory acidosis", "A normal PaCO2 with severe hypoxemia", "Elevated bicarbonate with normal pH"]'::jsonb, 1, 'Type II respiratory failure reflects ventilatory failure with inadequate CO2 elimination, defined by an elevated PaCO2 with acidemia, often from COPD exacerbation, neuromuscular weakness, or CNS depression.', 'Pre-Council', '🎓', true),
(6418, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which condition is a classic cause of Type I (hypoxemic) respiratory failure?', '["Opioid overdose", "ARDS or pulmonary oedema causing V/Q mismatch and shunt", "Guillain-Barr\u00e9 syndrome", "Myasthenic crisis"]'::jsonb, 1, 'ARDS and pulmonary oedema cause alveolar filling or collapse leading to intrapulmonary shunt and V/Q mismatch, the hallmark mechanism of Type I hypoxemic respiratory failure.', 'Pre-Council', '🎓', true),
(6419, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which condition is a classic cause of Type II (hypercapnic) respiratory failure?', '["Pulmonary embolism", "Opioid-induced respiratory depression with decreased minute ventilation", "Early ARDS", "Pneumonia with a normal ventilatory drive"]'::jsonb, 1, 'Opioid overdose suppresses the central respiratory drive, reducing minute ventilation and causing CO2 retention, a classic cause of Type II ventilatory respiratory failure.', 'Pre-Council', '🎓', true),
(6420, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient in acute respiratory failure has ABG results: pH 7.28, PaCO2 60 mmHg, HCO3 26 mEq/L, PaO2 55 mmHg. This is best interpreted as:', '["Compensated metabolic alkalosis", "Acute (uncompensated) respiratory acidosis with hypoxemia", "Fully compensated respiratory acidosis", "Acute metabolic acidosis"]'::jsonb, 1, 'A low pH with elevated PaCO2 and a near-normal HCO3 indicates an acute respiratory acidosis without significant renal compensation yet, alongside hypoxemia, consistent with acute Type II respiratory failure.', 'Pre-Council', '🎓', true),
(6421, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which clinical sign is an early indicator of impending respiratory failure that the nurse should recognize before ABG results are available?', '["Use of accessory muscles, tachypnea, and restlessness or anxiety", "Bradycardia and hypotension only", "Warm, dry skin", "Slow, deep, regular respirations"]'::jsonb, 0, 'Early signs of respiratory distress include tachypnea, accessory muscle use, nasal flaring, and restlessness from hypoxemia; these clinical signs often precede definitive ABG changes.', 'Pre-Council', '🎓', true),
(6422, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In a patient with respiratory failure, a decreasing level of consciousness with rising PaCO2 indicates:', '["Improving ventilatory status", "CO2 narcosis from severe hypercapnia, an emergency requiring urgent intervention", "A normal sleep pattern", "Effective compensation"]'::jsonb, 1, 'Severe hypercapnia causes CNS depression (CO2 narcosis), presenting as decreasing level of consciousness; this is an ominous sign requiring immediate ventilatory support.', 'Pre-Council', '🎓', true),
(6423, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The alveolar-arterial (A-a) oxygen gradient is useful in respiratory failure to differentiate:', '["Intrapulmonary causes (V/Q mismatch, shunt) from extrapulmonary causes (hypoventilation) of hypoxemia", "Metabolic versus respiratory acidosis", "Acute versus chronic renal failure", "Types of anemia"]'::jsonb, 0, 'A widened A-a gradient suggests a lung-based problem such as V/Q mismatch, diffusion defect, or shunt, while a normal A-a gradient with hypoxemia points to hypoventilation as the cause.', 'Pre-Council', '🎓', true),
(6424, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with acute respiratory failure is started on noninvasive positive pressure ventilation. Which finding indicates the trial is failing and intubation should be considered?', '["Improving mental status", "Worsening acidosis, a rising PaCO2, or hemodynamic instability despite noninvasive ventilation", "A decreasing respiratory rate toward normal", "Improved oxygen saturation"]'::jsonb, 1, 'Failure to improve gas exchange, worsening acidosis, or hemodynamic/mental status deterioration despite an adequate trial indicates the need to proceed to invasive mechanical ventilation.', 'Pre-Council', '🎓', true),
(6425, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following best describes the pathophysiology of shunt as a cause of hypoxemic respiratory failure?', '["Blood perfuses alveoli that are not ventilated (e.g., filled with fluid or collapsed), so it returns to systemic circulation without being oxygenated", "Air reaches alveoli that have no blood supply", "Both ventilation and perfusion are proportionally reduced together", "Increased diffusion distance across a thickened membrane alone"]'::jsonb, 0, 'Shunt occurs when blood passes through unventilated but perfused alveolar units, such as in ARDS or pulmonary oedema, and this hypoxemia typically responds poorly to supplemental oxygen alone.', 'Pre-Council', '🎓', true),
(6426, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key characteristic of shunt physiology compared to V/Q mismatch in respiratory failure is that the hypoxemia:', '["Improves significantly with supplemental oxygen alone", "Does not correct fully with supplemental oxygen because blood bypasses ventilated alveoli entirely", "Is unrelated to oxygen therapy", "Only occurs in normal lung tissue"]'::jsonb, 1, 'True shunt, where blood is not exposed to any ventilated alveoli, responds poorly to increased FiO2, unlike V/Q mismatch, which generally improves with supplemental oxygen.', 'Pre-Council', '🎓', true),
(6427, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Neuromuscular causes of respiratory failure, such as Guillain-Barré syndrome or myasthenic crisis, primarily lead to which type of respiratory failure?', '["Type I hypoxemic failure from alveolar collapse", "Type II hypercapnic failure from inadequate ventilatory muscle strength", "No meaningful risk of respiratory failure", "Pure oxygenation failure with normal CO2"]'::jsonb, 1, 'Neuromuscular weakness impairs the respiratory muscles'' ability to generate adequate minute ventilation, leading to CO2 retention and Type II (hypercapnic) respiratory failure.', 'Pre-Council', '🎓', true),
(6428, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which bedside pulmonary function measurement is used to monitor respiratory muscle strength and fatigue in neuromuscular respiratory failure, such as Guillain-Barré syndrome?', '["Peak expiratory flow rate alone", "Negative inspiratory force (NIF) and vital capacity", "Pulse oximetry alone", "Heart rate variability"]'::jsonb, 1, 'Negative inspiratory force and vital capacity trends are used to monitor declining respiratory muscle strength in neuromuscular disease, helping predict the need for intubation before overt hypoxemia or hypercapnia develop.', 'Pre-Council', '🎓', true),
(6429, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In ARDS-related respiratory failure, the ventilator strategy of low tidal volume (6 mL/kg predicted body weight) is used primarily to:', '["Maximize alveolar recruitment via large breaths", "Minimize ventilator-induced lung injury (volutrauma/barotrauma)", "Eliminate the need for PEEP", "Reduce oxygen requirements to zero"]'::jsonb, 1, 'The lung-protective, low tidal volume strategy reduces overdistension of already-injured, non-compliant alveoli, minimizing ventilator-induced lung injury while accepting permissive hypercapnia if needed.', 'Pre-Council', '🎓', true),
(6430, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Permissive hypercapnia, used in some ARDS ventilation strategies, refers to:', '["Allowing PaCO2 to rise above normal to avoid the harms of high tidal volumes and pressures", "Deliberately causing severe hypoxemia", "Withholding all ventilator support", "Targeting a PaCO2 of zero"]'::jsonb, 0, 'Permissive hypercapnia accepts a higher-than-normal PaCO2, with resultant mild respiratory acidosis, as a trade-off for using lung-protective low tidal volumes and pressures that reduce lung injury.', 'Pre-Council', '🎓', true),
(6431, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient in respiratory failure from severe pneumonia develops refractory hypoxemia despite maximal ventilator settings. Which adjunct therapy may be considered?', '["Prone positioning to improve V/Q matching", "Immediate extubation", "Discontinuing PEEP", "Increasing tidal volume above 10 mL/kg"]'::jsonb, 0, 'Prone positioning improves ventilation-perfusion matching and recruits dorsal lung regions in ARDS/severe pneumonia, improving oxygenation in patients with refractory hypoxemia.', 'Pre-Council', '🎓', true),
(6432, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which combination of ABG values indicates chronic (compensated) respiratory failure rather than acute?', '["pH 7.36, PaCO2 65 mmHg, HCO3 36 mEq/L", "pH 7.20, PaCO2 70 mmHg, HCO3 24 mEq/L", "pH 7.50, PaCO2 25 mmHg, HCO3 22 mEq/L", "pH 7.10, PaCO2 80 mmHg, HCO3 22 mEq/L"]'::jsonb, 0, 'A near-normal pH despite an elevated PaCO2, with a compensatory elevated HCO3, indicates renal compensation has occurred over time, consistent with chronic respiratory failure, as seen in COPD.', 'Pre-Council', '🎓', true),
(6433, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Weaning readiness from mechanical ventilation in a patient recovering from respiratory failure is best assessed using:', '["Random ABG draws only", "A spontaneous breathing trial with assessment of the rapid shallow breathing index", "A chest X-ray alone", "Body temperature trends"]'::jsonb, 1, 'A spontaneous breathing trial, often combined with the rapid shallow breathing index, is a standard, evidence-based method to assess a patient''s readiness for extubation.', 'Pre-Council', '🎓', true),
(6434, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which patient is at greatest risk for developing acute-on-chronic respiratory failure?', '["A COPD patient with a new respiratory infection", "A healthy young adult with a mild cold", "A postoperative patient with normal lung function", "A patient with well-controlled seasonal allergies"]'::jsonb, 0, 'Patients with chronic respiratory disease such as COPD have limited reserve; an acute insult like infection can precipitate acute-on-chronic respiratory failure, requiring prompt recognition and treatment.', 'Pre-Council', '🎓', true),
(6435, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with acute respiratory failure requires emergent intubation. Which pre-intubation nursing action is most important to optimize outcomes?', '["Withhold oxygen until the tube is placed to avoid hyperoxia", "Pre-oxygenate with high-flow oxygen or bag-valve-mask prior to intubation", "Sedate the patient heavily without any oxygen supplementation", "Delay intubation until the patient is fully alert"]'::jsonb, 1, 'Adequate pre-oxygenation extends the safe apnea time during intubation attempts, reducing the risk of severe desaturation and cardiac arrest during the peri-intubation period.', 'Pre-Council', '🎓', true),
(6436, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'BiPAP (Bilevel Positive Airway Pressure) differs from CPAP in that it provides:', '["Only a single continuous pressure throughout the respiratory cycle", "Two different pressure levels: a higher inspiratory positive airway pressure (IPAP) and a lower expiratory positive airway pressure (EPAP)", "Invasive mechanical ventilation only", "No support during inspiration"]'::jsonb, 1, 'BiPAP delivers separate IPAP, which is higher and assists inspiration, and EPAP, which is lower and maintains alveolar recruitment during expiration, unlike CPAP which provides one constant pressure.', 'Pre-Council', '🎓', true),
(6437, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key clinical benefit of BiPAP in a patient with a COPD exacerbation and respiratory failure is that it:', '["Reduces the work of breathing by providing inspiratory pressure support while maintaining alveolar recruitment with EPAP", "Eliminates the need for any pharmacologic bronchodilator therapy", "Cures the underlying airway obstruction", "Requires no patient cooperation or spontaneous breathing effort"]'::jsonb, 0, 'The pressure differential in BiPAP, with IPAP greater than EPAP, assists the patient''s own inspiratory effort, reducing work of breathing, while EPAP prevents alveolar and airway collapse, helping avoid intubation in COPD exacerbations.', 'Pre-Council', '🎓', true),
(6438, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which patient is an appropriate candidate for BiPAP therapy?', '["An alert, cooperative patient with a COPD exacerbation and mild-to-moderate respiratory distress who can protect their airway", "An unconscious patient with no gag reflex", "A patient in cardiac arrest", "A patient with full-thickness facial trauma preventing mask fit"]'::jsonb, 0, 'BiPAP requires a cooperative, spontaneously breathing patient who can protect their airway; it is contraindicated in patients with decreased consciousness, inability to protect the airway, or facial trauma preventing mask seal.', 'Pre-Council', '🎓', true),
(6439, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A major contraindication to BiPAP use is:', '["Mild hypoxemia", "Decreased level of consciousness with inability to protect the airway", "Stable vital signs", "A history of well-controlled asthma"]'::jsonb, 1, 'BiPAP requires the patient to maintain their own airway and cooperate with the mask interface; altered consciousness increases aspiration risk and is a contraindication.', 'Pre-Council', '🎓', true),
(6440, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In cardiogenic pulmonary oedema, BiPAP or CPAP improves oxygenation and hemodynamics primarily by:', '["Increasing venous return to the already overloaded heart", "Reducing preload and afterload through positive intrathoracic pressure, improving cardiac performance", "Directly increasing myocardial contractility", "Causing bronchoconstriction to trap air"]'::jsonb, 1, 'Positive intrathoracic pressure from BiPAP or CPAP decreases venous return (preload) and reduces left ventricular transmural pressure (afterload), improving cardiac output and reducing pulmonary congestion.', 'Pre-Council', '🎓', true),
(6441, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing assessment is essential when a patient is on BiPAP therapy?', '["Skin integrity checks over the nasal bridge and face to prevent pressure injury from the mask", "Daily weight only", "Bowel sounds every hour", "Deep tendon reflexes"]'::jsonb, 0, 'Tight-fitting BiPAP masks can cause pressure injury to the nasal bridge and face; regular skin assessment and mask repositioning or padding are essential nursing interventions.', 'Pre-Council', '🎓', true),
(6442, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient on BiPAP develops abdominal distension and complains of nausea. This is most likely due to:', '["Gastric insufflation from swallowed air during positive pressure ventilation", "Acute pancreatitis", "A normal expected finding requiring no action", "A medication side effect from bronchodilators"]'::jsonb, 0, 'Positive pressure delivered via mask can cause air to be swallowed into the stomach (gastric insufflation), causing distension, discomfort, and increased aspiration risk.', 'Pre-Council', '🎓', true),
(6443, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which finding after 1-2 hours of BiPAP therapy indicates the treatment is failing and the patient may need intubation?', '["Improving ABG values and a decreasing respiratory rate", "Worsening mental status, persistent acidosis, or hemodynamic instability", "Improved patient comfort and synchrony with the device", "A decreasing oxygen requirement"]'::jsonb, 1, 'Lack of improvement or worsening of respiratory or metabolic status despite an adequate BiPAP trial signals treatment failure, requiring escalation to invasive mechanical ventilation.', 'Pre-Council', '🎓', true),
(6444, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The EPAP setting on BiPAP functions similarly to which parameter on invasive mechanical ventilation?', '["Tidal volume", "PEEP (positive end-expiratory pressure)", "FiO2", "Respiratory rate"]'::jsonb, 1, 'EPAP maintains positive pressure at end-expiration, functioning like PEEP on invasive ventilation, preventing alveolar collapse and improving functional residual capacity.', 'Pre-Council', '🎓', true),
(6445, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A benefit of BiPAP over invasive mechanical ventilation for appropriate candidates includes:', '["Reduced risk of ventilator-associated pneumonia and preservation of airway defense mechanisms", "Elimination of any risk of aspiration", "No need for patient monitoring", "Guaranteed prevention of intubation in all cases"]'::jsonb, 0, 'By avoiding an endotracheal tube, BiPAP preserves natural airway defenses such as cough and mucociliary clearance, and avoids infection risks associated with invasive ventilation, such as ventilator-associated pneumonia.', 'Pre-Council', '🎓', true),
(6446, 'Pulmonary Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When initiating BiPAP for a patient in acute respiratory distress, the nurse should prioritize which action to promote tolerance and effectiveness?', '["Applying the mask at full pressure settings immediately without explanation", "Explaining the procedure, ensuring proper mask fit, and starting at lower pressures with gradual titration", "Sedating the patient heavily before mask application", "Removing the mask every 5 minutes for the first hour"]'::jsonb, 1, 'Patient education, comfort, and a snug but not overly tight mask fit with gradual pressure titration improve tolerance and adherence, which is critical to BiPAP''s success since it requires patient cooperation.', 'Pre-Council', '🎓', true),
(6447, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the Berlin definition timeframe for onset of ARDS relative to a known clinical insult?', '["Within 1 week", "Within 2 weeks", "Within 72 hours", "Within 1 month"]'::jsonb, 0, 'The Berlin definition requires new or worsening respiratory symptoms within 1 week of a known clinical insult.', 'Pre-Council', '🎓', true),
(6448, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'According to Berlin criteria, ARDS-associated pulmonary edema must not be fully explained by which two causes?', '["Cardiac failure or fluid overload", "Infection or sepsis", "Trauma or burns", "Sedation or paralysis"]'::jsonb, 0, 'Berlin criteria require that respiratory failure not be fully explained by cardiac failure or fluid overload, distinguishing ARDS from cardiogenic pulmonary edema.', 'Pre-Council', '🎓', true),
(6449, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What PaO2/FiO2 ratio threshold, with PEEP of at least 5 cmH2O, defines severe ARDS under the Berlin definition?', '["300 or less", "200 or less", "100 or less", "150 or less"]'::jsonb, 2, 'Severe ARDS is defined as PaO2/FiO2 of 100 mmHg or less with PEEP at least 5 cmH2O; mild is 200-300 and moderate is 100-200.', 'Pre-Council', '🎓', true),
(6450, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The primary goal of ventilatory therapy in ARDS is best described as:', '["Normalizing PaCO2 at all times to prevent hypercapnia", "Achieving adequate oxygenation while minimizing ventilator-induced lung injury", "Maximizing tidal volume to recruit collapsed alveoli", "Eliminating the need for PEEP"]'::jsonb, 1, 'Lung-protective ventilation aims to maintain adequate gas exchange while limiting volutrauma, barotrauma, and atelectrauma, even accepting some hypercapnia.', 'Pre-Council', '🎓', true),
(6451, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The ARDSNet lung-protective ventilation strategy recommends target tidal volumes of:', '["10-12 mL/kg predicted body weight", "4-8 mL/kg predicted body weight (typically around 6)", "8-10 mL/kg actual body weight", "12-15 mL/kg ideal body weight"]'::jsonb, 1, 'Low tidal volume ventilation, about 6 mL/kg predicted body weight, reduces ventilator-induced lung injury in ARDS.', 'Pre-Council', '🎓', true),
(6452, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In ARDS lung-protective ventilation, plateau pressure should be maintained at or below:', '["40 cmH2O", "35 cmH2O", "30 cmH2O", "25 cmH2O"]'::jsonb, 2, 'Keeping plateau pressure at 30 cmH2O or less limits alveolar overdistension and reduces the risk of barotrauma.', 'Pre-Council', '🎓', true),
(6453, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Permissive hypercapnia in ARDS management refers to:', '["Allowing PaCO2 to rise above normal to permit lower tidal volumes and pressures", "Deliberately hyperventilating to reduce intracranial pressure", "Withholding sedation to allow spontaneous ventilation", "Tolerating hypoxemia to reduce oxygen toxicity"]'::jsonb, 0, 'Permissive hypercapnia accepts a higher-than-normal PaCO2, with compensated respiratory acidosis, as a tradeoff for lung-protective low tidal volumes.', 'Pre-Council', '🎓', true),
(6454, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why is PEEP used in the management of ARDS?', '["To decrease intrathoracic pressure", "To prevent alveolar collapse at end-expiration and improve oxygenation", "To reduce the work of breathing during weaning only", "To increase venous return"]'::jsonb, 1, 'PEEP recruits and stabilizes collapsed alveoli, increasing functional residual capacity and improving ventilation-perfusion matching and oxygenation.', 'Pre-Council', '🎓', true),
(6455, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A potential adverse hemodynamic effect of high PEEP levels is:', '["Increased preload and hypertension", "Decreased venous return and reduced cardiac output", "Bradycardia from vagal stimulation", "Increased coronary perfusion"]'::jsonb, 1, 'High PEEP increases intrathoracic pressure, which can impede venous return to the right heart, reducing preload and cardiac output.', 'Pre-Council', '🎓', true),
(6456, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which pharmacologic agent may be used early in severe ARDS to improve ventilator synchrony and reduce oxygen consumption?', '["A neuromuscular blocking agent such as cisatracurium", "A loop diuretic", "A beta-agonist bronchodilator", "A systemic anticoagulant"]'::jsonb, 0, 'Short-term neuromuscular blockade in early severe ARDS can improve patient-ventilator synchrony, reduce barotrauma, and decrease oxygen consumption and CO2 production.', 'Pre-Council', '🎓', true),
(6457, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Prone positioning in ARDS is used primarily to:', '["Reduce the need for sedation", "Improve ventilation-perfusion matching and recruit dorsal lung regions, improving oxygenation", "Eliminate the risk of ventilator-associated pneumonia entirely", "Eliminate the need for PEEP"]'::jsonb, 1, 'Prone positioning redistributes perfusion and ventilation, recruiting dependent dorsal lung units that are collapsed in supine ARDS patients, improving oxygenation.', 'Pre-Council', '🎓', true),
(6458, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the recommended fluid management strategy in ARDS patients who are not in shock?', '["Aggressive fluid resuscitation to maintain high preload", "Conservative fluid management or fluid restriction to minimize pulmonary edema", "Diuresis regardless of hemodynamic status", "Fluid boluses guided solely by urine output"]'::jsonb, 1, 'A conservative fluid strategy reduces extravascular lung water and improves oxygenation and ventilator-free days in ARDS without compromising organ perfusion.', 'Pre-Council', '🎓', true),
(6459, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Refractory hypoxemia in severe ARDS despite optimized ventilator settings, prone positioning, and neuromuscular blockade may warrant consideration of:', '["High-dose corticosteroids alone", "Extracorporeal membrane oxygenation (ECMO)", "Immediate extubation", "Switching to nasal cannula"]'::jsonb, 1, 'ECMO provides extracorporeal gas exchange, allowing further lung rest, and is considered for refractory hypoxemia unresponsive to conventional lung-protective strategies.', 'Pre-Council', '🎓', true),
(6460, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When caring for a patient on Pressure Control Ventilation (PCV) for ARDS, the nurse should closely monitor:', '["Only the set pressure, since volume is irrelevant", "Exhaled tidal volume, since it varies with changes in lung compliance and resistance", "Only respiratory rate", "FiO2 alone"]'::jsonb, 1, 'In PCV the clinician sets pressure and inspiratory time; tidal volume is a dependent variable that fluctuates with the patient''s compliance and airway resistance, so it must be monitored continuously.', 'Pre-Council', '🎓', true),
(6461, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In PCV, if a patient''s lung compliance suddenly improves, the nurse should anticipate:', '["Decreased tidal volume delivery", "Increased tidal volume delivery, risking volutrauma", "No change in delivered volume", "Automatic decrease in set pressure by the ventilator"]'::jsonb, 1, 'Because pressure is fixed in PCV, improved compliance results in a larger delivered tidal volume for the same pressure, risking volutrauma if not detected and the pressure adjusted.', 'Pre-Council', '🎓', true),
(6462, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A hallmark inspiratory flow pattern of Pressure Control Ventilation is:', '["A constant, square flow waveform", "A decelerating flow waveform", "A sine wave flow pattern only", "A flow pattern identical to volume control"]'::jsonb, 1, 'PCV delivers a decelerating, ramp-down inspiratory flow pattern that fills the lungs early in the breath and can improve gas distribution.', 'Pre-Council', '🎓', true),
(6463, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing consideration is a priority when a patient on PCV for ARDS becomes tachypneic and dyssynchronous with the ventilator?', '["Increase FiO2 to 100% permanently without further assessment", "Assess for causes of distress such as hypoxemia, pain, secretions, or pneumothorax, and consider sedation or analgesia adjustment", "Immediately discontinue PEEP", "Switch the mode to CPAP without physician notification"]'::jsonb, 1, 'Ventilator dyssynchrony requires prompt assessment for reversible causes before medication changes; ARDS patients often require deeper sedation, and possibly paralysis, to tolerate lung-protective settings.', 'Pre-Council', '🎓', true),
(6464, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'One of the primary indications for initiating mechanical ventilation in a patient with ARDS is:', '["PaO2/FiO2 ratio greater than 300 with normal work of breathing", "Refractory hypoxemia and increased work of breathing despite supplemental oxygen", "Mild bilateral crackles with normal arterial blood gases", "Elective sedation for comfort"]'::jsonb, 1, 'Mechanical ventilation is indicated when a patient cannot maintain adequate oxygenation or ventilation despite maximal noninvasive oxygen therapy, reflected by worsening hypoxemia and increased work of breathing.', 'Pre-Council', '🎓', true),
(6465, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The characteristic chest radiograph finding in ARDS is:', '["Unilateral lobar consolidation", "Bilateral diffuse infiltrates, described as a ''white-out'' pattern consistent with pulmonary edema", "Hyperinflation with flattened diaphragms", "A normal chest film"]'::jsonb, 1, 'ARDS classically presents with bilateral diffuse pulmonary infiltrates on chest x-ray or CT, reflecting diffuse alveolar damage and non-cardiogenic pulmonary edema.', 'Pre-Council', '🎓', true),
(6466, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why is high FiO2, near 100%, avoided for prolonged periods in ARDS management when possible?', '["It causes immediate pneumothorax", "Prolonged high FiO2 can cause oxygen toxicity and absorption atelectasis", "It lowers PaO2", "It has no clinical downside"]'::jsonb, 1, 'Prolonged exposure to high FiO2 can cause oxygen free-radical injury and absorption atelectasis, so the lowest FiO2 achieving adequate oxygenation is targeted.', 'Pre-Council', '🎓', true),
(6467, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key diagnostic criterion distinguishing ARDS from cardiogenic pulmonary edema is:', '["Presence of bilateral infiltrates", "Low pulmonary capillary wedge pressure or no evidence of left atrial hypertension as the primary cause", "Hypoxemia", "Need for mechanical ventilation"]'::jsonb, 1, 'ARDS pulmonary edema results from increased capillary permeability, not elevated left atrial or hydrostatic pressure, so cardiogenic causes should be excluded.', 'Pre-Council', '🎓', true),
(6468, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse caring for a sedated, paralyzed ARDS patient on PCV must prioritize which assessment because the patient cannot report symptoms?', '["Family communication only", "Continuous monitoring of vital signs and SpO2, along with eye and skin protection since protective reflexes are absent", "Daily weight only", "Oral intake tolerance"]'::jsonb, 1, 'With neuromuscular blockade, the patient cannot report pain or distress or protect their airway or eyes, so continuous objective monitoring and supportive care such as eye care and skin protection are essential nursing priorities.', 'Pre-Council', '🎓', true),
(6469, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The most reliable immediate bedside method to confirm correct endotracheal tube placement after intubation is:', '["Auscultation of bilateral breath sounds alone", "Continuous waveform capnography showing a sustained CO2 waveform", "Chest x-ray only", "Visualizing chest rise alone"]'::jsonb, 1, 'Continuous waveform capnography is the gold-standard bedside confirmation of tracheal, rather than esophageal, tube placement and should be used immediately after intubation.', 'Pre-Council', '🎓', true),
(6470, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Endotracheal tube cuff pressure should be maintained within which range to minimize tracheal ischemia while preventing aspiration and air leak?', '["5-10 cmH2O", "20-30 cmH2O", "40-50 cmH2O", "60-70 cmH2O"]'::jsonb, 1, 'Cuff pressures of about 20-30 cmH2O balance sealing the airway against tracheal capillary perfusion pressure to prevent mucosal ischemia.', 'Pre-Council', '🎓', true),
(6471, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The main purpose of subglottic secretion drainage endotracheal tubes is to:', '["Reduce risk of ventilator-associated pneumonia by removing secretions pooled above the cuff", "Increase tidal volume delivery", "Reduce the need for suctioning below the cuff", "Prevent esophageal intubation"]'::jsonb, 0, 'Subglottic suction ports allow continuous or intermittent removal of secretions pooled above the endotracheal tube cuff, reducing microaspiration and VAP risk.', 'Pre-Council', '🎓', true),
(6472, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Prior to suctioning an intubated patient, the nurse should:', '["Increase sedation to the maximum dose", "Hyperoxygenate the patient, typically with 100% FiO2", "Decrease PEEP to zero", "Disconnect the ventilator for 5 minutes first"]'::jsonb, 1, 'Preoxygenating or hyperoxygenating before suctioning helps prevent suction-induced hypoxemia.', 'Pre-Council', '🎓', true),
(6473, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Suction catheter insertion depth during endotracheal suctioning should be limited to:', '["As far as it will pass, applying continuous suction the whole way in", "Just past the tip of the tube until slight resistance is felt, applying suction only on withdrawal", "Twice the length of the endotracheal tube", "Advancing until the patient coughs forcefully, then continuing for another 30 seconds"]'::jsonb, 1, 'The catheter should be advanced only until slight resistance is felt, with suction applied intermittently during withdrawal, to minimize mucosal trauma and hypoxemia.', 'Pre-Council', '🎓', true),
(6474, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Each suction pass on an intubated patient should be limited to no more than approximately:', '["5 seconds", "10-15 seconds", "30 seconds", "60 seconds"]'::jsonb, 1, 'Limiting each suction pass to about 10-15 seconds minimizes hypoxemia, mucosal trauma, and vagally mediated bradycardia or dysrhythmias.', 'Pre-Council', '🎓', true),
(6475, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key nursing intervention to prevent ventilator-associated pneumonia (VAP) in an intubated patient includes:', '["Keeping the head of bed flat at 0 degrees", "Elevating the head of bed 30-45 degrees", "Minimizing oral care to once daily", "Giving routine prophylactic antibiotics to all patients"]'::jsonb, 1, 'Semi-recumbent positioning at 30-45 degrees reduces aspiration of gastric or oral secretions and is a core component of VAP-prevention bundles, along with oral care and sedation vacations.', 'Pre-Council', '🎓', true),
(6476, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the primary purpose of humidification in mechanically ventilated patients?', '["To increase tidal volume", "To prevent drying and thickening of secretions since the upper airway''s normal humidification is bypassed", "To reduce cuff pressure", "To reduce oxygen requirement"]'::jsonb, 1, 'An artificial airway bypasses the nose and upper airway''s natural warming and humidifying function, so inspired gas must be actively humidified to prevent thick, tenacious secretions.', 'Pre-Council', '🎓', true),
(6477, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The high-pressure alarm on a ventilator most commonly indicates:', '["A disconnection in the circuit", "Something obstructing or restricting airflow, such as secretions, biting the tube, or bronchospasm", "An empty oxygen source", "Inadequate sedation only"]'::jsonb, 1, 'High-pressure alarms are triggered by increased resistance to gas delivery, commonly from secretions, kinked tubing, biting, bronchospasm, or worsening compliance.', 'Pre-Council', '🎓', true),
(6478, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A low-pressure or low-exhaled-volume alarm on the ventilator most often signals:', '["A leak or disconnection in the ventilator circuit or cuff", "Mucus plugging", "Bronchospasm", "Breath stacking"]'::jsonb, 0, 'Low-pressure alarms typically indicate a leak, such as circuit disconnection, a cuff leak, or partial extubation, resulting in loss of delivered volume or pressure.', 'Pre-Council', '🎓', true),
(6479, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which assessment finding after intubation would most strongly suggest right mainstem bronchus intubation?', '["Bilateral equal breath sounds", "Diminished or absent breath sounds on the left side with the right side clear", "Diminished breath sounds bilaterally", "Stridor"]'::jsonb, 1, 'If the endotracheal tube is advanced too far, it commonly enters the right mainstem bronchus, causing absent or diminished breath sounds on the left.', 'Pre-Council', '🎓', true),
(6480, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the recommended action if a ventilated patient''s exhaled tidal volume suddenly drops significantly with a normal peak pressure and an audible air leak at the mouth?', '["Assume mucus plug and suction aggressively", "Suspect cuff leak or partial tube displacement and assess cuff pressure and tube position immediately", "Increase PEEP", "Increase sedation"]'::jsonb, 1, 'A sudden volume loss with an audible leak suggests cuff deflation or tube malposition; the nurse should assess cuff pressure and tube position urgently.', 'Pre-Council', '🎓', true),
(6481, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The purpose of noting and documenting endotracheal tube depth, in centimeters at the teeth or lips, at each shift is to:', '["Calculate tidal volume", "Detect tube migration that could result in mainstem intubation or accidental extubation", "Determine cuff pressure", "Assess for ventilator-associated pneumonia"]'::jsonb, 1, 'Comparing the tube depth marking to the baseline documented depth helps detect unintentional advancement or withdrawal of the tube.', 'Pre-Council', '🎓', true),
(6482, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following best describes the role of daily sedation vacations or spontaneous awakening trials for ventilated patients?', '["They increase the duration of mechanical ventilation", "They are paired with spontaneous breathing trials to assess weaning readiness and reduce duration of ventilation", "They are only performed in patients with tracheostomies", "They eliminate the need for analgesia"]'::jsonb, 1, 'Daily interruption of sedation paired with spontaneous breathing trials reduces ventilator days, ICU length of stay, and delirium when performed safely.', 'Pre-Council', '🎓', true),
(6483, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following is an absolute priority nursing action immediately before a scheduled extubation?', '["Increase sedation for comfort", "Ensure the patient can protect their airway, with adequate cough and gag reflex and the ability to follow commands, and have reintubation equipment at the bedside", "Remove all IV access", "Discontinue cardiac monitoring"]'::jsonb, 1, 'Extubation should occur only when airway protective reflexes and mental status are adequate, and emergency reintubation equipment must be immediately available.', 'Pre-Council', '🎓', true),
(6484, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When intubating a patient with suspected cervical spine injury, the recommended technique to protect the spine is:', '["Full neck extension for optimal glottic view", "Manual in-line stabilization with the anterior portion of the cervical collar removed during the procedure", "Flexion of the neck", "Leaving the patient fully upright"]'::jsonb, 1, 'The anterior portion of the collar is typically opened and an assistant maintains manual in-line stabilization to limit neck movement while allowing jaw manipulation for intubation.', 'Pre-Council', '🎓', true),
(6485, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'All trauma patients undergoing emergency intubation should be treated as having a ''full stomach'' primarily because:', '["They have usually eaten recently", "Trauma, pain, and opioids delay gastric emptying, increasing aspiration risk", "It simplifies documentation", "It reduces the need for preoxygenation"]'::jsonb, 1, 'Trauma, stress, pain, and opioid analgesia delay gastric emptying; all trauma patients are assumed to have a full stomach, increasing aspiration risk during induction.', 'Pre-Council', '🎓', true),
(6486, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Rapid sequence intubation (RSI) in trauma is characterized by:', '["Slow titration of sedative with bag-mask ventilation between doses", "Near-simultaneous administration of a sedative or induction agent and a rapid-onset paralytic to minimize time between loss of airway reflexes and securing the airway", "Intubation without any sedation", "Awake intubation using topical anesthesia only"]'::jsonb, 1, 'RSI uses a predetermined induction agent immediately followed by a fast-acting neuromuscular blocker to rapidly achieve intubating conditions and minimize aspiration risk from prolonged bag-mask ventilation.', 'Pre-Council', '🎓', true),
(6487, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In a hypotensive trauma patient requiring rapid sequence intubation, which induction agent is often preferred due to relative hemodynamic stability?', '["Propofol at a standard dose", "Etomidate or ketamine", "High-dose midazolam", "Thiopental"]'::jsonb, 1, 'Etomidate and ketamine are favored in hemodynamically unstable trauma patients because they cause less cardiovascular depression compared with propofol or high-dose benzodiazepines.', 'Pre-Council', '🎓', true),
(6488, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why should induction agent doses typically be reduced in a trauma patient in hemorrhagic shock?', '["Shock patients metabolize drugs faster", "Reduced circulating volume and altered pharmacokinetics increase sensitivity to induction agents, risking severe hypotension or cardiovascular collapse", "It has no impact on dosing", "To shorten onset time"]'::jsonb, 1, 'In shock, reduced cardiac output delivers drug to the brain faster and a smaller volume of distribution increases drug sensitivity, so standard doses can cause profound hypotension.', 'Pre-Council', '🎓', true),
(6489, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A trauma patient with significant facial and airway trauma is being intubated. Which additional preparation is essential?', '["No additional preparation is needed beyond standard rapid sequence intubation", "Have a surgical airway kit immediately available and consider a difficult airway algorithm", "Proceed with nasotracheal intubation regardless of facial fractures", "Delay all preoxygenation"]'::jsonb, 1, 'Facial and airway trauma increases the likelihood of a difficult or failed airway, so backup surgical airway equipment and a difficult airway plan must be immediately available.', 'Pre-Council', '🎓', true),
(6490, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Nasotracheal intubation is generally contraindicated in trauma patients with suspected:', '["Rib fractures", "Basilar skull fracture or significant midface fracture", "Pelvic fracture", "Long bone fracture"]'::jsonb, 1, 'Nasal intubation risks inadvertent intracranial tube placement through a fractured cribriform plate in basilar skull or severe midface fractures, so it is avoided.', 'Pre-Council', '🎓', true),
(6491, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During intubation of a trauma patient, cricoid pressure, if used, should be released if:', '["It is never released once applied", "It obscures the laryngoscopic view or impedes intubation or ventilation", "The patient is easy to ventilate", "SpO2 is above 95%"]'::jsonb, 1, 'Cricoid pressure should be released or adjusted if it worsens the laryngoscopic view or impairs ventilation or intubation, as its routine use is now debated.', 'Pre-Council', '🎓', true),
(6492, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A trauma patient requires intubation for airway protection due to a decreasing Glasgow Coma Scale score. Before induction, the nurse should ensure availability of:', '["Only a bag-valve mask", "Suction, a working laryngoscope, correctly sized tube with functioning cuff, backup airway devices, and hemodynamic support at the bedside", "A nasogastric tube only", "An arterial line only"]'::jsonb, 1, 'Emergency airway management requires full preparation, including working equipment, backup devices, and readiness to treat peri-intubation hypotension.', 'Pre-Council', '🎓', true),
(6493, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is a key hemodynamic risk during intubation of a trauma patient in shock?', '["Hypertension from pain only", "Cardiovascular collapse from combined effects of positive-pressure ventilation, sedative-induced vasodilation, and loss of sympathetic drive", "Bradycardia from vagal tone alone, unrelated to volume status", "No significant hemodynamic risk if preoxygenated"]'::jsonb, 1, 'Peri-intubation cardiac arrest in shock patients results from combined induction-agent effects, loss of catecholamine drive, and increased intrathoracic pressure from positive-pressure ventilation reducing venous return.', 'Pre-Council', '🎓', true),
(6494, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In a trauma patient with suspected pneumothorax, what should be addressed before or concurrent with intubation and initiation of positive-pressure ventilation?', '["Nothing extra is needed", "Decompression of the pneumothorax, since positive-pressure ventilation can rapidly convert it to a tension pneumothorax", "Delaying intubation indefinitely", "Placing the patient supine only"]'::jsonb, 1, 'Positive-pressure ventilation can rapidly worsen an occult or simple pneumothorax into a tension pneumothorax, so it should be decompressed promptly.', 'Pre-Council', '🎓', true),
(6495, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When preoxygenating a trauma patient with facial injuries before intubation, the nurse should be cautious with bag-valve-mask ventilation because:', '["It always causes hypoxemia", "Excessive ventilation pressure can cause gastric insufflation and increase aspiration risk, and may worsen facial injuries", "It has no risks", "It improves cervical spine stability"]'::jsonb, 1, 'Aggressive bag-mask ventilation increases the risk of gastric insufflation, raising aspiration risk, and mask seal may be complicated by facial trauma.', 'Pre-Council', '🎓', true),
(6496, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A trauma patient with a distended, tense abdomen requires intubation. Why is this significant for airway management?', '["It indicates the patient has already been intubated", "Abdominal distension can increase aspiration risk and reduce functional residual capacity, complicating preoxygenation and increasing desaturation risk", "It is unrelated to airway management", "It improves oxygen reserve"]'::jsonb, 1, 'Abdominal distension raises intra-abdominal pressure, reduces functional residual capacity and oxygen reserve, and increases regurgitation and aspiration risk.', 'Pre-Council', '🎓', true),
(6497, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Manual in-line stabilization during trauma intubation is performed by:', '["The intubating provider alone", "A second provider stabilizing the head and neck in neutral alignment while the anterior collar is removed", "Applying axial traction to the neck", "The patient stabilizing their own head"]'::jsonb, 1, 'A dedicated assistant holds the head and neck in neutral in-line position, allowing the anterior collar to be removed for jaw thrust and laryngoscopy while limiting cervical spine motion.', 'Pre-Council', '🎓', true),
(6498, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which statement about difficult airway prediction in facial trauma is accurate?', '["Facial trauma never affects airway difficulty", "Distorted anatomy, bleeding, edema, and secretions from facial trauma commonly increase intubation difficulty and should prompt a difficult airway plan", "Facial trauma only affects nasal intubation", "Difficult airway equipment is unnecessary if the Glasgow Coma Scale score is normal"]'::jsonb, 1, 'Facial trauma distorts landmarks, causes bleeding and secretions that obscure the view, and can cause airway edema, all increasing intubation difficulty.', 'Pre-Council', '🎓', true),
(6499, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In Assist-Control (AC) ventilation, every breath, whether patient-triggered or ventilator-initiated, receives:', '["A variable, patient-determined tidal volume", "The full preset tidal volume or pressure target", "No support at all", "Only PEEP"]'::jsonb, 1, 'In AC mode, both mandatory and patient-triggered breaths deliver the full set tidal volume or pressure, ensuring guaranteed minute ventilation but risking hyperventilation if the patient breathes rapidly.', 'Pre-Council', '🎓', true),
(6500, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A potential complication of Assist-Control ventilation in a patient who is tachypneic from anxiety or pain is:', '["Hypoventilation and hypercapnia", "Respiratory alkalosis from hyperventilation, along with breath stacking and auto-PEEP", "Inability to trigger any breaths", "Automatic apnea"]'::jsonb, 1, 'Because every triggered breath in AC delivers the full tidal volume, a rapid respiratory rate can cause hyperventilation and insufficient expiratory time, leading to breath stacking and auto-PEEP.', 'Pre-Council', '🎓', true),
(6501, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'SIMV, or synchronized intermittent mandatory ventilation, differs from AC in that:', '["SIMV delivers full mandatory support on every breath like AC", "SIMV delivers a set number of synchronized mandatory breaths, while additional patient-initiated breaths between them are typically unsupported or only pressure-supported, not full mandatory volume", "SIMV cannot be synchronized with patient effort", "SIMV is only used for pediatric patients"]'::jsonb, 1, 'In SIMV, mandatory breaths are synchronized to patient effort at a set rate, but spontaneous breaths taken between mandatory breaths receive only the patient''s own effort, often augmented with pressure support.', 'Pre-Council', '🎓', true),
(6502, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'SIMV is often used clinically as a mode for:', '["Fully sedated or paralyzed ARDS patients requiring guaranteed full support", "Weaning patients from mechanical ventilation by gradually reducing the mandatory rate", "Initial resuscitation of an apneic patient", "Patients who cannot trigger any breaths"]'::jsonb, 1, 'SIMV allows a mix of mandatory and spontaneous breaths and has traditionally been used to gradually wean patients by decreasing the set mandatory rate as spontaneous effort increases.', 'Pre-Council', '🎓', true),
(6503, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key disadvantage of SIMV, especially at low mandatory rates, is:', '["It eliminates the work of breathing entirely", "Increased work of breathing for the patient during unsupported spontaneous breaths, potentially causing fatigue", "It cannot be combined with PEEP", "It prevents any spontaneous breathing"]'::jsonb, 1, 'Unsupported spontaneous breaths between mandatory breaths require the patient to generate their own inspiratory effort against tube and circuit resistance, which can increase work of breathing and cause fatigue.', 'Pre-Council', '🎓', true),
(6504, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In Pressure Control Ventilation (PCV), the clinician sets:', '["Tidal volume and flow rate", "The inspiratory pressure level and inspiratory time, with tidal volume as the dependent variable", "Only FiO2", "Only PEEP"]'::jsonb, 1, 'PCV is a pressure-targeted mode where the set inspiratory pressure and inspiratory time determine the breath; resulting tidal volume depends on the patient''s lung compliance and airway resistance.', 'Pre-Council', '🎓', true),
(6505, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Compared with Volume Control Ventilation, an advantage of Pressure Control Ventilation is:', '["Guaranteed constant tidal volume regardless of compliance changes", "A decelerating flow pattern that may improve gas distribution and directly limit peak airway pressures", "Elimination of the need for a set respiratory rate", "Automatic weaning capability"]'::jsonb, 1, 'PCV''s decelerating flow and pressure-limited delivery can improve gas distribution in noncompliant lungs and directly limits peak inspiratory pressure, which volume control does not guarantee.', 'Pre-Council', '🎓', true),
(6506, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A disadvantage of Pressure Control Ventilation compared to Volume Control is:', '["Tidal volume is fixed and predictable", "Tidal volume is variable and can change unpredictably with changes in patient compliance or resistance, requiring close monitoring", "It always causes barotrauma", "It cannot be used with PEEP"]'::jsonb, 1, 'Since PCV delivers a set pressure rather than volume, delivered tidal volume varies breath to breath as compliance or resistance changes, requiring vigilant monitoring of exhaled tidal volume.', 'Pre-Council', '🎓', true),
(6507, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilator mode commonly chosen for ARDS patients to strictly limit peak and plateau airway pressures while accepting variable tidal volumes is:', '["SIMV with no pressure support", "Pressure Control Ventilation", "CPAP alone", "T-piece trial"]'::jsonb, 1, 'PCV allows precise control of the maximum airway pressure delivered each breath, valuable in ARDS to minimize barotrauma, while tidal volume varies within safe limits.', 'Pre-Council', '🎓', true),
(6508, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In Volume Control ventilation, a form of AC, if a patient''s airway resistance suddenly increases from bronchospasm, what happens to peak airway pressure?', '["It decreases", "It increases, since the set volume is delivered regardless of resistance", "It remains constant", "The ventilator stops delivering volume"]'::jsonb, 1, 'In volume-controlled ventilation, the ventilator delivers the preset tidal volume regardless of resistance changes, so increased resistance results in higher peak and plateau pressures.', 'Pre-Council', '🎓', true),
(6509, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which mode of ventilation would be least appropriate as the sole mode for an apneic, heavily sedated patient with no spontaneous respiratory effort?', '["Assist-Control", "Pressure Control Ventilation", "CPAP with pressure support alone and no backup mandatory rate", "SIMV with an adequate mandatory rate"]'::jsonb, 2, 'CPAP or pressure support without a backup mandatory rate relies on the patient''s spontaneous effort to trigger breaths; an apneic patient would receive no ventilation, risking respiratory arrest.', 'Pre-Council', '🎓', true),
(6510, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Pressure Support Ventilation, often combined with SIMV or used alone for weaning, functions by:', '["Delivering a fixed mandatory rate regardless of patient effort", "Augmenting each patient-triggered spontaneous breath with a set inspiratory pressure to reduce work of breathing", "Controlling only the expiratory phase", "Eliminating the need for patient-triggered breaths"]'::jsonb, 1, 'Pressure support adds a clinician-set level of inspiratory pressure assistance to each spontaneous breath the patient initiates, decreasing work of breathing through the tube and circuit.', 'Pre-Council', '🎓', true),
(6511, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient on AC ventilation is triggering breaths at a rate of 32 per minute due to anxiety and pain. The priority nursing intervention is to:', '["Immediately switch the patient to SIMV without a physician order", "Assess and treat the underlying cause, such as pain, anxiety, or hypoxemia, and notify the physician if breath stacking or hemodynamic compromise develops", "Ignore the rate since AC always compensates", "Turn off all alarms"]'::jsonb, 1, 'A high spontaneous trigger rate on AC increases the risk of breath stacking and auto-PEEP; the nurse should identify and treat reversible causes of tachypnea and communicate any worsening dyssynchrony.', 'Pre-Council', '🎓', true),
(6512, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What does auto-PEEP, or intrinsic PEEP, refer to?', '["The set PEEP level on the ventilator", "Trapped air and pressure remaining in the alveoli at end-expiration due to incomplete exhalation before the next breath is delivered", "PEEP applied only during CPAP", "A normal finding with no clinical significance"]'::jsonb, 1, 'Auto-PEEP occurs when insufficient expiratory time prevents full lung emptying, causing gas trapping and elevated end-expiratory alveolar pressure not reflected by the set PEEP.', 'Pre-Council', '🎓', true),
(6513, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient on AC or SIMV develops signs of severe auto-PEEP with hypotension. An appropriate emergency nursing action, in collaboration with respiratory therapy and the physician, is to:', '["Increase the respiratory rate further", "Briefly disconnect the patient from the ventilator to allow full exhalation, then adjust settings to increase expiratory time", "Increase tidal volume", "Add more PEEP immediately without assessment"]'::jsonb, 1, 'Momentarily disconnecting the circuit allows trapped gas to escape and can rapidly relieve severe auto-PEEP causing hemodynamic compromise, followed by ventilator adjustments to prevent recurrence.', 'Pre-Council', '🎓', true),
(6514, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Compared to AC ventilation, SIMV generally results in:', '["Higher mean airway pressures always", "Potentially lower mean airway pressure but greater patient work of breathing during spontaneous breaths", "Complete elimination of patient effort", "No ability to set PEEP"]'::jsonb, 1, 'Because not every breath in SIMV receives full mandatory support, mean airway pressures can be lower than AC, but the patient must generate more of their own respiratory effort.', 'Pre-Council', '🎓', true),
(6515, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which mode and setting combination best reflects a lung-protective pressure control strategy for ARDS?', '["High tidal volumes with zero PEEP", "A set inspiratory pressure that yields tidal volumes near 6 mL per kg predicted body weight combined with adequate PEEP titrated to oxygenation and compliance", "Unlimited peak pressure with high FiO2", "Pressure support only with no PEEP"]'::jsonb, 1, 'Lung-protective ventilation in ARDS aims for tidal volumes near 6 mL/kg predicted body weight, limited plateau pressures, and PEEP titrated to maintain alveolar recruitment.', 'Pre-Council', '🎓', true),
(6516, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The respiratory rate set on a ventilator in AC or SIMV mode represents:', '["The maximum rate the patient may breathe", "The minimum guaranteed number of full mandatory breaths per minute, with the patient able to trigger additional breaths above this in AC", "The exact rate the patient will always breathe at", "An alarm limit only"]'::jsonb, 1, 'The set rate establishes the minimum backup mandatory breath rate; in AC, patient-triggered breaths above this rate also receive full support.', 'Pre-Council', '🎓', true),
(6517, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key nursing and respiratory therapy consideration unique to PCV that is less critical in standard volume control is:', '["Monitoring FiO2", "Monitoring exhaled tidal volume for adequacy since it is not guaranteed by the machine", "Monitoring heart rate", "Checking endotracheal tube cuff pressure"]'::jsonb, 1, 'Because PCV does not guarantee a fixed tidal volume, ongoing monitoring of exhaled tidal volume is essential to ensure adequate minute ventilation as lung mechanics change.', 'Pre-Council', '🎓', true),
(6518, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Inverse Ratio Ventilation, sometimes used as a rescue pressure-control strategy in severe ARDS, involves:', '["Prolonging expiratory time relative to inspiratory time", "Prolonging inspiratory time relative to expiratory time, giving an I:E ratio greater than 1:1, to improve oxygenation via increased mean airway pressure", "Eliminating PEEP entirely", "Using only spontaneous breathing"]'::jsonb, 1, 'Inverse ratio ventilation reverses the normal I:E ratio to increase mean airway pressure, improving alveolar recruitment and oxygenation, though it risks auto-PEEP and requires heavy sedation.', 'Pre-Council', '🎓', true),
(6519, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When transitioning a stable patient from AC to SIMV in preparation for weaning, the nurse should closely monitor for signs of:', '["Improved comfort universally", "Increased work of breathing, tachypnea, accessory muscle use, or fatigue indicating intolerance", "Automatic extubation", "Loss of airway reflexes"]'::jsonb, 1, 'Because SIMV requires the patient to generate more spontaneous effort, the nurse must watch for signs of respiratory fatigue or distress indicating intolerance of decreased mandatory support.', 'Pre-Council', '🎓', true),
(6520, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What differentiates a controlled, non-triggered breath from an assisted, patient-triggered breath in AC mode?', '["Controlled breaths deliver a smaller volume", "Controlled breaths are time-triggered by the ventilator if the patient fails to initiate a breath within the set interval, while assisted breaths are triggered by patient effort, but both deliver the same full set volume or pressure", "There is no difference in AC mode", "Controlled breaths never occur in AC"]'::jsonb, 1, 'In AC, if the patient does not trigger a breath within the interval corresponding to the set rate, the ventilator delivers a mandatory breath; both mandatory and assisted breaths receive the full preset support.', 'Pre-Council', '🎓', true),
(6521, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilator mode where the patient controls their own respiratory rate and tidal volume with only pressure support and PEEP applied is best described as:', '["Assist-Control", "Pressure Support Ventilation, often combined with CPAP", "SIMV with 100% mandatory rate", "Pressure Control Ventilation with a fixed rate"]'::jsonb, 1, 'Pressure Support Ventilation provides only inspiratory pressure assistance to spontaneous breaths, with the patient determining their own rate and, to an extent, tidal volume.', 'Pre-Council', '🎓', true),
(6522, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which statement about triggering sensitivity on a ventilator is correct?', '["Triggering sensitivity is irrelevant to patient comfort", "If trigger sensitivity is set too insensitive, requiring excessive effort, the patient may struggle to initiate breaths, increasing work of breathing and dyssynchrony", "Trigger sensitivity only applies to controlled modes", "Trigger sensitivity cannot be adjusted"]'::jsonb, 1, 'Flow or pressure trigger sensitivity determines how much patient effort is needed to initiate a supported breath; if set too insensitive, the patient must work harder, causing dyssynchrony and fatigue.', 'Pre-Council', '🎓', true),
(6523, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'For a hemodynamically unstable ARDS patient requiring precise control of airway pressures to minimize barotrauma risk while sedated, which mode is often preferred initially?', '["Pressure Support Ventilation with a low backup rate", "Pressure Control Ventilation, or volume control with a plateau pressure limit, with controlled mandatory breaths", "CPAP alone", "T-piece trial"]'::jsonb, 1, 'A fully controlled mode ensures guaranteed ventilation and precise pressure or volume limits appropriate for a sedated, unstable ARDS patient who cannot reliably trigger effective spontaneous breaths.', 'Pre-Council', '🎓', true),
(6524, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During a routine respiratory assessment of a mechanically ventilated patient, the nurse notes new asymmetric chest expansion and absent breath sounds on the right, with tracheal deviation to the left. This most urgently suggests:', '["Mucus plugging of the left mainstem bronchus", "Right-sided tension pneumothorax", "A normal variant", "Right mainstem intubation"]'::jsonb, 1, 'Absent breath sounds with tracheal deviation away from the affected side and asymmetric chest expansion are classic signs of tension pneumothorax, a life-threatening emergency.', 'Pre-Council', '🎓', true),
(6525, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse assessing a ventilated patient should evaluate for signs of inadequate oxygenation or ventilation including all of the following EXCEPT:', '["Restlessness and confusion", "Tachycardia", "Bradycardia and hypotension as late signs", "Polyuria"]'::jsonb, 3, 'Polyuria is not a typical sign of hypoxemia or hypoventilation; restlessness, tachycardia, and eventually bradycardia and hypotension are recognized signs of worsening respiratory compromise.', 'Pre-Council', '🎓', true),
(6526, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key nursing assessment component specific to a patient receiving neuromuscular blockade for ventilator synchrony is:', '["Assessing verbal pain reports", "Using a peripheral nerve stimulator, such as train-of-four, to monitor level of blockade and ensuring adequate concurrent sedation and analgesia", "Allowing the patient to ambulate", "Discontinuing all monitoring since the patient cannot move"]'::jsonb, 1, 'Paralyzed patients cannot demonstrate pain or awareness behaviorally, so train-of-four monitoring guides blockade depth, and adequate sedation and analgesia must be ensured since paralytics have no sedative or analgesic effect.', 'Pre-Council', '🎓', true),
(6527, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When assessing a mechanically ventilated patient''s readiness for a spontaneous breathing trial, the nurse should confirm:', '["The patient is deeply sedated", "Hemodynamic stability, adequate oxygenation on minimal support, and the ability to initiate spontaneous breaths", "The patient has a fever", "The patient requires increasing FiO2"]'::jsonb, 1, 'Spontaneous breathing trial readiness criteria typically include hemodynamic stability, adequate oxygenation on low FiO2 and PEEP, and adequate mentation without excessive sedation.', 'Pre-Council', '🎓', true),
(6528, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In an intubated patient, an increase in peak inspiratory pressure with an unchanged plateau pressure most likely indicates a problem with:', '["Lung compliance, such as worsening ARDS", "Airway resistance, such as secretions, bronchospasm, or a kinked tube", "The set PEEP", "The set FiO2"]'::jsonb, 1, 'Peak pressure reflects both airway resistance and compliance, while plateau pressure reflects compliance alone; a rise in peak with a stable plateau isolates the problem to increased airway resistance.', 'Pre-Council', '🎓', true),
(6529, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An increase in both peak and plateau pressures in a ventilated patient, with the pressure difference between them unchanged, suggests a problem with:', '["Airway resistance only", "Lung or chest wall compliance, such as worsening pulmonary edema, pneumothorax, or abdominal distension", "The humidifier", "The suction catheter"]'::jsonb, 1, 'When peak and plateau pressures rise together while their difference stays the same, the underlying issue is decreased compliance of the lungs or chest wall rather than increased airway resistance.', 'Pre-Council', '🎓', true),
(6530, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse notes copious thick secretions requiring frequent suctioning in a ventilated patient. An appropriate independent nursing intervention is:', '["Decrease humidification to dry secretions", "Ensure adequate systemic hydration and airway humidification, and reposition or mobilize the patient to promote secretion clearance", "Increase sedation to reduce coughing", "Restrict oral and IV fluids"]'::jsonb, 1, 'Adequate hydration and humidification thin secretions for easier clearance, and repositioning and mobility help mobilize secretions; over-sedation can worsen secretion retention by blunting cough.', 'Pre-Council', '🎓', true),
(6531, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing assessment finding would indicate a need to reassess endotracheal tube cuff integrity?', '["Stable vital signs", "An audible air leak around the tube, decreased exhaled tidal volume, and the patient able to vocalize despite being intubated", "A normal capnography waveform", "Appropriate tube depth marking"]'::jsonb, 1, 'A cuff leak allows air to escape around the tube, causing an audible leak and reduced exhaled volumes, and may allow the patient to make sounds around the tube, requiring urgent evaluation.', 'Pre-Council', '🎓', true),
(6532, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'For a ventilated patient, daily nursing assessment of gastrointestinal status includes monitoring for:', '["Signs of stress ulcer or gastrointestinal bleeding and confirming ordered stress ulcer prophylaxis is administered", "Only bowel sounds every shift", "Nothing specific, since gastrointestinal status is unrelated to ventilation", "Discontinuing enteral feeds automatically"]'::jsonb, 0, 'Critically ill ventilated patients are at increased risk for stress-related mucosal disease; nurses monitor for bleeding signs and ensure prescribed prophylaxis and appropriate enteral nutrition.', 'Pre-Council', '🎓', true),
(6533, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilated patient''s SpO2 drops from 96% to 88% acutely. Using a systematic differential for displacement, obstruction, pneumothorax, and equipment failure, the nurse should assess for all of these EXCEPT:', '["Tube displacement or dislodgement", "Airway obstruction from secretions", "Pneumothorax", "Recent oral care"]'::jsonb, 3, 'Recent oral care is not part of the differential for acute ventilator desaturation; the nurse should evaluate for tube displacement, obstruction, pneumothorax, and equipment or circuit failure.', 'Pre-Council', '🎓', true),
(6534, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'If a ventilated patient acutely desaturates and the cause is not immediately identified, an appropriate first-line nursing action while troubleshooting is to:', '["Leave the patient on the ventilator and wait", "Disconnect from the ventilator and manually ventilate with a bag-valve device on 100% oxygen while assessing for the cause", "Immediately extubate", "Turn off all alarms to focus"]'::jsonb, 1, 'Manually bagging with 100% oxygen while troubleshooting helps isolate whether the problem is with the ventilator or circuit versus the patient or airway, and ensures oxygen delivery during assessment.', 'Pre-Council', '🎓', true),
(6535, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Ongoing nursing assessment of pain and sedation level in ventilated patients using validated scales is important because:', '["Sedation should always be maximized to prevent any patient awareness", "Over- or under-sedation both carry risks, such as delirium, prolonged ventilation, self-extubation, or distress, so targeted, regularly reassessed sedation improves outcomes", "Pain assessment is unnecessary in sedated patients", "Sedation scores have no bearing on weaning"]'::jsonb, 1, 'Protocolized, targeted sedation using validated scales avoids the harms of both oversedation, such as prolonged ventilation and delirium, and undersedation, such as distress and self-extubation.', 'Pre-Council', '🎓', true),
(6536, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing intervention helps reduce the risk of unplanned self-extubation in an agitated ventilated patient?', '["Leaving hands and the tube untethered for comfort", "Appropriate sedation and analgesia management, use of soft wrist restraints per protocol when clinically indicated, and properly securing the tube", "Removing all monitoring", "Increasing tidal volume"]'::jsonb, 1, 'Preventing self-extubation involves adequately treating pain and agitation, properly securing the tube, and using restraints per protocol only when less restrictive measures are inadequate.', 'Pre-Council', '🎓', true),
(6537, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse is assessing an intubated patient''s response to increasing FiO2 from 40% to 60% for a SpO2 of 89%. After 10-15 minutes, SpO2 remains 89%. What should the nurse do next?', '["Continue increasing FiO2 indefinitely without further assessment", "Reassess the patient thoroughly, including breath sounds, secretions, tube position, and hemodynamics, and notify the physician if hypoxemia persists", "Decrease FiO2 back to 40%", "Discontinue PEEP"]'::jsonb, 1, 'Persistent hypoxemia despite increased FiO2 warrants a full reassessment for reversible causes and timely physician notification, since it indicates a significant clinical change.', 'Pre-Council', '🎓', true),
(6538, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which is an appropriate nursing intervention to reduce complications of immobility in a critically ill ventilated patient?', '["Keep the patient supine and immobile until extubation", "Implement early mobility protocols as hemodynamically tolerated, along with regular repositioning, DVT prophylaxis, and skin care", "Avoid all repositioning to prevent tube dislodgement", "Discontinue DVT prophylaxis while intubated"]'::jsonb, 1, 'Early mobility when safe, frequent repositioning, and prophylactic measures reduce ICU-acquired weakness, pressure injuries, and venous thromboembolism in ventilated patients.', 'Pre-Council', '🎓', true),
(6539, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When performing a neurological assessment on a ventilated, sedated patient, what should the nurse prioritize?', '["Skip the neurological assessment since the patient is sedated", "Periodic sedation interruption when appropriate, or use of validated sedation and delirium scales to assess level of consciousness and detect delirium", "Assume normal neurological status", "Rely solely on family report"]'::jsonb, 1, 'Regular use of validated tools such as a sedation scale and a delirium screening tool allows objective neurological assessment even in sedated ICU patients and guides sedation titration.', 'Pre-Council', '🎓', true),
(6540, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilated patient develops new-onset agitation, tachycardia, and hypertension despite no apparent ventilator alarm. Priority nursing assessment should rule out:', '["Only anxiety", "Hypoxemia, pain, ventilator dyssynchrony, and other physiologic causes before attributing symptoms to agitation alone", "Nothing; sedate immediately without assessment", "Low fluid intake only"]'::jsonb, 1, 'New agitation and hemodynamic changes in a ventilated patient should prompt assessment for underlying physiologic causes rather than immediate sedation, which could mask a serious problem.', 'Pre-Council', '🎓', true),
(6541, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A critical nursing responsibility when caring for a ventilated patient includes ensuring the presence of which equipment at the bedside at all times?', '["Only a stethoscope", "A manual resuscitation bag-valve mask connected to oxygen, suction equipment, and appropriately sized airway supplies", "A wheelchair", "Extra bed linens"]'::jsonb, 1, 'Emergency bag-valve-mask, functioning suction, and airway equipment must always be immediately available at the bedside of an intubated patient to manage sudden deterioration or accidental extubation.', 'Pre-Council', '🎓', true),
(6542, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which finding in a mechanically ventilated patient requires IMMEDIATE physician notification?', '["Stable vital signs with SpO2 97%", "An unresponsive patient with a new fixed, dilated pupil and no response to ventilator adjustments", "Routine cuff pressure of 25 cmH2O", "A scheduled sedation vacation"]'::jsonb, 1, 'A new fixed, dilated pupil suggests an acute neurologic catastrophe, such as herniation or stroke, and is a critical, time-sensitive finding requiring immediate physician notification.', 'Pre-Council', '🎓', true),
(6543, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A sustained rise in peak and plateau airway pressures unresponsive to suctioning and repositioning should prompt the nurse to:', '["Wait until the next shift to report it", "Notify the physician promptly, as this may indicate worsening lung compliance, pneumothorax, or other significant pathology", "Simply increase sedation and not report it", "Decrease the tidal volume without an order"]'::jsonb, 1, 'Persistent, unexplained rising airway pressures despite basic troubleshooting suggest a significant change in condition requiring prompt physician evaluation.', 'Pre-Council', '🎓', true),
(6544, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse should notify the physician immediately if an intubated patient exhibits which of the following?', '["Baseline anxiety managed with prescribed sedation", "Inability to pass a suction catheter through the endotracheal tube", "Scheduled arterial blood gas results within normal limits", "Routine oral care completed"]'::jsonb, 1, 'Inability to pass a suction catheter suggests possible tube obstruction, kinking, or malposition, which can rapidly compromise ventilation and requires urgent notification.', 'Pre-Council', '🎓', true),
(6545, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilated patient''s EtCO2 progressively rises over several hours from 38 to 55 mmHg despite no ventilator setting changes, accompanied by increasing somnolence. This trend requires the nurse to:', '["Continue routine monitoring without action", "Notify the physician promptly, as this suggests worsening hypoventilation or CO2 retention needing evaluation", "Decrease the FiO2", "Discontinue capnography monitoring"]'::jsonb, 1, 'A progressive, unexplained rise in EtCO2 with declining mental status indicates worsening hypoventilation or CO2 retention, a significant clinical change warranting prompt physician notification.', 'Pre-Council', '🎓', true),
(6546, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'New-onset hemodynamic instability, with hypotension and tachycardia, shortly after a ventilator setting change such as increased PEEP warrants:', '["No action, since this is expected and self-resolving", "Prompt reassessment and physician notification, as the change may be contributing to decreased venous return or cardiac output", "Increasing PEEP further", "Discontinuing all monitoring"]'::jsonb, 1, 'Ventilator changes, particularly increased PEEP, can reduce venous return and cardiac output; new hemodynamic instability temporally related to a setting change should be promptly reported.', 'Pre-Council', '🎓', true),
(6547, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following arterial blood gas trends in a ventilated patient should be reported to the physician rather than simply documented?', '["A stable, chronically compensated blood gas matching baseline", "A new significant respiratory acidosis or worsening hypoxemia compared to previous values", "A blood gas drawn per routine schedule with expected results", "A normal arterial blood gas"]'::jsonb, 1, 'New or worsening acid-base or oxygenation abnormalities represent a clinically significant change that may require treatment adjustment, warranting physician notification.', 'Pre-Council', '🎓', true),
(6548, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient on mechanical ventilation develops visible accessory muscle use, diaphoresis, and asynchrony with the ventilator despite appropriate sedation. The nurse should:', '["Increase the tidal volume without an order", "Assess for reversible causes and notify the physician or respiratory therapist for possible setting or sedation adjustment", "Disregard this as normal behavior", "Discontinue sedation entirely"]'::jsonb, 1, 'Significant patient-ventilator dyssynchrony despite adequate sedation suggests settings may not match patient demand or a new problem has arisen, and should be assessed and reported.', 'Pre-Council', '🎓', true),
(6549, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Notification of the physician is necessary when an intubated patient''s cuff requires progressively larger volumes of air to maintain a seal, because this may indicate:', '["Normal cuff function", "Tracheomalacia or cuff and tube damage requiring evaluation", "Appropriate tube sizing", "Improved lung compliance"]'::jsonb, 1, 'A cuff requiring increasing air volumes to seal may signal cuff or pilot balloon damage, or tracheal dilation from prolonged cuff pressure, both needing prompt evaluation.', 'Pre-Council', '🎓', true),
(6550, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilated patient develops a new cardiac dysrhythmia, such as new atrial fibrillation with rapid ventricular response, along with desaturation. The nurse should:', '["Treat this as an isolated cardiac issue unrelated to ventilation", "Assess for hypoxemia or ventilatory causes contributing to the dysrhythmia and notify the physician promptly given the combined instability", "Wait for the next scheduled assessment", "Decrease FiO2"]'::jsonb, 1, 'Hypoxemia is a common trigger for new dysrhythmias in critically ill patients; the combination of new dysrhythmia and desaturation reflects significant compromise requiring urgent notification.', 'Pre-Council', '🎓', true),
(6551, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Physician notification is warranted for which change in an intubated patient''s secretions?', '["Clear, thin secretions in normal amounts", "A new large amount of frank blood or purulent, foul-smelling secretions", "Routine suctioning needs", "Secretions that thin after adequate humidification"]'::jsonb, 1, 'New hemoptysis or purulent, foul-smelling secretions may indicate airway trauma, bleeding, or a new pulmonary infection and should be reported for further evaluation.', 'Pre-Council', '🎓', true),
(6552, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilated patient''s low minute ventilation alarm persistently triggers despite ventilator checks and troubleshooting. Appropriate nursing action includes:', '["Silencing the alarm permanently", "Reassessing the patient and circuit, and notifying the physician or respiratory therapist if the cause cannot be identified and corrected", "Increasing sedation only", "Ignoring alarms during quiet hours"]'::jsonb, 1, 'Persistent, unresolved alarms indicate an unaddressed problem with ventilation adequacy and require thorough reassessment with escalation if the source is not found and corrected.', 'Pre-Council', '🎓', true),
(6553, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When should the nurse notify the physician regarding an intubated patient''s level of consciousness?', '["Only if the family requests an update", "If there is an unexpected decrease in responsiveness not attributable to sedation, or failure to wake appropriately during a sedation interruption", "Only during shift change", "Never, since sedation controls consciousness"]'::jsonb, 1, 'An unexpected decline in consciousness beyond what is explained by sedation may indicate a new neurologic event or worsening hypoxemia/hypercapnia, requiring prompt evaluation.', 'Pre-Council', '🎓', true),
(6554, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A ventilated patient requires escalating FiO2 and PEEP over a short period to maintain oxygenation targets. This trend should be:', '["Considered a normal part of ventilator management not requiring reporting", "Communicated to the physician, as it may indicate worsening respiratory status requiring reassessment of the treatment plan", "Resolved solely by nursing without physician input", "Addressed by discontinuing PEEP"]'::jsonb, 1, 'A rising oxygen and PEEP requirement signals deteriorating lung function and should prompt physician notification for reassessment and possible escalation of therapy.', 'Pre-Council', '🎓', true),
(6555, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse should notify the physician promptly if an intubated patient develops subcutaneous emphysema, or crepitus, around the neck and chest because this may indicate:', '["A benign, expected finding requiring no action", "Barotrauma with air leaking into subcutaneous tissue, such as from pneumothorax or airway injury", "Normal cuff inflation", "Improved oxygenation"]'::jsonb, 1, 'New subcutaneous emphysema suggests air escaping into tissue planes, often from barotrauma, pneumothorax, or tracheobronchial injury, requiring prompt physician notification.', 'Pre-Council', '🎓', true),
(6556, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which situation involving an intubated patient''s family or psychosocial status would still warrant physician communication in addition to nursing support?', '["Family simply visiting during open visiting hours", "Family expressing a request to discuss goals of care or possible withdrawal of aggressive treatment given the patient''s deteriorating status", "Family bringing personal items", "Family asking about visiting hours"]'::jsonb, 1, 'Family requests regarding goals of care or treatment decisions require physician involvement for informed discussion and documentation, alongside nursing support.', 'Pre-Council', '🎓', true),
(6557, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'One of the most important immediate benefits of continuous waveform capnography after intubation is:', '["Measuring blood pressure noninvasively", "Confirming correct tracheal, as opposed to esophageal, tube placement in real time", "Measuring core body temperature", "Assessing renal function"]'::jsonb, 1, 'A sustained, characteristic capnography waveform confirms the tube is in the trachea, whereas absence of a waveform strongly suggests esophageal placement.', 'Pre-Council', '🎓', true),
(6558, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Continuous EtCO2 monitoring provides ongoing benefit during mechanical ventilation by:', '["Replacing the need for any blood gas analysis", "Providing breath-by-breath, real-time trending of ventilation adequacy between intermittent arterial blood gas measurements", "Measuring oxygen saturation directly", "Eliminating the need for chest x-rays"]'::jsonb, 1, 'EtCO2 offers continuous, real-time trend information about ventilation status, allowing detection of changes between the intermittent snapshots provided by arterial blood gases.', 'Pre-Council', '🎓', true),
(6559, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The EtCO2 value typically correlates with, and is normally slightly lower than, which arterial value?', '["PaO2", "PaCO2", "Serum bicarbonate", "Arterial pH"]'::jsonb, 1, 'EtCO2 approximates PaCO2 with a normal gradient of about 2-5 mmHg due to alveolar dead space, allowing EtCO2 trends to estimate ventilation status noninvasively.', 'Pre-Council', '🎓', true),
(6560, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key benefit of capnography during procedural sedation, even in non-intubated patients, is:', '["It measures blood glucose", "It provides earlier detection of hypoventilation or apnea than pulse oximetry alone, often before desaturation occurs", "It eliminates the need for a pulse oximeter", "It measures end-tidal oxygen"]'::jsonb, 1, 'Because capnography detects ventilation changes breath by breath, it can identify hypoventilation or apnea before oxygen desaturation becomes apparent on pulse oximetry, especially with supplemental oxygen.', 'Pre-Council', '🎓', true),
(6561, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During cardiopulmonary resuscitation, continuous EtCO2 monitoring is beneficial because:', '["It has no role during CPR", "It reflects the effectiveness of chest compressions and cardiac output, and a sudden sustained rise can be an early indicator of return of spontaneous circulation", "It measures defibrillation energy delivered", "It replaces the need for pulse checks entirely without exception"]'::jsonb, 1, 'EtCO2 during CPR correlates with pulmonary blood flow generated by compressions; a persistently low value suggests poor compression quality, while a sudden sustained increase often signals ROSC.', 'Pre-Council', '🎓', true),
(6562, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'EtCO2 monitoring assists in early detection of which acute complication in a mechanically ventilated patient?', '["Skin breakdown", "Accidental extubation or ventilator circuit disconnection, via sudden loss of the waveform", "Urinary retention", "Constipation"]'::jsonb, 1, 'A sudden, complete loss of the capnography waveform is one of the earliest and most reliable indicators of accidental extubation or circuit disconnection.', 'Pre-Council', '🎓', true),
(6563, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In addition to confirming initial tube placement, capnography is recommended for continuous use throughout transport of an intubated patient because:', '["It is required by insurance only", "It provides ongoing confirmation that the tube remains correctly positioned and ventilation remains adequate despite movement", "It measures ambient temperature", "It has no additional benefit during transport"]'::jsonb, 1, 'Tube dislodgement is a known risk during patient movement and transport; continuous capnography provides real-time reassurance that the airway remains secure and ventilation adequate.', 'Pre-Council', '🎓', true),
(6564, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A benefit of capnography in detecting a sudden drop in cardiac output, such as from a massive pulmonary embolism or severe hypotension, is:', '["EtCO2 rises sharply with reduced cardiac output", "EtCO2 falls because reduced pulmonary blood flow decreases CO2 delivery to the alveoli for exhalation", "EtCO2 is unaffected by cardiac output", "Capnography monitoring cannot detect circulatory changes"]'::jsonb, 1, 'EtCO2 depends on both ventilation and pulmonary perfusion; a sudden drop in pulmonary blood flow decreases CO2 delivered to the alveoli, causing a corresponding fall in EtCO2.', 'Pre-Council', '🎓', true),
(6565, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Capnography can assist in the early recognition of malignant hyperthermia because:', '["EtCO2 decreases progressively", "EtCO2 rises rapidly and unexpectedly due to the marked increase in metabolic CO2 production", "EtCO2 remains unchanged", "Capnography cannot detect metabolic changes"]'::jsonb, 1, 'The hypermetabolic state of malignant hyperthermia causes a sharp, otherwise unexplained rise in CO2 production, often one of the earliest clinical clues detected as a sudden rise in EtCO2.', 'Pre-Council', '🎓', true),
(6566, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Using EtCO2 to guide ventilator adjustments in a patient managed with permissive hypercapnia, such as an ARDS lung-protective strategy, provides the benefit of:', '["Eliminating the need to check arterial blood gases entirely", "Allowing noninvasive, continuous trending of ventilation adequacy to help balance lung-protective settings against acceptable CO2 elevation", "Forcing normalization of PaCO2 at all times", "Preventing any hypercapnia from occurring"]'::jsonb, 1, 'Continuous EtCO2 trending helps the care team monitor the degree of hypercapnia noninvasively and in real time while implementing lung-protective ventilation, complementing periodic blood gas checks.', 'Pre-Council', '🎓', true),
(6567, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'One benefit of capnography for a patient receiving opioid analgesia or sedation who is NOT intubated is:', '["It measures pain intensity directly", "Nasal cannula capnography can provide early warning of opioid-induced hypoventilation or respiratory depression", "It monitors urinary output", "It replaces the need for any respiratory assessment"]'::jsonb, 1, 'Nasal EtCO2 monitoring in non-intubated patients receiving opioids or sedatives can detect early hypoventilation before clinically significant desaturation occurs, allowing earlier intervention.', 'Pre-Council', '🎓', true),
(6568, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'EtCO2 monitoring benefits nursing assessment of a ventilated patient''s dead space and ventilation efficiency because:', '["It has no relationship to dead space", "A widened gradient between PaCO2 and EtCO2 can indicate increased alveolar dead space, such as from pulmonary embolism, hypoperfusion, or hyperinflation", "It directly measures anatomic dead space volume", "It is only useful for confirming tube placement"]'::jsonb, 1, 'An abnormally widened PaCO2-EtCO2 gradient suggests increased alveolar dead space, seen in pulmonary embolism, low cardiac output states, or hyperinflation with high PEEP.', 'Pre-Council', '🎓', true),
(6569, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'On a normal capnogram, Phase III, the alveolar plateau, represents:', '["Inspiration", "The exhalation of CO2-rich alveolar gas, appearing as a relatively flat plateau ending at the EtCO2 value", "Dead space gas only", "The beginning of exhalation with no CO2"]'::jsonb, 1, 'Phase III is the alveolar plateau, reflecting mixed alveolar gas exhalation; its highest point marks the EtCO2 value, and it is normally nearly flat.', 'Pre-Council', '🎓', true),
(6570, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A sudden, complete loss of the capnography waveform, with a flatline and EtCO2 near zero, in an intubated patient most urgently suggests:', '["Mild bronchospasm", "Esophageal intubation, complete airway obstruction, ventilator disconnection, or accidental extubation", "Rebreathing of exhaled gas", "Hyperventilation"]'::jsonb, 1, 'A sudden flatline capnogram is a critical finding requiring immediate assessment for esophageal placement, complete obstruction, disconnection, or extubation.', 'Pre-Council', '🎓', true),
(6571, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A shark-fin shaped capnography waveform, with a slowly rising, sloped Phase II and Phase III, classically indicates:', '["Normal ventilation", "Bronchospasm or airway obstruction, such as an asthma or COPD exacerbation, causing uneven alveolar emptying", "Esophageal intubation", "Hyperthermia"]'::jsonb, 1, 'The shark-fin pattern reflects delayed, uneven emptying of alveoli with varying time constants, classically seen with bronchospasm or airflow obstruction.', 'Pre-Council', '🎓', true),
(6572, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A progressively rising capnogram baseline that does not return to zero during inspiration suggests:', '["Normal capnography", "Rebreathing of exhaled CO2, such as from exhausted CO2 absorbent, a faulty expiratory valve, or inadequate fresh gas flow", "Esophageal intubation", "Circuit disconnection"]'::jsonb, 1, 'The baseline should return to zero during inspiration as fresh gas is inhaled; failure to return to zero indicates the patient is rebreathing CO2 from a malfunctioning circuit component.', 'Pre-Council', '🎓', true),
(6573, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A curare cleft, a small notch or dip during the alveolar plateau of the capnogram in a mechanically ventilated patient, typically represents:', '["A ventilator malfunction requiring immediate circuit replacement", "The patient''s spontaneous inspiratory effort occurring during a mandatory ventilator breath, suggesting inadequate paralysis or ventilator asynchrony", "Esophageal intubation", "Complete airway obstruction"]'::jsonb, 1, 'A curare cleft appears when a partially paralyzed or spontaneously breathing patient makes an inspiratory effort during the mandatory breath''s alveolar plateau, indicating incomplete neuromuscular blockade.', 'Pre-Council', '🎓', true),
(6574, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A sudden, significant decrease in EtCO2 without loss of the waveform in a hemodynamically unstable patient should prompt the nurse to suspect:', '["Improved cardiac output", "Decreased pulmonary blood flow from hypotension, cardiac arrest, or massive pulmonary embolism", "Rebreathing", "Fever"]'::jsonb, 1, 'A sudden drop in EtCO2 with a preserved but smaller waveform suggests reduced pulmonary perfusion delivering less CO2 to the alveoli.', 'Pre-Council', '🎓', true),
(6575, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A gradual, progressive decrease in EtCO2 over time in a stable-appearing ventilated patient may indicate:', '["Hyperthermia", "Hypothermia, hyperventilation, or a developing hypoperfusion state", "Rebreathing", "Bronchospasm"]'::jsonb, 1, 'Gradual EtCO2 decline can reflect decreased CO2 production from hypothermia, increased minute ventilation from hyperventilation, or a slowly developing perfusion problem.', 'Pre-Council', '🎓', true),
(6576, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A gradual, progressive increase in EtCO2 over time may indicate:', '["Hyperventilation", "Hypoventilation, rising body temperature, or accumulating CO2 from an exhausted absorbent", "Pulmonary embolism", "Cardiac arrest"]'::jsonb, 1, 'Rising EtCO2 over time can result from hypoventilation relative to CO2 production, increased CO2 production from fever or sepsis, or rebreathing from absorbent exhaustion.', 'Pre-Council', '🎓', true),
(6577, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A sudden, sharp increase in EtCO2 could be caused by:', '["Esophageal intubation", "Release of a tourniquet or aortic cross-clamp, or bicarbonate administration, causing a bolus of CO2 to reach the lungs", "Accidental extubation", "Circuit disconnection"]'::jsonb, 1, 'Sudden CO2 boluses, from tourniquet or clamp release or from bicarbonate administration, transiently spike EtCO2.', 'Pre-Council', '🎓', true),
(6578, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'On capnography, the point during exhalation where CO2 first begins to rise from baseline, known as Phase II or the expiratory upstroke, reflects:', '["Pure dead space gas", "The transition from anatomic dead space gas to alveolar gas as exhalation progresses", "Inspiration", "Esophageal gas"]'::jsonb, 1, 'Phase II is the rapid upstroke as CO2-poor dead space gas is followed by CO2-rich alveolar gas mixing and rising toward the plateau.', 'Pre-Council', '🎓', true),
(6579, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An absent or markedly diminished capnography waveform immediately after intubation, despite good chest rise and bilateral breath sounds on auscultation, should be interpreted as:', '["Reassuring, since chest rise confirms correct placement", "A critical warning sign requiring reassessment for esophageal intubation, as breath sounds and chest rise can be misleading", "Evidence of bronchospasm", "Evidence of normal dead space"]'::jsonb, 1, 'Capnography is more reliable than auscultation or chest rise for confirming tracheal placement; a poor or absent waveform must be treated as possible esophageal intubation until proven otherwise.', 'Pre-Council', '🎓', true),
(6580, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A capnogram showing an abnormally widened alpha angle, the angle between Phase II and Phase III, is associated with:', '["Normal lung function", "Obstructive airway disease with delayed, uneven alveolar emptying", "Esophageal intubation", "Rebreathing only"]'::jsonb, 1, 'A widened alpha angle reflects a more sloped Phase II to Phase III transition from uneven, delayed emptying of alveoli with differing time constants, characteristic of obstructive lung disease.', 'Pre-Council', '🎓', true),
(6581, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In a patient with a known pulmonary embolism, capnography would classically show:', '["Increased EtCO2 with a narrowed PaCO2-EtCO2 gradient", "Decreased EtCO2 with a widened PaCO2-EtCO2 gradient due to increased alveolar dead space", "No change in EtCO2", "A shark-fin waveform"]'::jsonb, 1, 'Pulmonary embolism obstructs perfusion to ventilated alveoli, increasing alveolar dead space; EtCO2 falls while PaCO2 remains relatively higher, widening the gradient.', 'Pre-Council', '🎓', true),
(6582, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When troubleshooting an abnormal capnography waveform, which initial step should the nurse take if the waveform suddenly disappears?', '["Assume equipment malfunction and ignore it", "Immediately assess the patient directly, including airway, breath sounds, chest rise, and SpO2, rather than assuming only equipment failure", "Replace the capnography sensor before assessing the patient", "Increase the ventilator rate"]'::jsonb, 1, 'A sudden loss of waveform must first be treated as a potential patient emergency, such as extubation or obstruction, with immediate direct patient assessment rather than assuming a benign equipment problem.', 'Pre-Council', '🎓', true),
(6583, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A capnogram with a normal waveform shape but a persistently elevated baseline that never returns to zero, occurring in a patient using a circle breathing system, should prompt the nurse and respiratory therapist to check:', '["The pulse oximeter probe placement", "The CO2 absorbent canister and unidirectional expiratory valve for exhaustion or malfunction", "The endotracheal tube cuff pressure", "The patient''s temperature only"]'::jsonb, 1, 'In a circle system, an elevated non-zero baseline indicating rebreathing is classically caused by exhausted CO2 absorbent or a faulty expiratory valve allowing rebreathed gas to mix with fresh gas.', 'Pre-Council', '🎓', true),
(6584, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which capnography finding would be expected immediately after successful reintubation of a previously esophageally intubated patient?', '["Continued absent waveform", "Prompt appearance of a normal, sustained CO2 waveform with an appropriate EtCO2 value", "A shark-fin waveform", "A waveform that never returns to baseline"]'::jsonb, 1, 'Correction of esophageal intubation with proper tracheal placement should result in immediate appearance of a normal capnography waveform with a physiologic EtCO2 reading.', 'Pre-Council', '🎓', true),
(6585, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A capnography waveform that shows normal morphology but a low, flattened plateau with reduced EtCO2 amplitude in a patient with a large air leak around the tube cuff is explained by:', '["Increased CO2 production", "Dilution of exhaled CO2 sample by entrained room air through the leak, falsely lowering the measured EtCO2", "Esophageal intubation", "Rebreathing"]'::jsonb, 1, 'A significant cuff leak allows room air to mix with exhaled gas at the sampling site, diluting the CO2 concentration and producing a falsely low EtCO2 reading despite adequate underlying ventilation.', 'Pre-Council', '🎓', true),
(6586, 'Management of Patients with Respiratory Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During weaning trials, a rising EtCO2 trend accompanied by increased respiratory rate and use of accessory muscles most likely indicates:', '["Successful weaning progress", "Developing respiratory muscle fatigue and hypoventilation, suggesting weaning intolerance", "Hyperventilation", "Improved lung compliance"]'::jsonb, 1, 'Rising EtCO2 combined with tachypnea and accessory muscle use during a weaning trial suggests the patient is fatiguing and unable to sustain adequate spontaneous ventilation, indicating weaning intolerance.', 'Pre-Council', '🎓', true),
(6587, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Approximately what percentage of resting cardiac output do the kidneys normally receive?', '["40%", "5%", "10%", "20-25%"]'::jsonb, 3, 'The kidneys receive about one-fifth to one-quarter of cardiac output despite their small share of body weight, reflecting high metabolic and filtration demands.', 'Pre-Council', '🎓', true),
(6588, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which structure is the primary site of blood filtration in the nephron?', '["Distal convoluted tubule", "Collecting duct", "Glomerulus", "Loop of Henle"]'::jsonb, 2, 'The glomerulus is a tuft of capillaries where plasma is filtered under pressure into Bowman''s capsule, forming the filtrate that becomes urine.', 'Pre-Council', '🎓', true),
(6589, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nephron segment is primarily responsible for the countercurrent multiplier system that concentrates urine?', '["Bowman''s capsule", "Proximal convoluted tubule", "Renal pelvis", "Loop of Henle"]'::jsonb, 3, 'The descending and ascending limbs of the loop of Henle create a concentration gradient in the medullary interstitium via the countercurrent multiplier mechanism, enabling urine concentration.', 'Pre-Council', '🎓', true),
(6590, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The juxtaglomerular apparatus regulates blood pressure and renal blood flow chiefly by secreting which substance?', '["Antidiuretic hormone", "Aldosterone", "Renin", "Erythropoietin"]'::jsonb, 2, 'Juxtaglomerular cells release renin in response to reduced renal perfusion pressure or sympathetic stimulation, triggering the renin-angiotensin-aldosterone system.', 'Pre-Council', '🎓', true),
(6591, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Erythropoietin, essential for red blood cell production, is synthesized mainly by which renal cells in response to hypoxia?', '["Podocytes of the glomerulus", "Peritubular interstitial cells of the cortex", "Cells of the loop of Henle", "Mesangial cells"]'::jsonb, 1, 'Peritubular fibroblast-like interstitial cells in the renal cortex sense hypoxia and secrete erythropoietin, explaining why chronic kidney disease commonly causes anemia.', 'Pre-Council', '🎓', true),
(6592, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The kidney contributes to bone mineral metabolism primarily by performing which function?', '["Producing calcitonin", "Converting 25-hydroxyvitamin D to its active form, calcitriol", "Storing calcium in the renal medulla", "Synthesizing parathyroid hormone"]'::jsonb, 1, 'Proximal tubule cells contain 1-alpha-hydroxylase, converting inactive 25-hydroxyvitamin D into active calcitriol, essential for intestinal calcium absorption; this is why CKD causes renal osteodystrophy.', 'Pre-Council', '🎓', true),
(6593, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which mechanism helps maintain glomerular filtration pressure when renal perfusion falls, mediated by angiotensin II?', '["Dilation of the efferent arteriole", "Dilation of both arterioles equally", "Constriction of the efferent arteriole", "Constriction of the afferent arteriole"]'::jsonb, 2, 'Angiotensin II preferentially constricts the efferent arteriole, raising intraglomerular pressure and helping preserve GFR during hypoperfusion; this is why ACE inhibitors/ARBs can precipitate AKI in volume depletion or renal artery stenosis.', 'Pre-Council', '🎓', true),
(6594, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Renal autoregulation maintains a relatively constant glomerular filtration rate across which approximate range of mean arterial pressure?', '["60-80 mmHg", "40-60 mmHg", "180-220 mmHg", "80-180 mmHg"]'::jsonb, 3, 'Through myogenic and tubuloglomerular feedback mechanisms, renal blood flow and GFR remain relatively stable across a MAP range of roughly 80-180 mmHg; below this, renal perfusion falls sharply.', 'Pre-Council', '🎓', true),
(6595, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which statement correctly differentiates the renal cortex from the renal medulla?', '["The cortex has no blood supply while the medulla is highly vascular", "The cortex contains glomeruli and convoluted tubules while the medulla contains the loops of Henle and collecting ducts", "The cortex contains renal pyramids while the medulla contains glomeruli", "The medulla is the outer layer and the cortex is the inner layer"]'::jsonb, 1, 'The renal cortex houses the glomeruli and convoluted tubules, while the medulla, arranged into pyramids, contains the loops of Henle and collecting ducts.', 'Pre-Council', '🎓', true),
(6596, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following best describes the process of tubular secretion in the nephron?', '["Filtration of plasma proteins into the tubule", "Active or passive movement of substances such as potassium, hydrogen ions, and drugs from peritubular capillaries into the tubular fluid", "Movement of filtrate from Bowman''s capsule into the tubule", "Reabsorption of glucose and amino acids into the bloodstream"]'::jsonb, 1, 'Tubular secretion moves substances such as potassium, hydrogen ions, ammonia, and many drugs from peritubular blood into the tubular lumen, complementing filtration and reabsorption.', 'Pre-Council', '🎓', true),
(6597, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A normal adult glomerular filtration rate (GFR) is approximately:', '["10-20 mL/min", "150-180 mL/min", "90-120 mL/min", "40-60 mL/min"]'::jsonb, 2, 'Normal GFR in a healthy young adult is approximately 90-120 mL/min/1.73m2; values below 60 for three or more months define chronic kidney disease.', 'Pre-Council', '🎓', true),
(6598, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with severe hemorrhage and hypotension develops oliguria and rising creatinine. This mechanism of acute kidney injury is best classified as:', '["Nephrotoxic", "Postrenal", "Prerenal", "Intrarenal"]'::jsonb, 2, 'Hypovolemia and hypotension reduce renal perfusion without direct parenchymal damage initially, producing prerenal azotemia, which is reversible if perfusion is restored promptly.', 'Pre-Council', '🎓', true),
(6599, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following is the most common intrinsic (intrarenal) cause of acute kidney injury in critically ill patients?', '["Bladder outlet obstruction", "Renal artery stenosis", "Nephrolithiasis", "Acute tubular necrosis"]'::jsonb, 3, 'Acute tubular necrosis, resulting from prolonged ischemia or nephrotoxin exposure, is the most common intrarenal cause of AKI in critically ill patients.', 'Pre-Council', '🎓', true),
(6600, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A 68-year-old man with benign prostatic hyperplasia presents with anuria and a palpably distended bladder. This is most consistent with which category of AKI?', '["Prerenal", "Intrarenal", "Functional", "Postrenal"]'::jsonb, 3, 'Bladder outlet obstruction from BPH causes back-pressure on the kidneys and postrenal AKI; bladder decompression via catheterization often reverses it promptly.', 'Pre-Council', '🎓', true),
(6601, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which combination of medications places a critically ill patient at greatest risk of prerenal AKI due to loss of compensatory glomerular autoregulation?', '["ACE inhibitors and NSAIDs", "Calcium channel blockers and insulin", "Proton pump inhibitors and antihistamines", "Beta blockers and statins"]'::jsonb, 0, 'ACE inhibitors block efferent arteriolar constriction while NSAIDs block afferent arteriolar dilation; combined, they abolish the kidney''s ability to maintain GFR during hypoperfusion, precipitating AKI.', 'Pre-Council', '🎓', true),
(6602, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Rhabdomyolysis causes acute kidney injury primarily through which mechanism?', '["Direct tubular obstruction and toxicity from myoglobin", "Ureteral obstruction by muscle debris", "Immune complex deposition in the glomerulus", "Renal vein thrombosis"]'::jsonb, 0, 'Myoglobin released from damaged muscle is filtered by the glomerulus and precipitates in the renal tubules, causing direct tubular toxicity and obstruction, worsened by acidic urine and volume depletion.', 'Pre-Council', '🎓', true),
(6603, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which finding is most suggestive of contrast-induced nephropathy after coronary angiography?', '["Hyperkalemia occurring within minutes of injection", "Gross hematuria developing after two weeks", "Immediate anuria during the procedure", "Rise in serum creatinine within 24-72 hours of contrast exposure"]'::jsonb, 3, 'Contrast-induced nephropathy typically presents as a rise in serum creatinine within 24-72 hours after contrast administration, peaking around day 3-5, due to direct tubular toxicity and renal vasoconstriction.', 'Pre-Council', '🎓', true),
(6604, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing intervention is most effective in preventing contrast-induced nephropathy in an at-risk patient before a CT scan with IV contrast?', '["Administering prophylactic antibiotics", "Withholding all oral fluids for 12 hours before the scan", "Administering a loop diuretic prior to the scan", "Ensuring adequate IV isotonic fluid hydration before and after the procedure"]'::jsonb, 3, 'Adequate periprocedural hydration with isotonic IV fluids is the most consistently effective measure to reduce the risk of contrast-induced nephropathy in at-risk patients.', 'Pre-Council', '🎓', true),
(6605, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which class of antibiotics is well known for nephrotoxic potential requiring renal dose adjustment and trough level monitoring in ICU patients?', '["Penicillins", "First-generation cephalosporins", "Aminoglycosides", "Macrolides"]'::jsonb, 2, 'Aminoglycosides such as gentamicin accumulate in proximal tubular cells and can cause dose-related acute tubular necrosis; trough levels and renal function must be monitored closely.', 'Pre-Council', '🎓', true),
(6606, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient in septic shock develops AKI despite adequate fluid resuscitation and a normal blood pressure. The primary mechanism is best explained by:', '["Postrenal obstruction from bacterial casts", "Osmotic diuresis from hyperglycemia", "Inflammatory mediator-induced microvascular dysfunction and direct tubular injury", "Pure prerenal hypoperfusion only"]'::jsonb, 2, 'Sepsis-associated AKI results from microcirculatory dysfunction, inflammatory cytokine injury, and altered renal autoregulation rather than hypoperfusion alone, explaining why it can occur even with normalized blood pressure.', 'Pre-Council', '🎓', true),
(6607, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Using the RIFLE classification system for AKI, the ''Injury'' stage is generally defined by which change from baseline?', '["Serum creatinine increased 1.5 times baseline", "Serum creatinine increased 2 times baseline, or GFR decreased by 50%", "Serum creatinine increased 3 times baseline", "Complete loss of kidney function for more than 4 weeks"]'::jsonb, 1, 'In RIFLE, ''Risk'' equals 1.5x creatinine, ''Injury'' equals 2x creatinine or a 50% GFR fall, and ''Failure'' equals 3x creatinine or a 75% GFR fall; RIFLE stands for Risk, Injury, Failure, Loss, End-stage.', 'Pre-Council', '🎓', true),
(6608, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'According to KDIGO criteria, which urine output finding over 6 hours meets the definition of Stage 1 acute kidney injury?', '["Urine output greater than 2 mL/kg/hr", "Urine output less than 0.5 mL/kg/hr", "Urine output less than 0.3 mL/kg/hr for 24 hours", "Anuria"]'::jsonb, 1, 'KDIGO Stage 1 AKI includes urine output less than 0.5 mL/kg/hr for 6-12 hours, in addition to a creatinine rise of 0.3 mg/dL or 1.5-1.9 times baseline; more severe oliguria criteria define higher stages.', 'Pre-Council', '🎓', true),
(6609, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following is a modifiable risk factor for progression of chronic kidney disease that the critical care nurse should specifically address in patient education?', '["Genetic predisposition", "Sex", "Poor glycemic control in diabetes", "Age"]'::jsonb, 2, 'Tight glycemic control slows progression of diabetic nephropathy, the leading cause of CKD; age, genetics, and sex are non-modifiable risk factors.', 'Pre-Council', '🎓', true),
(6610, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The two leading causes of chronic kidney disease and end-stage renal disease in adults are:', '["Lupus nephritis and amyloidosis", "Diabetes mellitus and hypertension", "Nephrolithiasis and pyelonephritis", "Polycystic kidney disease and glomerulonephritis"]'::jsonb, 1, 'Diabetes mellitus and hypertension together account for the majority of new ESRD cases worldwide due to progressive glomerular and vascular damage.', 'Pre-Council', '🎓', true),
(6611, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient in the oliguric phase of acute tubular necrosis is at greatest immediate risk for which life-threatening complication?', '["Metabolic alkalosis", "Hyperkalemia", "Hypokalemia", "Hypernatremia"]'::jsonb, 1, 'During the oliguric phase, the kidneys cannot excrete potassium, placing the patient at high risk for life-threatening hyperkalemia and cardiac dysrhythmias.', 'Pre-Council', '🎓', true),
(6612, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The diuretic phase of acute tubular necrosis recovery places the patient at greatest risk for which complication if fluid and electrolyte losses are not carefully replaced?', '["Volume depletion, hypokalemia, and hyponatremia", "Fluid overload and hyperkalemia", "Uremic encephalopathy", "Metabolic acidosis and hypercalcemia"]'::jsonb, 0, 'As tubules recover but cannot yet concentrate urine effectively, patients can lose large volumes of dilute urine, risking dehydration, hypokalemia, and hyponatremia if not carefully monitored and replaced.', 'Pre-Council', '🎓', true),
(6613, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which laboratory pattern is most consistent with prerenal azotemia rather than intrinsic renal failure?', '["FENa greater than 2%", "BUN:creatinine ratio near 10:1 with dilute urine", "Urine sodium greater than 40 mEq/L", "BUN:creatinine ratio greater than 20:1 with concentrated urine"]'::jsonb, 3, 'In prerenal azotemia, the kidney avidly reabsorbs sodium and water, producing a BUN:creatinine ratio greater than 20:1, concentrated urine, low urine sodium, and FENa less than 1%.', 'Pre-Council', '🎓', true),
(6614, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Cardiorenal syndrome in a patient with acute decompensated heart failure is best explained by which pathophysiology?', '["Autoimmune injury to the glomerular basement membrane", "Direct nephrotoxicity from cardiac medications", "Ureteral compression by an enlarged heart", "Reduced cardiac output and venous congestion impairing renal perfusion and function"]'::jsonb, 3, 'Cardiorenal syndrome results from reduced forward cardiac output combined with elevated central venous pressure causing renal venous congestion, both of which impair glomerular filtration.', 'Pre-Council', '🎓', true),
(6615, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with long-standing hypertension and diabetes has an eGFR of 25 mL/min/1.73m2 sustained for over three months. This is classified as:', '["Nephrotic syndrome", "Acute kidney injury", "Chronic kidney disease stage 2", "Chronic kidney disease stage 4"]'::jsonb, 3, 'An eGFR of 15-29 mL/min/1.73m2 sustained for more than three months meets criteria for CKD stage 4, severely decreased kidney function.', 'Pre-Council', '🎓', true),
(6616, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following best distinguishes acute kidney injury from chronic kidney disease on renal ultrasound?', '["Ultrasound cannot differentiate acute from chronic renal disease", "Chronic kidney disease typically shows small, echogenic kidneys, while kidney size is often normal or enlarged in AKI", "Both conditions always show identical kidney size", "AKI typically shows small, shrunken, echogenic kidneys, while CKD shows normal or enlarged kidneys"]'::jsonb, 1, 'Chronically diseased kidneys are usually small and echogenic due to fibrosis, whereas kidneys in acute injury are typically normal-sized or swollen from edema, an important clue when duration of dysfunction is unclear.', 'Pre-Council', '🎓', true),
(6617, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient receiving vancomycin and an aminoglycoside together for severe sepsis is at increased risk for which complication?', '["Synergistic nephrotoxicity", "Hepatotoxicity", "Bone marrow suppression only", "Hypoglycemia"]'::jsonb, 0, 'Vancomycin combined with aminoglycosides has a synergistic nephrotoxic effect, increasing the risk of acute kidney injury; renal function and trough levels should be closely monitored.', 'Pre-Council', '🎓', true),
(6618, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Abdominal compartment syndrome can cause acute kidney injury primarily through which mechanism?', '["Direct puncture of the ureters", "Excess erythropoietin production", "Increased intra-abdominal pressure compressing the renal veins and parenchyma, reducing renal perfusion", "Autoimmune glomerular injury"]'::jsonb, 2, 'Elevated intra-abdominal pressure directly compresses renal vasculature and parenchyma, and reduces cardiac output while increasing renal venous pressure, all of which impair renal perfusion and can precipitate AKI.', 'Pre-Council', '🎓', true),
(6619, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which patient is at highest risk for developing acute kidney injury in the ICU?', '["A 70-year-old with sepsis, baseline CKD, and recent IV contrast exposure", "A 40-year-old post-appendectomy with normal vitals", "A 25-year-old with a mild upper respiratory infection", "A 30-year-old with a simple ankle fracture"]'::jsonb, 0, 'Advanced age, pre-existing CKD, sepsis, and nephrotoxin exposure from contrast are all major, additive risk factors for AKI, making this patient the highest risk among the options.', 'Pre-Council', '🎓', true),
(6620, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which urinary finding is most characteristic of acute tubular necrosis on urine microscopy?', '["White blood cell casts", "Hyaline casts only", "Muddy brown granular casts", "Red blood cell casts"]'::jsonb, 2, 'Muddy brown granular casts, composed of sloughed tubular epithelial cells, are the classic urinary sediment finding in acute tubular necrosis.', 'Pre-Council', '🎓', true),
(6621, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which statement about acute kidney injury progressing to chronic kidney disease or end-stage renal disease is correct?', '["Renal recovery after AKI is always complete regardless of severity", "CKD never results from repeated episodes of AKI", "AKI is always irreversible and requires permanent dialysis", "Some episodes of AKI, especially with pre-existing CKD or severe/prolonged injury, can progress to chronic kidney disease or ESRD"]'::jsonb, 3, 'Even though many AKI episodes resolve, severe, prolonged, or repeated AKI, particularly with underlying CKD, can lead to incomplete recovery and progression toward chronic kidney disease or ESRD.', 'Pre-Council', '🎓', true),
(6622, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with obstructive uropathy from bilateral ureteral stones is treated with nephrostomy tube placement. What immediate postobstructive complication should the nurse monitor for?', '["Post-obstructive diuresis with large fluid and electrolyte losses", "Hypertension crisis only", "Immediate anuria", "Spontaneous resolution of chronic kidney disease"]'::jsonb, 0, 'After relief of urinary tract obstruction, tubules may transiently lose concentrating ability, producing marked post-obstructive diuresis that can cause significant volume and electrolyte depletion if not monitored and replaced.', 'Pre-Council', '🎓', true),
(6623, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following best describes the pathophysiologic hallmark of nephrotic syndrome contributing to renal impairment?', '["Complete anuria from ureteral obstruction", "Isolated tubular potassium wasting", "Massive proteinuria due to glomerular basement membrane damage, leading to hypoalbuminemia and edema", "Gross hematuria from renal vein thrombosis only"]'::jsonb, 2, 'Nephrotic syndrome results from increased glomerular permeability causing heavy proteinuria greater than 3.5 g/day, hypoalbuminemia, edema, and hyperlipidemia, and can contribute to progressive renal impairment.', 'Pre-Council', '🎓', true),
(6624, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Serum creatinine is considered a more reliable indicator of renal function than BUN mainly because:', '["BUN is not affected by dehydration", "Creatinine is heavily affected by dietary protein intake", "Creatinine production is relatively constant and less affected by hydration status or diet", "Creatinine is filtered and then completely reabsorbed"]'::jsonb, 2, 'Creatinine is produced at a fairly constant rate from muscle metabolism and is minimally reabsorbed, making it a more specific marker of GFR, whereas BUN is influenced by protein intake, hydration, catabolism, and GI bleeding.', 'Pre-Council', '🎓', true),
(6625, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A normal BUN:creatinine ratio is approximately:', '["5:1", "30:1 to 40:1", "50:1", "10:1 to 20:1"]'::jsonb, 3, 'The normal BUN:creatinine ratio is roughly 10:1 to 20:1; ratios above 20:1 suggest a prerenal cause such as dehydration or GI bleeding.', 'Pre-Council', '🎓', true),
(6626, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The Cockcroft-Gault equation and MDRD/CKD-EPI formulas are used clinically to estimate:', '["Kidney function, expressed as creatinine clearance or GFR", "Urine osmolality", "Bladder capacity", "Serum electrolyte concentration"]'::jsonb, 0, 'These formulas estimate creatinine clearance or GFR using variables such as serum creatinine, age, sex, and weight, providing a practical bedside measure of kidney function without a timed urine collection.', 'Pre-Council', '🎓', true),
(6627, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Fractional excretion of sodium (FENa) less than 1% is most consistent with which type of acute kidney injury?', '["Postrenal obstruction", "Acute tubular necrosis", "Glomerulonephritis with heavy proteinuria", "Prerenal azotemia"]'::jsonb, 3, 'In prerenal AKI, intact tubules avidly reabsorb sodium to conserve volume, resulting in a FENa less than 1%; in ATN, damaged tubules lose this ability, so FENa is typically greater than 2%.', 'Pre-Council', '🎓', true),
(6628, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A 24-hour urine collection for creatinine clearance is started incorrectly if the nurse:', '["Records the exact start and end times of collection", "Discards the first voided specimen at the start time and collects all urine thereafter for 24 hours", "Includes the first morning void from the day before starting the collection", "Keeps the specimen refrigerated or on ice throughout the collection"]'::jsonb, 2, 'A 24-hour collection should begin by discarding the first void and timing from that point; including urine voided before the timed start introduces error and invalidates the collection.', 'Pre-Council', '🎓', true),
(6629, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which urine specific gravity finding is most consistent with the kidneys'' normal ability to concentrate urine appropriately in a dehydrated patient?', '["1.001", "1.025-1.030", "1.000", "1.010"]'::jsonb, 1, 'A higher specific gravity, approximately 1.025-1.030, indicates the kidneys are appropriately concentrating urine in response to volume depletion; a fixed value near 1.010, or isosthenuria, suggests impaired concentrating ability.', 'Pre-Council', '🎓', true),
(6630, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient''s eGFR is persistently 45 mL/min/1.73m2 for over three months with no other abnormality. According to CKD staging, this corresponds to:', '["Stage 5", "Stage 2", "Stage 1", "Stage 3"]'::jsonb, 3, 'CKD stage 3 is defined as an eGFR of 30-59 mL/min/1.73m2 sustained for more than three months, representing moderately decreased kidney function.', 'Pre-Council', '🎓', true),
(6631, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which serum marker is increasingly used as an earlier and more specific indicator of reduced GFR than creatinine, particularly in patients with reduced muscle mass?', '["Troponin", "C-reactive protein", "Cystatin C", "Alkaline phosphatase"]'::jsonb, 2, 'Cystatin C is produced at a constant rate by nucleated cells and is less affected by muscle mass, age, or sex than creatinine, offering a more sensitive early marker of declining GFR.', 'Pre-Council', '🎓', true),
(6632, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Presence of red blood cell casts in the urine sediment is most specific for which condition?', '["Urinary tract infection", "Dehydration", "Glomerulonephritis", "Benign prostatic hyperplasia"]'::jsonb, 2, 'Red blood cell casts form when red blood cells pass through damaged glomeruli and become trapped in the tubule lumen, making them a specific marker of glomerular bleeding, as in glomerulonephritis.', 'Pre-Council', '🎓', true),
(6633, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Microalbuminuria in a diabetic patient is clinically significant because it:', '["Indicates definite bladder cancer", "Is an early marker of diabetic nephropathy and cardiovascular risk", "Always indicates urinary tract infection", "Has no prognostic significance"]'::jsonb, 1, 'Microalbuminuria, 30-300 mg/day, is one of the earliest detectable signs of diabetic glomerular damage and is also an independent marker of increased cardiovascular risk.', 'Pre-Council', '🎓', true),
(6634, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which imaging study is preferred as a first-line, noninvasive test to evaluate for hydronephrosis or urinary tract obstruction?', '["Renal ultrasound", "Positron emission tomography", "Renal biopsy", "Intravenous pyelography with contrast"]'::jsonb, 0, 'Renal ultrasound is safe, radiation-free, and highly sensitive for detecting hydronephrosis and structural abnormalities, making it the preferred initial imaging study for suspected obstruction.', 'Pre-Council', '🎓', true),
(6635, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A renal biopsy is contraindicated or requires extreme caution in a patient with which condition?', '["Well-controlled hypertension", "Uncontrolled bleeding disorder or severe uncorrected coagulopathy", "Mild proteinuria", "Stable chronic kidney disease stage 2"]'::jsonb, 1, 'Because renal biopsy carries a bleeding risk from the highly vascular kidney, uncorrected coagulopathy or bleeding disorders are major contraindications requiring correction before the procedure if at all possible.', 'Pre-Council', '🎓', true),
(6636, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Serum urea (BUN) can be falsely elevated independent of true renal function by which of the following?', '["Overhydration", "Liver failure", "Upper gastrointestinal bleeding", "Low protein diet"]'::jsonb, 2, 'Blood in the GI tract is digested and absorbed as protein, increasing hepatic urea production, which can raise BUN disproportionately to actual renal function, a classic cause of an elevated BUN:creatinine ratio.', 'Pre-Council', '🎓', true),
(6637, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which urine osmolality finding would be expected in a patient with acute tubular necrosis who has lost the ability to concentrate urine?', '["Urine osmolality much greater than serum osmolality", "Urine osmolality inversely related to specific gravity", "Urine osmolality of zero", "Urine osmolality close to or equal to serum osmolality, or isosthenuric"]'::jsonb, 3, 'In ATN, damaged tubules cannot concentrate or dilute urine, so urine osmolality approximates serum osmolality around 300 mOsm/kg, a pattern known as isosthenuria.', 'Pre-Council', '🎓', true),
(6638, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse notes a patient''s serum creatinine has risen from 0.9 mg/dL to 1.8 mg/dL over 36 hours, with urine output of 0.4 mL/kg/hr for the past 8 hours. This most appropriately triggers:', '["Discontinuation of all IV fluids", "No action, since values remain within a wide ''normal'' laboratory range", "Immediate recognition and reporting of acute kidney injury per KDIGO criteria", "A repeat test in one week"]'::jsonb, 2, 'A doubling of serum creatinine and oliguria under 0.5 mL/kg/hr for more than 6 hours meet KDIGO Stage 2 criteria for AKI and require prompt recognition, further evaluation, and intervention.', 'Pre-Council', '🎓', true),
(6639, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The primary principle by which hemodialysis removes solutes such as urea and creatinine from the blood is:', '["Active transport across the dialyzer membrane", "Diffusion of solutes down a concentration gradient across a semipermeable membrane", "Filtration by centrifugal force", "Osmosis of water only"]'::jsonb, 1, 'Hemodialysis relies primarily on diffusion, in which solutes move from an area of higher concentration in blood to lower concentration in dialysate across the semipermeable dialyzer membrane.', 'Pre-Council', '🎓', true),
(6640, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In hemodialysis, removal of excess fluid from the blood is achieved primarily through:', '["Reverse osmosis of dialysate", "Ultrafiltration, driven by a hydrostatic/osmotic pressure gradient across the membrane", "Diffusion", "Active pumping of plasma proteins"]'::jsonb, 1, 'Ultrafiltration removes plasma water by creating a pressure gradient across the dialyzer membrane, allowing precise removal of excess fluid to reach the patient''s target dry weight.', 'Pre-Council', '🎓', true),
(6641, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which mnemonic is commonly used to remember indications for urgent or emergent dialysis?', '["SEPSIS", "MONA", "AEIOU, standing for acidosis, electrolyte imbalance, ingestion/intoxication, overload, uremia", "FAST"]'::jsonb, 2, 'AEIOU summarizes classic emergent indications for dialysis: refractory metabolic Acidosis, severe Electrolyte abnormalities such as hyperkalemia, certain Ingestions/toxins, fluid Overload unresponsive to diuretics, and symptomatic Uremia.', 'Pre-Council', '🎓', true),
(6642, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which vascular access is generally preferred for long-term hemodialysis due to lower infection and thrombosis rates compared with other options?', '["Tunneled central venous catheter", "Temporary femoral catheter", "Arteriovenous fistula", "Peripheral IV line"]'::jsonb, 2, 'An arteriovenous fistula, created by surgically connecting an artery and vein, has the lowest rates of infection and thrombosis and the best long-term patency of all access types.', 'Pre-Council', '🎓', true),
(6643, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When assessing a patient''s arteriovenous fistula, the nurse palpates for a ''thrill'' and auscultates for a ''bruit.'' Absence of these findings suggests:', '["Excessive blood flow through the fistula", "The fistula is ready for first use", "Possible thrombosis or occlusion of the fistula", "Normal fistula function"]'::jsonb, 2, 'A palpable thrill and audible bruit indicate turbulent flow through a patent fistula; their absence is an emergency finding suggesting thrombosis and requires immediate reporting.', 'Pre-Council', '🎓', true),
(6644, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Blood pressure measurements, venipuncture, and IV insertions should be avoided in the arm with an arteriovenous fistula primarily to prevent:', '["Fistula compression, thrombosis, or damage that could compromise the access", "Increased risk of arrhythmia", "Falsely low blood pressure readings", "Patient discomfort only"]'::jsonb, 0, 'Constricting or puncturing the fistula arm risks compressing or damaging the delicate, high-flow access, potentially causing thrombosis and loss of this vital, hard-to-replace vascular lifeline.', 'Pre-Council', '🎓', true),
(6645, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A hemodialysis patient develops sudden hypotension, nausea, headache, and confusion approximately 3 hours into a first dialysis session. This presentation is most consistent with:', '["Anaphylaxis to the dialyzer membrane", "Air embolism", "Dialysis disequilibrium syndrome", "Hyperkalemic cardiac arrest"]'::jsonb, 2, 'Dialysis disequilibrium syndrome occurs when rapid removal of urea from the blood creates an osmotic gradient causing cerebral edema, most common during or after the first few dialysis sessions in patients with very high pre-dialysis BUN.', 'Pre-Council', '🎓', true),
(6646, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which strategy reduces the risk of dialysis disequilibrium syndrome in a patient starting hemodialysis with a very high BUN?', '["Withholding all anticoagulation", "Performing a single long, aggressive session to normalize BUN quickly", "Using shorter, less efficient initial dialysis sessions with a lower blood flow rate to gradually reduce solutes", "Increasing dialysate sodium abruptly"]'::jsonb, 2, 'Gradual, shorter initial sessions with reduced blood flow and solute clearance rates minimize rapid osmotic shifts, reducing the risk of cerebral edema associated with disequilibrium syndrome.', 'Pre-Council', '🎓', true),
(6647, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The most common complication experienced by patients during a routine hemodialysis session is:', '["Pneumothorax", "Intradialytic hypotension", "Anaphylaxis", "Air embolism"]'::jsonb, 1, 'Intradialytic hypotension, related to rapid fluid removal relative to plasma refilling, is the most frequently encountered complication during hemodialysis sessions.', 'Pre-Council', '🎓', true),
(6648, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient becomes acutely hypotensive during hemodialysis. What is the priority nursing intervention?', '["Administer a diuretic", "Place the patient in Trendelenburg position, reduce or stop ultrafiltration, and administer a fluid bolus as ordered", "Immediately discontinue dialysis permanently", "Increase the ultrafiltration rate"]'::jsonb, 1, 'For intradialytic hypotension, the nurse should reduce or stop fluid removal, position the patient to promote venous return, and give a fluid bolus per protocol while continuing to monitor closely.', 'Pre-Council', '🎓', true),
(6649, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Heparin is commonly used during hemodialysis to prevent which complication?', '["Hypotension", "Air embolism", "Clotting of blood within the dialyzer and extracorporeal circuit", "Hemolysis of red blood cells in the circuit"]'::jsonb, 2, 'Because blood contacts foreign extracorporeal surfaces during dialysis, systemic or regional heparin anticoagulation is used to prevent clot formation in the dialyzer and tubing, which would reduce efficiency and risk embolization.', 'Pre-Council', '🎓', true),
(6650, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which patient would require the least amount of, or no, heparin anticoagulation during hemodialysis?', '["A patient with a normal platelet count and coagulation studies", "A patient with a well-functioning arteriovenous fistula", "A patient with no bleeding risk undergoing routine outpatient dialysis", "A patient who is actively bleeding or recently had surgery"]'::jsonb, 3, 'In patients with active bleeding, recent surgery, or high bleeding risk, dialysis is often performed with minimal or no heparin, or regional citrate anticoagulation, to avoid worsening hemorrhage.', 'Pre-Council', '🎓', true),
(6651, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', '''Steal syndrome'' following creation of an arteriovenous fistula refers to:', '["Theft of dialysis supplies", "Distal limb ischemia caused by blood being diverted away from the hand into the low-resistance fistula", "Infection of the fistula site", "Excessive clot formation within the fistula"]'::jsonb, 1, 'Steal syndrome occurs when the fistula diverts a significant portion of arterial blood flow away from the distal extremity, causing ischemic pain, coolness, numbness, or weakness in the hand distal to the access.', 'Pre-Council', '🎓', true),
(6652, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A dialysis patient''s target ''dry weight'' refers to:', '["The patient''s weight before starting dialysis treatment", "The patient''s ideal body weight based on BMI charts", "The maximum weight gain allowed between sessions", "The lowest weight a patient can tolerate after dialysis without symptoms of hypotension or hypovolemia, once excess fluid has been removed"]'::jsonb, 3, 'Dry weight is the estimated post-dialysis weight at which the patient is euvolemic, guiding the ultrafiltration goal for each session; it is periodically reassessed.', 'Pre-Council', '🎓', true),
(6653, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Uremic pericarditis, a potential complication of untreated or inadequately dialyzed end-stage renal disease, is classically treated by:', '["High-dose diuretics", "Fluid restriction only, with no change to dialysis", "Beta-blockers alone", "Intensified or urgent dialysis"]'::jsonb, 3, 'Uremic pericarditis is an indication for intensified or emergent dialysis, since it results from accumulated uremic toxins; NSAIDs are typically avoided due to increased risk of hemorrhagic pericardial effusion in these often-anticoagulated patients.', 'Pre-Council', '🎓', true),
(6654, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following best describes the composition principle of standard hemodialysate related to potassium removal?', '["Dialysate potassium concentration is typically lower than plasma potassium, creating a gradient that pulls potassium out of the blood", "Dialysate potassium concentration is always higher than plasma potassium to add potassium", "Dialysate contains no electrolytes at all", "Potassium removal occurs only through ultrafiltration, not diffusion"]'::jsonb, 0, 'Dialysate potassium is set lower than the patient''s serum potassium, commonly 1-3 mEq/L, to establish a diffusion gradient that removes excess potassium from the blood during treatment.', 'Pre-Council', '🎓', true),
(6655, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A tunneled central venous catheter used for hemodialysis access carries the highest risk of which complication compared with an AV fistula?', '["Catheter-related bloodstream infection", "High-output cardiac failure", "Aneurysm formation", "Steal syndrome"]'::jsonb, 0, 'Central venous catheters have the highest infection and central line-associated bloodstream infection risk among dialysis access types and are generally used only when fistula or graft placement is not feasible or as a bridge.', 'Pre-Council', '🎓', true),
(6656, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Peritoneal dialysis differs from hemodialysis in that it uses which structure as the semipermeable membrane for solute and fluid exchange?', '["The patient''s own peritoneal membrane", "The dialyzer''s synthetic membrane", "The glomerular basement membrane", "The pleural membrane"]'::jsonb, 0, 'In peritoneal dialysis, dialysate is instilled into the peritoneal cavity, and the patient''s own richly vascularized peritoneal membrane serves as the semipermeable surface for diffusion and osmosis-driven exchange.', 'Pre-Council', '🎓', true),
(6657, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A hemodialysis patient reports muscle cramps during the latter part of a dialysis session. This is most often related to:', '["Excessive potassium removal", "Hyperglycemia", "Excess dialysate temperature", "Rapid fluid/electrolyte shifts and relative hypovolemia from aggressive ultrafiltration"]'::jsonb, 3, 'Intradialytic muscle cramps are commonly linked to rapid fluid removal, hypovolemia, and electrolyte shifts, particularly sodium and calcium; slowing the ultrafiltration rate and adjusting dialysate sodium often help.', 'Pre-Council', '🎓', true),
(6658, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following is an absolute priority assessment the nurse must perform before initiating a scheduled hemodialysis treatment?', '["Administer prophylactic antibiotics", "Withhold all antihypertensive medications regardless of blood pressure", "Insert a new peripheral IV in the fistula arm", "Assess and document vascular access patency, current weight compared with dry weight, vital signs, and relevant labs such as potassium"]'::jsonb, 3, 'Pre-dialysis assessment must include vascular access patency, weight comparison to determine ultrafiltration goals, vital signs, and relevant recent labs to safely individualize the treatment plan.', 'Pre-Council', '🎓', true),
(6659, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following is a primary indication for choosing continuous renal replacement therapy (CRRT) over intermittent hemodialysis in a critically ill patient?', '["CRRT is always cheaper and easier to staff", "The patient is hemodynamically stable and requires only outpatient maintenance dialysis", "The patient is hemodynamically unstable and would not tolerate the rapid fluid/solute shifts of intermittent hemodialysis", "CRRT requires no anticoagulation"]'::jsonb, 2, 'CRRT''s slower, continuous solute and fluid removal is far better tolerated hemodynamically than intermittent hemodialysis, making it the preferred modality for hemodynamically unstable ICU patients with AKI.', 'Pre-Council', '🎓', true),
(6660, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In CVVH, continuous venovenous hemofiltration, solute removal occurs primarily through which mechanism?', '["Active transport", "Osmosis alone", "Diffusion", "Convection, driven by hydrostatic pressure pushing plasma water and dissolved solutes across the filter membrane"]'::jsonb, 3, 'CVVH uses convective clearance, in which a pressure gradient drives plasma water with dissolved solutes across the filter membrane; replacement fluid is then given to maintain volume balance, unlike CVVHD which relies on diffusion.', 'Pre-Council', '🎓', true),
(6661, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In CVVHD, continuous venovenous hemodialysis, solute clearance is achieved mainly by:', '["Osmotic ultrafiltration only", "Diffusion, using a countercurrent dialysate flow across the filter membrane", "Centrifugal separation", "Convection only"]'::jsonb, 1, 'CVVHD uses a dialysate solution flowing countercurrent to blood across the hemofilter, clearing solutes primarily by diffusion, similar in principle to conventional hemodialysis but delivered continuously.', 'Pre-Council', '🎓', true),
(6662, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'CVVHDF, continuous venovenous hemodiafiltration, combines which two clearance mechanisms?', '["Ultrafiltration and reabsorption only", "Osmosis and active transport", "Filtration and centrifugation", "Diffusion and convection"]'::jsonb, 3, 'CVVHDF uses both dialysate flow for diffusion and convective ultrafiltration with replacement fluid, maximizing clearance of both small and middle-molecular-weight solutes.', 'Pre-Council', '🎓', true),
(6663, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The most common cause of premature clotting or loss of the CRRT filter and circuit is:', '["Inadequate anticoagulation and/or low blood flow rates through the circuit", "Overuse of citrate", "Too high a dialysate temperature", "Excessive anticoagulation"]'::jsonb, 0, 'Filter clotting most often results from insufficient anticoagulation, low blood flow, kinks or access issues, or circuit interruptions; maintaining adequate blood flow and appropriate anticoagulation helps prolong filter life.', 'Pre-Council', '🎓', true),
(6664, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which is a classic sign of impending CRRT filter clotting that the nurse should recognize during circuit monitoring?', '["Progressively rising transmembrane/filter pressure and darkening of blood in the filter", "Increased ultrafiltrate clarity", "Decreasing transmembrane pressure trend", "Falling venous pressure"]'::jsonb, 0, 'A rising transmembrane pressure along with visibly dark blood or clot streaks in the filter and drip chambers signals impending clotting and filter failure, requiring prompt assessment and often circuit change.', 'Pre-Council', '🎓', true),
(6665, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Citrate is often used as regional anticoagulation for CRRT circuits because it:', '["Has no effect on coagulation", "Chelates ionized calcium within the extracorporeal circuit, preventing clotting there while calcium is reinfused systemically to the patient", "Is metabolized entirely by the kidneys, avoiding any systemic effects", "Provides systemic anticoagulation with high bleeding risk"]'::jsonb, 1, 'Citrate binds ionized calcium in the extracorporeal circuit to prevent clotting; calcium is then reinfused into the patient systemically, largely limiting anticoagulant effect to the circuit and reducing systemic bleeding risk compared with heparin.', 'Pre-Council', '🎓', true),
(6666, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient on CRRT with citrate anticoagulation develops metabolic alkalosis along with a widening gap between total calcium and ionized calcium. This suggests:', '["Adequate citrate clearance and normal liver function", "Hypokalemia", "Citrate accumulation or toxicity, often due to impaired hepatic metabolism of citrate", "Filter clotting"]'::jsonb, 2, 'Citrate is normally metabolized to bicarbonate by the liver; in citrate toxicity, often from liver dysfunction or citrate overdose, citrate accumulates, chelating more calcium and generating excess bicarbonate, causing metabolic alkalosis.', 'Pre-Council', '🎓', true),
(6667, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which electrolyte disturbance is a well-recognized complication of CRRT due to continuous convective/diffusive clearance, particularly with prolonged therapy?', '["Hypophosphatemia, hypokalemia, and hypomagnesemia from ongoing solute clearance", "Hypernatremia exclusively", "Hyperkalemia and hyperphosphatemia only", "Hypercalcemia exclusively"]'::jsonb, 0, 'CRRT continuously clears small solutes including phosphate, potassium, and magnesium; without adequate replacement and monitoring, patients frequently develop hypophosphatemia, hypokalemia, and hypomagnesemia during prolonged therapy.', 'Pre-Council', '🎓', true),
(6668, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Hypothermia is a common complication of CRRT because:', '["CRRT machines actively cool the blood intentionally at all times", "Patients are typically febrile at baseline", "Extracorporeal blood is exposed to room-temperature tubing, filters, and replacement fluids, causing heat loss", "The dialysate is always heated above body temperature"]'::jsonb, 2, 'As blood circulates through extracorporeal tubing and filters and mixes with room-temperature replacement/dialysate fluids, significant heat loss occurs; most modern CRRT machines include blood-warming devices to mitigate this.', 'Pre-Council', '🎓', true),
(6669, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A key nursing implication of CRRT-induced mild hypothermia in critically ill patients is that it may:', '["Improve coagulation profile permanently", "Worsen hemodynamic stability", "Mask fever and delay recognition of infection, requiring vigilant monitoring beyond temperature alone", "Have no clinical relevance"]'::jsonb, 2, 'While mild hypothermia can offer modest hemodynamic benefit via vasoconstriction, it can also blunt febrile responses to infection, so the nurse must monitor other signs of sepsis such as hemodynamics, white count, and lactate rather than relying on temperature alone.', 'Pre-Council', '🎓', true),
(6670, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following is a potentially fatal mechanical complication of the CRRT extracorporeal circuit that requires the nurse to check all connections and use air detectors?', '["Hyperglycemia", "Uremic frost", "Peritonitis", "Air embolism"]'::jsonb, 3, 'Disconnection or improper priming of the circuit can introduce air into the bloodstream, risking air embolism; CRRT machines have air detectors and alarms, and the nurse must ensure all connections are secure.', 'Pre-Council', '🎓', true),
(6671, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Significant hypotension during CVVH initiation is most often related to:', '["Excessive potassium supplementation", "The blood volume held in the extracorporeal circuit combined with the rate of fluid removal relative to plasma refill", "Excess dialysate glucose", "Hyperthermia"]'::jsonb, 1, 'At initiation, priming and circulating blood through the extracorporeal circuit removes some circulating volume, and if fluid removal exceeds plasma refill rate, hypotension can result; slow initiation and careful fluid balance help prevent this.', 'Pre-Council', '🎓', true),
(6672, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Nutritional considerations for a patient on CRRT include which of the following?', '["No need for additional protein since CRRT conserves amino acids", "Restriction of all protein intake", "Increased protein needs due to significant amino acid and micronutrient losses across the filter", "Complete avoidance of enteral nutrition"]'::jsonb, 2, 'CRRT clears amino acids, water-soluble vitamins, and trace elements continuously, increasing protein and micronutrient requirements, often with higher protein targets than for standard ICU patients.', 'Pre-Council', '🎓', true),
(6673, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When titrating CRRT replacement fluid and dialysate flow rates for a patient with severe metabolic acidosis, the priority nursing consideration is:', '["Using a bicarbonate- or lactate-buffered replacement fluid to help correct the acidosis gradually", "Using only solutions with no buffer", "Rapidly correcting the entire acid-base deficit within the first hour", "Avoiding any buffer to prevent alkalosis"]'::jsonb, 0, 'Bicarbonate- or lactate-buffered CRRT replacement/dialysate fluids help gradually correct metabolic acidosis as part of therapy; correction should occur gradually, and lactate-buffered solutions require adequate hepatic function to be metabolized.', 'Pre-Council', '🎓', true),
(6674, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which vascular access complication is specific to CRRT catheter placement, such as an internal jugular or femoral dialysis catheter, that the nurse must monitor for post-insertion?', '["Aneurysm of a peripheral vein", "Steal syndrome", "Pneumothorax with internal jugular or subclavian placement, or catheter malposition/malfunction", "Fistula thrombosis"]'::jsonb, 2, 'Central venous catheter placement for CRRT carries procedural risks including pneumothorax, hemothorax, arterial puncture, and catheter malposition, which the nurse should monitor for via post-procedure chest x-ray and clinical assessment.', 'Pre-Council', '🎓', true),
(6675, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A nurse notices the CRRT machine''s effluent bag is filling much faster than programmed, and the patient is becoming hypotensive. The priority action is:', '["Stop or pause therapy, verify machine settings and fluid balance, and notify the provider promptly", "Disconnect the patient from the circuit permanently without notifying the provider", "Continue the therapy unchanged and reassess in one hour", "Increase the blood flow rate"]'::jsonb, 0, 'Unexpected excessive fluid removal is a critical safety event that can cause severe hypovolemia; the nurse should pause therapy, verify programmed settings and fluid balance, assess the patient, and notify the provider immediately.', 'Pre-Council', '🎓', true),
(6676, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Compared with intermittent hemodialysis, one key disadvantage of CRRT is:', '["Inability to remove any fluid", "Greater hemodynamic instability", "Slower, less efficient hourly solute clearance requiring nearly continuous therapy", "Higher risk of dialysis disequilibrium syndrome"]'::jsonb, 2, 'CRRT clears solutes more slowly per hour than intermittent hemodialysis, requiring nearly continuous, 24-hour therapy to achieve comparable total clearance; its advantage is the gentler, more hemodynamically tolerable rate of removal.', 'Pre-Council', '🎓', true),
(6677, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse caring for a patient on CRRT should recognize that repeated filter clotting and circuit changes over time can contribute to:', '["Hypercalcemia", "Anemia requiring monitoring of hemoglobin/hematocrit and possible transfusion", "Hyperkalemia", "Hypernatremia"]'::jsonb, 1, 'Repeated filter clotting and circuit changes can result in cumulative blood loss within the extracorporeal system, contributing to anemia in CRRT patients, who should have hemoglobin and hematocrit monitored regularly.', 'Pre-Council', '🎓', true),
(6678, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which combination best represents the priority ongoing nursing assessments specific to a patient receiving CRRT?', '["Daily weight only, once per shift", "Monthly electrolyte panels", "Vital signs only at the start and end of therapy", "Hourly fluid balance, ins and outs and net ultrafiltration, circuit pressures, electrolytes, temperature, and access site"]'::jsonb, 3, 'CRRT requires intensive, frequently hourly, monitoring of fluid balance, circuit integrity and pressures, electrolytes, coagulation status, temperature, and vascular access to detect complications early given the continuous nature of therapy.', 'Pre-Council', '🎓', true),
(6679, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Therapeutic plasma exchange, or plasmapheresis, works by:', '["Filtering and removing the patient''s plasma, which contains pathologic antibodies or proteins, and replacing it with donor plasma or albumin", "Removing only white blood cells", "Adding concentrated red blood cells to the circulation", "Diffusing small solutes only, similar to hemodialysis"]'::jsonb, 0, 'Plasmapheresis separates and removes plasma containing pathogenic autoantibodies, immune complexes, or toxins, replacing it with fresh frozen plasma or albumin solution, and is used in conditions like Guillain-Barre syndrome, myasthenia gravis, and TTP.', 'Pre-Council', '🎓', true),
(6680, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which condition is a well-established indication for therapeutic plasma exchange?', '["Uncomplicated urinary tract infection", "Thrombotic thrombocytopenic purpura (TTP)", "Mild hyperkalemia", "Simple dehydration"]'::jsonb, 1, 'TTP is a classic indication for urgent plasma exchange, which removes large von Willebrand factor multimers and autoantibodies against ADAMTS13 while replacing the deficient enzyme via donor plasma.', 'Pre-Council', '🎓', true),
(6681, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A common electrolyte complication of plasmapheresis, related to the citrate anticoagulant used in the extracorporeal circuit, is:', '["Hypocalcemia, or citrate toxicity, with symptoms such as perioral tingling and muscle cramps", "Hyperkalemia", "Hyperphosphatemia", "Hypernatremia"]'::jsonb, 0, 'Citrate used to anticoagulate the apheresis circuit chelates calcium, and some enters the systemic circulation, commonly causing symptomatic hypocalcemia such as perioral or extremity paresthesia and cramps; calcium supplementation is often given prophylactically or as needed.', 'Pre-Council', '🎓', true),
(6682, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The first-line emergent treatment for severe hyperkalemia with ECG changes, such as peaked T waves and widened QRS, is:', '["Loop diuretics", "IV calcium gluconate to stabilize the cardiac membrane", "Sodium polystyrene sulfonate (Kayexalate)", "Oral potassium binders"]'::jsonb, 1, 'IV calcium gluconate or calcium chloride does not lower serum potassium but immediately stabilizes the myocardial cell membrane, reducing the risk of life-threatening arrhythmias, and should be given first when ECG changes are present.', 'Pre-Council', '🎓', true),
(6683, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'After administering IV calcium for severe hyperkalemia, which interventions rapidly shift potassium intracellularly as temporizing measures?', '["Sodium polystyrene sulfonate and dialysis only", "Oral potassium supplements", "Furosemide alone", "IV regular insulin with concurrent dextrose, and nebulized or IV beta-2 agonists such as albuterol"]'::jsonb, 3, 'IV insulin, given with dextrose to prevent hypoglycemia, and beta-2 agonists both drive potassium into cells via stimulation of the Na-K-ATPase pump, providing rapid but temporary reduction in serum potassium while definitive removal is arranged.', 'Pre-Council', '🎓', true),
(6684, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which treatment actually removes potassium from the body, rather than simply shifting it intracellularly, in a patient with severe hyperkalemia and renal failure?', '["IV insulin and dextrose", "Sodium bicarbonate alone", "Hemodialysis", "IV calcium gluconate"]'::jsonb, 2, 'Hemodialysis actually removes potassium from the body, making it the definitive treatment in a patient with renal failure and severe hyperkalemia unresponsive to temporizing measures.', 'Pre-Council', '🎓', true),
(6685, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with chronic kidney disease commonly develops which acid-base abnormality due to reduced renal excretion of hydrogen ions and reduced bicarbonate regeneration?', '["Respiratory alkalosis", "Respiratory acidosis", "Metabolic acidosis", "Metabolic alkalosis"]'::jsonb, 2, 'Failing kidneys cannot adequately excrete the daily hydrogen ion load or regenerate bicarbonate, leading to a chronic anion-gap metabolic acidosis characteristic of advanced CKD.', 'Pre-Council', '🎓', true),
(6686, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Hyperphosphatemia in chronic kidney disease contributes to which secondary complication over time?', '["Secondary hyperparathyroidism and renal osteodystrophy", "Improved bone mineral density", "Hypocalcemia-induced tetany only in the acute setting", "Hypermagnesemia exclusively"]'::jsonb, 0, 'Retained phosphate binds calcium and stimulates parathyroid hormone secretion, driving secondary hyperparathyroidism, which over time contributes to renal osteodystrophy and vascular calcification in CKD patients.', 'Pre-Council', '🎓', true),
(6687, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which dietary/medication teaching is most appropriate for a CKD patient with chronic hyperphosphatemia?', '["Increase intake of dairy products and processed foods", "Take phosphate binders on an empty stomach between meals", "Avoid all protein intake completely", "Take prescribed phosphate binders with meals and limit high-phosphate foods"]'::jsonb, 3, 'Phosphate binders work by binding dietary phosphate in the gut and must be taken with meals to be effective; dietary phosphate restriction, limiting dairy, processed foods, and colas, is also emphasized.', 'Pre-Council', '🎓', true),
(6688, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Hypermagnesemia is a particular risk in renal failure patients who take which commonly available over-the-counter products?', '["Magnesium-containing antacids or laxatives", "Iron supplements", "Vitamin C supplements", "Acetaminophen"]'::jsonb, 0, 'Because impaired kidneys cannot excrete excess magnesium, magnesium-containing antacids such as milk of magnesia or laxatives can precipitate dangerous hypermagnesemia in renal failure patients and should generally be avoided.', 'Pre-Council', '🎓', true),
(6689, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Severe hypermagnesemia can cause which life-threatening cardiac/neuromuscular finding that the ICU nurse should monitor for?', '["Loss of deep tendon reflexes, respiratory depression, and bradycardia progressing to cardiac arrest", "Muscle spasticity and seizures", "Hypertension crisis with tremor", "Hyperreflexia and tachycardia"]'::jsonb, 0, 'Severe hypermagnesemia depresses neuromuscular transmission and cardiac conduction, causing diminished or absent deep tendon reflexes, muscle weakness, respiratory depression, bradyarrhythmias, and potentially cardiac arrest as levels rise.', 'Pre-Council', '🎓', true),
(6690, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with acute kidney injury develops hyponatremia primarily due to:', '["Excess sodium intake", "Excess aldosterone secretion", "Impaired free water excretion leading to dilutional hyponatremia, particularly with excessive hypotonic fluid administration", "Increased insensible losses"]'::jsonb, 2, 'In AKI and oliguria, the kidney''s impaired ability to excrete free water, especially when hypotonic IV fluids are administered, commonly leads to dilutional hyponatremia.', 'Pre-Council', '🎓', true),
(6691, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following best reflects appropriate nursing monitoring during and after a therapeutic apheresis procedure?', '["No specific monitoring is required beyond the procedure itself", "Monitoring vital signs, signs of citrate toxicity such as perioral tingling and cramping, bleeding at the access site, and signs of hypovolemia", "Monitoring only for allergic reaction", "Checking blood glucose only"]'::jsonb, 1, 'Apheresis nursing care includes close monitoring of vital signs, hypocalcemia/citrate toxicity symptoms, vascular access site for bleeding, and signs of hypovolemia or allergic/anaphylactoid reactions to replacement fluid.', 'Pre-Council', '🎓', true),
(6692, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with end-stage renal disease who missed a scheduled dialysis session presents with tall peaked T waves on ECG and a serum potassium of 7.2 mEq/L. In addition to emergent pharmacologic treatment, which nursing action is highest priority?', '["Continuous cardiac monitoring and preparation for emergent dialysis", "Administer a potassium supplement", "Delay treatment until the next routinely scheduled dialysis session", "Encourage oral intake of a high-potassium meal"]'::jsonb, 0, 'Severe hyperkalemia with ECG changes is a medical emergency requiring continuous cardiac monitoring, immediate temporizing pharmacologic treatment, and expedited emergent dialysis to remove the excess potassium definitively.', 'Pre-Council', '🎓', true),
(6693, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Chronic metabolic acidosis in CKD, if untreated, contributes to which additional complication commonly seen in these patients?', '["Hyperglycemia only", "Enhanced erythropoiesis", "Improved muscle mass", "Increased protein catabolism and worsening bone disease"]'::jsonb, 3, 'Chronic metabolic acidosis promotes muscle protein breakdown and buffers hydrogen ions by releasing calcium and phosphate from bone, worsening malnutrition and renal osteodystrophy; oral sodium bicarbonate is often prescribed to mitigate this.', 'Pre-Council', '🎓', true),
(6694, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The most common indication for a radical nephrectomy is:', '["Mild hydronephrosis", "Renal cell carcinoma", "Simple renal cyst", "Nephrolithiasis"]'::jsonb, 1, 'Radical nephrectomy, involving removal of the kidney, surrounding Gerota''s fascia, and often regional lymph nodes, is most commonly performed for localized renal cell carcinoma.', 'Pre-Council', '🎓', true),
(6695, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient is scheduled for a living donor nephrectomy. Which preoperative nursing priority is essential and specific to this surgery?', '["No special preoperative evaluation is needed beyond routine surgery workup", "Administering immunosuppressants preoperatively to the donor", "Scheduling immediate dialysis after the donor surgery", "Thorough evaluation of the donor''s overall renal function and anatomy, and confirming suitability and informed voluntary consent"]'::jsonb, 3, 'Because the donor will live with a single kidney afterward, thorough preoperative assessment of overall renal function, anatomy, and informed voluntary consent is essential prior to living donor nephrectomy.', 'Pre-Council', '🎓', true),
(6696, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Following an open nephrectomy via a flank incision, the nurse should monitor closely for which pulmonary complication due to the incision''s proximity to the diaphragm and pleura?', '["Aspiration pneumonia", "Atelectasis and potential pneumothorax", "Pulmonary edema from fluid overload only", "Pulmonary embolism only"]'::jsonb, 1, 'The flank incision used in open nephrectomy is high and close to the pleura and diaphragm, causing significant postoperative pain that limits deep breathing and predisposes to atelectasis, with some risk of pneumothorax from pleural injury during surgery.', 'Pre-Council', '🎓', true),
(6697, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Postoperative pain management and early incentive spirometry are especially important after nephrectomy primarily to prevent:', '["Atelectasis and pneumonia due to shallow breathing from incisional pain", "Deep vein thrombosis", "Wound dehiscence", "Paralytic ileus"]'::jsonb, 0, 'Because flank and upper abdominal incisions cause significant pain with breathing, adequate analgesia paired with incentive spirometry and early mobilization are critical to prevent atelectasis and postoperative pneumonia.', 'Pre-Council', '🎓', true),
(6698, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The priority postoperative nursing assessment after a unilateral nephrectomy, specific to renal function, is:', '["Monitoring hourly urine output to assess function of the remaining kidney", "Monitoring blood glucose exclusively", "Monitoring for signs of hyperthyroidism", "Monitoring bowel sounds only"]'::jsonb, 0, 'After removal of one kidney, the remaining kidney must compensate; hourly urine output monitoring is essential to detect early signs of inadequate renal function or acute kidney injury in the solitary kidney.', 'Pre-Council', '🎓', true),
(6699, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which position is typically used intraoperatively for an open nephrectomy, and what related postoperative nursing consideration follows from it?', '["Flexed lateral decubitus position, requiring careful postoperative assessment for pressure injury and stretch-related discomfort", "Prone position with no monitoring needed", "Trendelenburg position only", "Supine position, with no special considerations"]'::jsonb, 0, 'Nephrectomy is typically performed with the patient in a flexed lateral decubitus position to open the space between the ribs and iliac crest, which increases risk of pressure injury and stretch-related nerve or muscle discomfort requiring postoperative assessment.', 'Pre-Council', '🎓', true),
(6700, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient two hours post-laparoscopic nephrectomy reports shoulder tip pain. The nurse should recognize this as most likely related to:', '["Residual carbon dioxide gas used for pneumoperitoneum during laparoscopy, irritating the diaphragm", "Wound infection", "Renal colic", "Myocardial infarction"]'::jsonb, 0, 'Referred shoulder pain after laparoscopic surgery is a common, expected finding caused by retained CO2 gas irritating the diaphragm and phrenic nerve; it typically resolves within 24-48 hours with ambulation and mild analgesia.', 'Pre-Council', '🎓', true),
(6701, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which finding in the immediate postoperative period after nephrectomy should be reported to the surgeon promptly as a possible sign of hemorrhage?', '["Urine output of 40 mL/hr", "Normal bowel sounds returning on postoperative day 2", "Mild incisional pain controlled by prescribed analgesia", "Increasing abdominal/flank distention, tachycardia, and dropping blood pressure"]'::jsonb, 3, 'Increasing flank or abdominal distention combined with tachycardia and hypotension are classic signs of internal hemorrhage and require immediate notification of the surgical team.', 'Pre-Council', '🎓', true),
(6702, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient who underwent nephrectomy for renal trauma should be monitored postoperatively for which additional potential injury, given the mechanism?', '["Complete absence of any other injury risk", "Isolated fistula thrombosis", "Associated injuries to adjacent organs such as the spleen, liver, bowel, or vascular structures, depending on the trauma mechanism", "Immediate transplant rejection"]'::jsonb, 2, 'Traumatic nephrectomy often occurs in the context of significant blunt or penetrating trauma, so the nurse must maintain vigilance for concurrent injuries to nearby organs and structures.', 'Pre-Council', '🎓', true),
(6703, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Partial nephrectomy, or nephron-sparing surgery, is preferred over radical nephrectomy when possible, primarily because it:', '["Preserves more functioning renal tissue, reducing the risk of chronic kidney disease, especially with a solitary kidney or bilateral tumors", "Is always technically easier than radical nephrectomy", "Has a higher complication rate but a better cosmetic outcome", "Eliminates the need for postoperative monitoring"]'::jsonb, 0, 'Partial nephrectomy removes only the tumor and a margin of healthy tissue, preserving overall renal function and reducing long-term CKD risk compared with removing the entire kidney, and is favored for smaller tumors or when preserving renal mass is critical.', 'Pre-Council', '🎓', true),
(6704, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which laboratory trend would be most concerning in the days following a nephrectomy, suggesting the remaining kidney is not adequately compensating?', '["Stable or improving serum creatinine", "Progressively rising serum creatinine and BUN with declining urine output", "Normal serum potassium", "Mild transient postoperative anemia only"]'::jsonb, 1, 'A rising creatinine and BUN trend with declining urine output after nephrectomy suggests inadequate compensatory function of the remaining kidney and requires prompt evaluation.', 'Pre-Council', '🎓', true),
(6705, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Deep vein thrombosis prophylaxis, such as sequential compression devices, early ambulation, and pharmacologic prophylaxis as ordered, is important after nephrectomy primarily because:', '["It eliminates the need for pain management", "Major abdominal/flank surgery, immobility, and malignancy, when present, increase VTE risk", "DVT prophylaxis prevents wound infection", "Nephrectomy patients have no bleeding risk from anticoagulation"]'::jsonb, 1, 'Major surgery, postoperative immobility, and underlying malignancy in oncologic nephrectomy are all recognized VTE risk factors, making thromboprophylaxis an important part of postoperative nursing care.', 'Pre-Council', '🎓', true),
(6706, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Hyperacute rejection of a transplanted kidney occurs due to:', '["A T-cell mediated response developing over weeks", "Viral infection of the graft", "Preformed recipient antibodies against donor antigens, causing rejection within minutes to hours of transplantation", "Chronic fibrosis developing over years"]'::jsonb, 2, 'Hyperacute rejection results from preexisting recipient antibodies, from prior transplants, transfusions, or pregnancy, that immediately attack donor endothelial antigens, causing thrombosis and graft failure within minutes to hours; it is now rare due to pre-transplant crossmatching.', 'Pre-Council', '🎓', true),
(6707, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Acute rejection of a renal transplant typically occurs within which timeframe post-transplant, and is most often mediated by which mechanism?', '["It never involves the immune system", "Minutes to hours, antibody-mediated only", "Days to months, primarily a T-cell mediated cellular immune response", "Only after 5 years, purely fibrotic"]'::jsonb, 2, 'Acute rejection typically occurs within the first days to months post-transplant and is most commonly a T-cell mediated cellular immune response against donor antigens, though antibody-mediated acute rejection can also occur.', 'Pre-Council', '🎓', true),
(6708, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which clinical finding should raise the nurse''s suspicion for acute rejection in a renal transplant recipient?', '["Decreasing serum creatinine", "Improved appetite", "Weight loss with normal labs", "Fever, decreased urine output, graft tenderness/swelling, and rising serum creatinine"]'::jsonb, 3, 'Classic signs of acute rejection include fever, oliguria, graft tenderness or swelling, hypertension, and a rising serum creatinine, all of which require prompt evaluation, often including biopsy confirmation.', 'Pre-Council', '🎓', true),
(6709, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which class of immunosuppressant medications, including tacrolimus and cyclosporine, inhibits calcineurin to reduce T-cell activation but carries a significant risk of nephrotoxicity?', '["Antimetabolites, such as mycophenolate", "Calcineurin inhibitors", "Induction antibody agents", "Corticosteroids"]'::jsonb, 1, 'Calcineurin inhibitors such as tacrolimus and cyclosporine block T-cell activation by inhibiting calcineurin-dependent IL-2 production, but are also directly nephrotoxic and require careful therapeutic drug monitoring to balance rejection prevention with drug-induced kidney injury.', 'Pre-Council', '🎓', true),
(6710, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A renal transplant recipient on long-term immunosuppression is at increased risk for which category of complications that the critical care nurse must monitor for?', '["Only musculoskeletal complications", "Opportunistic infections, malignancy, and metabolic effects such as new-onset diabetes and hypertension related to chronic immunosuppression", "Only cardiovascular complications", "No increased risk compared with the general population"]'::jsonb, 1, 'Chronic immunosuppression increases susceptibility to opportunistic infections such as CMV, malignancy, especially skin cancers and post-transplant lymphoproliferative disease, and metabolic complications such as new-onset diabetes and hypertension from corticosteroids and calcineurin inhibitors.', 'Pre-Council', '🎓', true),
(6711, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Delayed graft function after renal transplantation is most commonly defined as:', '["Chronic rejection occurring years later", "Immediate excellent urine output post-transplant", "Need for dialysis within the first week post-transplant due to slow graft recovery, most often related to ischemia-reperfusion injury", "Rapid rise in urine output within the first hour"]'::jsonb, 2, 'Delayed graft function refers to the need for dialysis in the first week after transplant, most commonly resulting from ischemia-reperfusion injury during procurement, preservation, and transplantation; it is more common with deceased donor kidneys, especially after prolonged cold ischemia time.', 'Pre-Council', '🎓', true),
(6712, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Immediately post-transplant, the critical care nurse should anticipate replacing urine output on a milliliter-for-milliliter or fractional basis primarily to:', '["Prevent hypovolemia and maintain adequate graft perfusion, since large diuresis is common as the new kidney begins functioning", "Reduce the need for immunosuppression", "Prevent fluid overload only", "Prevent hyperkalemia exclusively"]'::jsonb, 0, 'A newly transplanted kidney, especially from a living donor, often produces large volumes of dilute urine immediately post-op; careful fluid replacement protocols prevent hypovolemia and maintain graft perfusion during this critical early period.', 'Pre-Council', '🎓', true),
(6713, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Chronic rejection of a renal transplant is characterized by which process?', '["Sudden anuria within the first 24 hours", "Gradual, progressive decline in graft function over months to years due to fibrosis and vascular changes", "Complete reversibility with steroid pulse therapy", "Rapid graft loss within hours"]'::jsonb, 1, 'Chronic rejection develops slowly over months to years, involving progressive interstitial fibrosis, tubular atrophy, and vascular changes, and is generally not reversible with standard rejection treatment, often leading to eventual graft failure.', 'Pre-Council', '🎓', true),
(6714, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which vital sign/laboratory trend in the early postoperative period after renal transplant should prompt the nurse to suspect surgical bleeding or a vascular complication rather than rejection?', '["Low-grade fever on postoperative day 5", "Slowly rising creatinine over several days with stable vitals", "Gradual increase in urine output", "Sudden hypotension, tachycardia, and falling hemoglobin/hematocrit in the first hours post-op"]'::jsonb, 3, 'Acute hypotension, tachycardia, and a falling hematocrit in the immediate postoperative hours are concerning for surgical hemorrhage or a vascular complication such as anastomotic leak or thrombosis, rather than rejection, which typically presents more gradually.', 'Pre-Council', '🎓', true),
(6715, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The nurse should teach a renal transplant recipient that lifelong adherence to immunosuppressive therapy is critical because:', '["Only the first year post-transplant requires strict adherence", "Missing doses only causes mild, reversible side effects", "Immunosuppression can be safely stopped once creatinine normalizes", "Nonadherence significantly increases the risk of acute or chronic rejection and graft loss"]'::jsonb, 3, 'Because rejection is an ongoing immunologic risk for the life of the graft, lifelong adherence to immunosuppressive therapy is essential; missed doses significantly increase the risk of rejection episodes and graft loss.', 'Pre-Council', '🎓', true),
(6716, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Renal artery thrombosis, a rare but serious early vascular complication after transplant, typically presents with:', '["Improved graft function", "Slowly rising blood pressure only", "Gradual painless decline in urine output over weeks", "Sudden, complete cessation of urine output with graft pain, requiring emergent evaluation"]'::jsonb, 3, 'Renal artery or vein thrombosis is a surgical emergency presenting with sudden anuria and graft tenderness; rapid recognition and intervention, often re-exploration, is needed to attempt to salvage the graft, though thrombosis frequently results in graft loss if not treated immediately.', 'Pre-Council', '🎓', true),
(6717, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Induction immunosuppression agents, such as anti-thymocyte globulin or basiliximab, are administered perioperatively for renal transplant primarily to:', '["Provide intense early immunosuppression during the highest-risk period for acute rejection, allowing lower maintenance doses later", "Prevent surgical site infection only", "Treat established chronic rejection", "Replace the need for maintenance immunosuppression entirely"]'::jsonb, 0, 'Induction therapy provides potent immunosuppression during the perioperative period, when the risk of acute rejection is highest, and allows for reduced intensity of maintenance immunosuppressive regimens thereafter.', 'Pre-Council', '🎓', true),
(6718, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A living kidney donor is generally preferred over a deceased donor when available, in part because living donor kidneys typically have:', '["Shorter cold ischemia time and generally better long-term graft outcomes", "A guaranteed genetically identical match", "No need for any immunosuppression in the recipient", "Higher rates of delayed graft function"]'::jsonb, 0, 'Living donor kidneys typically have minimal cold ischemia time since the organ is transplanted quickly, and are associated with better immediate function and generally superior long-term graft survival compared with deceased donor kidneys.', 'Pre-Council', '🎓', true),
(6719, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Post-transplant, a patient develops leukopenia and profound fatigue with elevated liver enzymes several weeks after starting immunosuppression. This clinical picture should raise suspicion for:', '["Acute cellular rejection", "A normal expected side effect requiring no evaluation", "Medication non-adherence", "Cytomegalovirus (CMV) infection or reactivation, a common opportunistic infection in immunosuppressed transplant patients"]'::jsonb, 3, 'CMV is one of the most common and clinically significant opportunistic infections in transplant recipients, often presenting with fever, leukopenia, fatigue, and organ involvement such as hepatitis or colitis; prophylaxis and monitoring are standard parts of post-transplant care.', 'Pre-Council', '🎓', true),
(6720, 'Renal Disorders', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The critical care nurse''s priority in the first 24 hours after renal transplantation includes which combination of interventions?', '["Close hemodynamic monitoring, hourly urine output measurement with fluid replacement per protocol, pain control, and vigilant monitoring for signs of rejection or vascular complications", "Withholding all pain medication to monitor mental status", "Strict fluid restriction regardless of urine output", "Immediate discontinuation of the urinary catheter"]'::jsonb, 0, 'The immediate post-transplant period requires intensive monitoring of hemodynamics and urine output with corresponding fluid replacement, effective analgesia, and close observation for early signs of rejection, bleeding, or vascular complications to protect the newly transplanted graft.', 'Pre-Council', '🎓', true),
(6721, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient sustains a rotational acceleration-deceleration injury in a high-speed motor vehicle collision. The initial CT is normal, but the patient remains comatose for several days. Which type of head injury is most consistent with this presentation?', '["Diffuse axonal injury", "Epidural hematoma", "Depressed skull fracture", "Concussion"]'::jsonb, 0, 'Diffuse axonal injury results from shearing forces on axons during rapid rotational acceleration-deceleration; CT is often initially normal despite severe, prolonged unconsciousness.', 'Pre-Council', '🎓', true),
(6722, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which finding is most indicative of a basilar skull fracture?', '["Contralateral hemiparesis", "Battle''s sign and raccoon eyes", "Ipsilateral pupil dilation", "Nuchal rigidity"]'::jsonb, 1, 'Mastoid ecchymosis (Battle''s sign) and periorbital ecchymosis (raccoon eyes), along with CSF otorrhea/rhinorrhea and hemotympanum, are classic signs of a basilar skull fracture.', 'Pre-Council', '🎓', true),
(6723, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A CSF leak is suspected from a patient''s nose after head trauma. Which bedside test helps confirm CSF rather than mucus?', '["Kernig''s sign", "Doll''s eye test", "Halo (ring) sign on gauze", "Babinski test"]'::jsonb, 2, 'When fluid containing CSF is dropped on gauze, CSF diffuses faster than blood, creating a clear halo/ring around a central blood spot; the fluid can also be confirmed positive for glucose.', 'Pre-Council', '🎓', true),
(6724, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the priority nursing action for a patient with suspected CSF rhinorrhea after head trauma?', '["Insert a nasogastric tube for feeding", "Position the patient supine and flat", "Encourage vigorous coughing", "Avoid nose blowing, suctioning, and nasal packing"]'::jsonb, 3, 'Nasal suctioning, blowing, or packing can introduce pathogens through the dural tear and raise the risk of ascending meningitis, so these are avoided until the leak resolves or is repaired.', 'Pre-Council', '🎓', true),
(6725, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which classification best describes a head injury caused by a bullet penetrating the skull?', '["Open (penetrating) head injury", "Closed head injury", "Coup injury", "Contrecoup injury"]'::jsonb, 0, 'A penetrating object that breaches the skull and dura is classified as an open head injury, carrying high risk of direct tissue destruction and infection.', 'Pre-Council', '🎓', true),
(6726, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient with a head injury has a Glasgow Coma Scale score of 10. This is classified as which severity of traumatic brain injury?', '["Mild", "Moderate", "Severe", "Vegetative state"]'::jsonb, 1, 'A GCS of 9-12 is classified as moderate traumatic brain injury, between mild (13-15) and severe (3-8).', 'Pre-Council', '🎓', true),
(6727, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The coup-contrecoup mechanism of brain injury describes which of the following?', '["Injury only at the site of direct impact", "Diffuse shearing injury without focal contusion", "Injury at the site of impact and at the opposite pole of the brain from movement within the skull", "A fracture line radiating from the impact point"]'::jsonb, 2, 'Coup injury occurs at the site of impact; contrecoup injury occurs at the opposite pole as the brain rebounds and strikes the skull, producing two areas of contusion.', 'Pre-Council', '🎓', true),
(6728, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following is a preventable secondary brain injury factor that critical care nurses must aggressively manage after TBI?', '["The initial mechanical impact", "Skull fracture location", "Scalp laceration", "Hypotension and hypoxia"]'::jsonb, 3, 'Unlike the primary mechanical injury, hypotension and hypoxia are preventable secondary insults that significantly worsen neurologic outcomes and must be avoided.', 'Pre-Council', '🎓', true),
(6729, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the priority initial management step for a patient with severe traumatic brain injury in the emergency department?', '["Airway, breathing, and circulation management with cervical spine precautions", "Immediate CT scan without airway assessment", "Immediate lumbar puncture", "Rapid infusion of hypotonic IV fluids"]'::jsonb, 0, 'ABCs with cervical spine immobilization take priority over diagnostic imaging, since hypoxia and hypotension from an unmanaged airway or hemorrhage cause secondary brain injury.', 'Pre-Council', '🎓', true),
(6730, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which type of skull fracture carries the highest risk of underlying dural tear and infection, often requiring surgical elevation?', '["Linear fracture", "Depressed skull fracture", "Hairline fracture", "Greenstick fracture"]'::jsonb, 1, 'A depressed skull fracture pushes bone fragments inward, risking dural laceration, brain contusion, and infection, and often requires surgical elevation and debridement.', 'Pre-Council', '🎓', true),
(6731, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Cushing''s triad, a late sign of rising intracranial pressure, consists of which three findings?', '["Hypotension, tachycardia, and tachypnea", "Hypertension with tachycardia and hyperthermia", "Hypertension with widened pulse pressure, bradycardia, and irregular respirations", "Hypotension, bradycardia, and apnea"]'::jsonb, 2, 'Cushing''s triad reflects the body''s attempt to maintain cerebral perfusion against rising ICP: widened pulse pressure hypertension, reflex bradycardia, and irregular respiratory patterns.', 'Pre-Council', '🎓', true),
(6732, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the normal range for intracranial pressure (ICP) in adults?', '["0-5 mmHg", "20-30 mmHg", "30-40 mmHg", "5-15 mmHg"]'::jsonb, 3, 'Normal adult ICP is approximately 5-15 mmHg; sustained values above 20 mmHg are generally treated as pathologically elevated.', 'Pre-Council', '🎓', true),
(6733, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the correct formula for cerebral perfusion pressure (CPP)?', '["CPP = MAP \u2212 ICP", "CPP = ICP \u2212 MAP", "CPP = MAP + ICP", "CPP = SBP \u2212 DBP"]'::jsonb, 0, 'CPP represents the pressure gradient driving cerebral blood flow and is calculated as mean arterial pressure minus intracranial pressure.', 'Pre-Council', '🎓', true),
(6734, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the generally recommended target cerebral perfusion pressure (CPP) in the management of severe traumatic brain injury?', '["40-50 mmHg", "60-70 mmHg", "90-100 mmHg", "Greater than 100 mmHg"]'::jsonb, 1, 'Current guidelines recommend maintaining CPP in the range of 60-70 mmHg to ensure adequate cerebral perfusion while avoiding the complications of excessive fluid and vasopressor use.', 'Pre-Council', '🎓', true),
(6735, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What degree of head-of-bed elevation is recommended to reduce intracranial pressure while maintaining cerebral perfusion?', '["Flat at 0 degrees", "15 degrees of elevation", "30 degrees of elevation with neutral head and neck alignment", "90 degrees, fully upright"]'::jsonb, 2, 'Elevating the head of bed to about 30 degrees with the head in neutral alignment promotes cerebral venous drainage and lowers ICP without significantly compromising CPP.', 'Pre-Council', '🎓', true),
(6736, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which arterial blood gas abnormality is most important to avoid in a patient with elevated ICP because it causes cerebral vasodilation?', '["Hypocapnia (PaCO2 less than 30 mmHg)", "Hyperoxia (PaO2 greater than 100 mmHg)", "Normocapnia", "Hypercapnia (PaCO2 greater than 45 mmHg)"]'::jsonb, 3, 'Hypercapnia causes cerebral vasodilation, increasing cerebral blood volume and worsening intracranial pressure, so normocapnia (PaCO2 35-40 mmHg) is generally the goal.', 'Pre-Council', '🎓', true),
(6737, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When administering mannitol for elevated ICP, the nurse should monitor for which of the following?', '["Serum osmolality and signs of hypovolemia or renal injury", "Serum potassium level only", "Blood glucose exclusively", "Liver enzyme levels"]'::jsonb, 0, 'Mannitol is an osmotic diuretic; nurses monitor serum osmolality (keeping it below approximately 320 mOsm/L) and watch for hypovolemia, hypotension, and renal injury from excessive diuresis.', 'Pre-Council', '🎓', true),
(6738, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Hypertonic saline reduces intracranial pressure primarily by which mechanism?', '["Directly vasodilating cerebral blood vessels", "Osmotically drawing free water out of brain tissue into the vasculature", "Decreasing serum sodium concentration", "Increasing CSF production"]'::jsonb, 1, 'Hypertonic saline creates an osmotic gradient that pulls water out of swollen brain tissue and into the intravascular space, reducing cerebral edema and ICP.', 'Pre-Council', '🎓', true),
(6739, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which ICP monitoring device is considered the gold standard because it also allows therapeutic drainage of cerebrospinal fluid?', '["Subarachnoid bolt", "Epidural sensor", "Intraventricular catheter (external ventricular drain)", "Intraparenchymal fiberoptic monitor"]'::jsonb, 2, 'The intraventricular catheter (EVD) is the gold standard for ICP monitoring because, unlike bolts or parenchymal monitors, it also permits therapeutic CSF drainage to control ICP.', 'Pre-Council', '🎓', true),
(6740, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the recommended external anatomical reference point used to zero and level an external ventricular drain (EVD)?', '["Xiphoid process", "Umbilicus", "Sternal angle", "Tragus of the ear (level of the foramen of Monro)"]'::jsonb, 3, 'The tragus approximates the level of the foramen of Monro and is the standard external reference point for zeroing and leveling an EVD transducer or drainage chamber.', 'Pre-Council', '🎓', true),
(6741, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A nurse needs to reposition a patient with an EVD in place. What is the priority action?', '["Clamp the drain per protocol and re-level it to prevent over- or under-drainage", "Leave the drain open regardless of the position change", "Immediately remove the drain", "Increase the drainage chamber height only"]'::jsonb, 0, 'Repositioning changes the relationship between the reference point and the drainage chamber; the drain should be clamped per protocol during the move and re-leveled afterward to avoid inaccurate drainage.', 'Pre-Council', '🎓', true),
(6742, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A comatose head-injury patient develops an ipsilateral fixed and dilated pupil with contralateral hemiparesis. This is most consistent with which herniation syndrome?', '["Bilateral pinpoint pupils indicating pontine injury", "Uncal (transtentorial) herniation", "Symmetric, reactive pupils bilaterally", "Bilateral hyperreflexia without pupillary change"]'::jsonb, 1, 'Uncal herniation compresses the ipsilateral oculomotor nerve (causing a fixed, dilated pupil) and the contralateral cerebral peduncle (causing contralateral weakness) as the uncus shifts through the tentorial notch.', 'Pre-Council', '🎓', true),
(6743, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Therapeutic hyperventilation used briefly as a temporizing measure for acute herniation should target a PaCO2 of approximately what value?', '["15-20 mmHg", "45-50 mmHg", "30-35 mmHg", "55-60 mmHg"]'::jsonb, 2, 'Brief hyperventilation to a PaCO2 of about 30-35 mmHg causes cerebral vasoconstriction to temporarily lower ICP; prolonged or more aggressive hyperventilation risks cerebral ischemia and is avoided.', 'Pre-Council', '🎓', true),
(6744, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the priority nursing intervention for airway management in an unconscious patient?', '["Position the patient supine and flat", "Insert an oral airway only if the gag reflex is present", "Elevate the legs above the level of the heart", "Position the patient laterally (recovery position) or semi-prone with the head of bed elevated to maintain a patent airway"]'::jsonb, 3, 'Lateral or semi-prone positioning with head-of-bed elevation prevents the tongue from occluding the airway and reduces aspiration risk in an unconscious patient who cannot protect their own airway.', 'Pre-Council', '🎓', true),
(6745, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why is meticulous eye care important for an unconscious patient with an absent corneal reflex?', '["To prevent corneal drying and exposure keratopathy", "To prevent hearing loss", "To reduce intracranial pressure", "To prevent joint contractures"]'::jsonb, 0, 'Loss of the blink reflex and corneal reflex leaves the cornea exposed and unprotected, risking drying, ulceration, and exposure keratopathy without regular lubrication and eye protection.', 'Pre-Council', '🎓', true),
(6746, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which nursing intervention best prevents pressure injuries in an unconscious ICU patient?', '["Restricting all repositioning to avoid disturbing the patient", "Repositioning at least every 2 hours and use of pressure-redistribution surfaces", "Applying tight restraints to limit movement", "Keeping the head of bed flat continuously"]'::jsonb, 1, 'Regular repositioning combined with pressure-redistributing support surfaces is the standard of care for preventing pressure injury in immobile, unconscious patients.', 'Pre-Council', '🎓', true),
(6747, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the standard approach to bladder management for an unconscious patient?', '["No catheterization is needed for an unconscious patient", "Encouraging the patient to void on command", "Indwelling urinary catheter placement with strict intake and output monitoring", "Fluid restriction"]'::jsonb, 2, 'An unconscious patient cannot sense or control bladder function, so an indwelling catheter with strict I&O monitoring is used to manage urinary elimination and track fluid balance.', 'Pre-Council', '🎓', true),
(6748, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which is an appropriate DVT prophylaxis strategy for an immobile, unconscious neurologic patient without contraindications?', '["Strict bed rest without any prophylaxis", "Early ambulation only", "Keeping the head of bed flat continuously", "Sequential compression devices and/or pharmacologic prophylaxis"]'::jsonb, 3, 'Since the patient cannot ambulate, mechanical (sequential compression devices) and, when appropriate, pharmacologic prophylaxis are used to reduce venous thromboembolism risk.', 'Pre-Council', '🎓', true),
(6749, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is an appropriate nutrition strategy for a patient who remains unconscious for a prolonged period?', '["Early enteral tube feeding once hemodynamically stable", "Total fasting until consciousness returns", "An oral feeding trial immediately", "Intravenous dextrose only, indefinitely"]'::jsonb, 0, 'Early enteral nutrition, once the patient is hemodynamically stable, supports metabolic needs, preserves gut integrity, and is preferred over prolonged fasting or dextrose-only support.', 'Pre-Council', '🎓', true),
(6750, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which combination correctly represents the three components and maximum score of the Glasgow Coma Scale?', '["Eye opening (5) + Verbal (4) + Motor (6) = 15", "Eye opening (4) + Verbal (5) + Motor (6) = 15", "Eye opening (4) + Verbal (6) + Motor (5) = 15", "Eye opening (3) + Verbal (5) + Motor (7) = 15"]'::jsonb, 1, 'The GCS is scored as Eye opening (maximum 4) + Verbal response (maximum 5) + Motor response (maximum 6), for a maximum total of 15.', 'Pre-Council', '🎓', true),
(6751, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A Glasgow Coma Scale score in which range classifies a traumatic brain injury as severe?', '["13-15", "9-12", "3-8", "3-5 only"]'::jsonb, 2, 'A GCS of 3-8 defines severe traumatic brain injury and is the threshold commonly used to indicate the need for airway protection/intubation.', 'Pre-Council', '🎓', true),
(6752, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient opens their eyes only to painful stimuli, makes incomprehensible sounds, and withdraws from pain. What is the calculated GCS score?', '["6", "10", "12", "8"]'::jsonb, 3, 'Eye opening to pain = 2, incomprehensible sounds = 2, withdrawal from pain = 4; the total is 2+2+4 = 8.', 'Pre-Council', '🎓', true),
(6753, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Abnormal flexion (decorticate posturing) corresponds to which motor score on the Glasgow Coma Scale?', '["3", "6", "5", "4"]'::jsonb, 0, 'Decorticate (abnormal flexor) posturing is scored as a motor response of 3 on the GCS, worse than localizing (5) or withdrawal (4) but better than extensor posturing (2).', 'Pre-Council', '🎓', true),
(6754, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Abnormal extension (decerebrate posturing) corresponds to which motor score on the Glasgow Coma Scale?', '["3", "2", "4", "5"]'::jsonb, 1, 'Decerebrate (abnormal extensor) posturing is scored as a motor response of 2, indicating more severe brainstem dysfunction than decorticate (flexor) posturing (score 3).', 'Pre-Council', '🎓', true),
(6755, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the lowest possible total score on the Glasgow Coma Scale?', '["0", "1", "3", "5"]'::jsonb, 2, 'Because each component (eye, verbal, motor) has a minimum score of 1, the lowest possible total GCS score is 3, not 0.', 'Pre-Council', '🎓', true),
(6756, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How is verbal responsiveness typically documented on the GCS for an intubated patient who cannot speak?', '["The GCS is omitted entirely", "A verbal score of 5 is assigned automatically", "The motor score alone is used as the total", "A verbal score of 1 is assigned with a \"T\" suffix noting intubation"]'::jsonb, 3, 'Because an intubated patient cannot produce verbal sounds, the verbal component is typically scored as 1 and documented with a "T" (e.g., "GCS 10T") to indicate the limitation.', 'Pre-Council', '🎓', true),
(6757, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which is considered a highly sensitive early indicator of neurological deterioration in a patient with a head injury?', '["Decreased level of consciousness (eye opening/arousal)", "Pupil size change", "Elevated blood pressure", "Change in motor strength"]'::jsonb, 0, 'A decline in level of consciousness or arousal is typically the earliest and most sensitive sign of neurologic deterioration, often preceding pupillary and vital sign changes.', 'Pre-Council', '🎓', true),
(6758, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A positive Babinski sign in an adult indicates which of the following?', '["A normal reflex arc", "An upper motor neuron lesion", "Peripheral neuropathy only", "Cerebellar dysfunction"]'::jsonb, 1, 'Dorsiflexion of the great toe with fanning of the other toes upon plantar stimulation is abnormal in an adult and indicates upper motor neuron pathway dysfunction.', 'Pre-Council', '🎓', true),
(6759, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A positive Babinski response (dorsiflexion of the great toe with fanning of the other toes) is considered a normal finding in which population?', '["Healthy adults", "Elderly patients only", "Infants under approximately 1-2 years of age", "Post-exercise adults"]'::jsonb, 2, 'An extensor plantar (Babinski) response is a normal finding in infants due to incomplete corticospinal tract myelination and becomes abnormal once the tract matures, typically by age 1-2 years.', 'Pre-Council', '🎓', true),
(6760, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'On the standard deep tendon reflex grading scale, a score of 4+ indicates which finding?', '["Absent reflex", "Normal reflex", "Diminished reflex", "Brisk, hyperactive reflex with clonus"]'::jsonb, 3, 'The DTR scale ranges from 0 (absent) to 4+ (brisk/hyperactive with clonus), with 2+ representing a normal response.', 'Pre-Council', '🎓', true),
(6761, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Diminished or absent deep tendon reflexes are a classic finding in which condition covered in this unit?', '["Guillain-Barre syndrome", "Simple febrile seizure", "Toxic epidermal necrolysis syndrome", "Migraine"]'::jsonb, 0, 'Guillain-Barre syndrome is an acute inflammatory demyelinating polyneuropathy that classically presents with progressive weakness accompanied by diminished or absent deep tendon reflexes (areflexia).', 'Pre-Council', '🎓', true),
(6762, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which deep tendon reflex is used to assess the S1 nerve root?', '["Biceps reflex", "Achilles reflex", "Patellar reflex", "Brachioradialis reflex"]'::jsonb, 1, 'The Achilles (ankle) reflex primarily tests the integrity of the S1 nerve root, while the patellar reflex tests L2-L4 and the biceps/brachioradialis reflexes test cervical roots.', 'Pre-Council', '🎓', true),
(6763, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How is brain death formally defined?', '["Persistent vegetative state", "Deep coma with intact brainstem reflexes", "Irreversible cessation of all functions of the entire brain, including the brainstem", "Locked-in syndrome"]'::jsonb, 2, 'Brain death is the irreversible loss of all brain and brainstem function, distinct from a persistent vegetative state (in which brainstem function is preserved) or locked-in syndrome (in which consciousness is intact).', 'Pre-Council', '🎓', true),
(6764, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During a formal apnea test, which finding supports a diagnosis of brain death?', '["The patient takes one deep breath", "PaCO2 falls below 30 mmHg", "The patient coughs during suctioning", "PaCO2 rises above 60 mmHg (or 20 mmHg above baseline) without spontaneous respiratory effort"]'::jsonb, 3, 'A positive apnea test, supporting brain death, occurs when the PaCO2 rises sufficiently to strongly stimulate respiratory drive yet the patient shows no spontaneous respiratory effort.', 'Pre-Council', '🎓', true),
(6765, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Before proceeding with formal brain death testing, which confounding factors must be excluded?', '["Hypothermia, drug intoxication, and severe metabolic derangement must be excluded", "The patient must be receiving vasopressors", "The patient must have a GCS of 6", "Family must be present at bedside"]'::jsonb, 0, 'Reversible conditions that can mimic brain death—such as hypothermia, sedating/paralyzing drugs, and severe metabolic or endocrine derangements—must be ruled out before brain death can be declared.', 'Pre-Council', '🎓', true),
(6766, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When the clinical examination or apnea test cannot be completed, which confirmatory ancillary test may be used to support a diagnosis of brain death?', '["Chest x-ray", "Cerebral blood flow study (radionuclide scan) or EEG showing electrocerebral silence", "Lumbar puncture", "MRI of the spine"]'::jsonb, 1, 'When clinical testing is inconclusive or cannot be safely performed, ancillary tests such as cerebral blood flow studies or EEG demonstrating electrocerebral silence support the diagnosis of brain death.', 'Pre-Council', '🎓', true),
(6767, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During cold caloric (oculovestibular) testing, which finding is consistent with brain death?', '["A normal brainstem shows no eye movement to cold water irrigation", "The test evaluates the pupillary light reflex, not eye movement", "Absence of eye deviation toward the irrigated ear indicates loss of the oculovestibular reflex, consistent with brain death", "The test evaluates spinal cord reflexes only"]'::jsonb, 2, 'In an intact brainstem, cold water irrigation of the ear causes tonic eye deviation toward that ear; absence of this response indicates loss of brainstem function consistent with brain death.', 'Pre-Council', '🎓', true),
(6768, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which of the following findings is NOT compatible with a diagnosis of brain death?', '["Fixed and dilated pupils", "Absent corneal reflex", "Absent gag reflex", "Spontaneous respiratory effort during apnea testing"]'::jsonb, 3, 'Any spontaneous respiratory effort during a properly conducted apnea test indicates preserved brainstem respiratory drive and rules out brain death; the other findings are all expected in brain death.', 'Pre-Council', '🎓', true),
(6769, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Approximately what percentage of all strokes are ischemic in origin?', '["~87%", "~50%", "~30%", "~13%"]'::jsonb, 0, 'Roughly 87% of strokes are ischemic (caused by arterial occlusion or thrombosis), while the remaining approximately 13% are hemorrhagic.', 'Pre-Council', '🎓', true),
(6770, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The FAST acronym used for rapid public and clinical recognition of stroke stands for which of the following?', '["Fever, Ataxia, Seizure, Trauma", "Face, Arm, Speech, Time", "Focus, Airway, Stroke, Treatment", "Face, Ataxia, Speech, Temperature"]'::jsonb, 1, 'FAST prompts assessment of Facial drooping, Arm weakness, Speech difficulty, and noting the Time symptoms began, which is critical for treatment eligibility decisions.', 'Pre-Council', '🎓', true),
(6771, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the standard time window from symptom onset for administering IV tissue plasminogen activator (tPA) in acute ischemic stroke?', '["12 hours", "24 hours", "3-4.5 hours", "48 hours"]'::jsonb, 2, 'IV tPA is generally administered within 3 to 4.5 hours of clearly defined symptom onset in eligible patients, based on established stroke treatment protocols.', 'Pre-Council', '🎓', true),
(6772, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What blood pressure threshold must generally be achieved before administering IV tPA for acute ischemic stroke?', '["Less than 220/120 mmHg", "Less than 160/100 mmHg", "There is no blood pressure limit", "Less than 185/110 mmHg"]'::jsonb, 3, 'Blood pressure must be lowered to below 185/110 mmHg before tPA administration to reduce the risk of hemorrhagic conversion, and kept below 180/105 mmHg afterward.', 'Pre-Council', '🎓', true),
(6773, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In an ischemic stroke patient who is NOT receiving tPA, permissive hypertension is typically allowed up to what blood pressure?', '["220/120 mmHg", "140/90 mmHg", "160/100 mmHg", "180/100 mmHg"]'::jsonb, 0, 'In ischemic stroke patients not eligible for thrombolysis, blood pressure is generally permitted to remain elevated up to about 220/120 mmHg to preserve perfusion to the ischemic penumbra.', 'Pre-Council', '🎓', true),
(6774, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why does blood pressure management differ in hemorrhagic stroke compared to ischemic stroke?', '["Hypertension should always be permitted", "Aggressive blood pressure lowering (e.g., SBP less than 140-160 mmHg) reduces hematoma expansion", "Blood pressure is irrelevant in hemorrhagic stroke", "Hypotension is the primary goal of management"]'::jsonb, 1, 'Unlike ischemic stroke, in hemorrhagic stroke aggressive blood pressure lowering is used because uncontrolled hypertension promotes ongoing bleeding and hematoma expansion.', 'Pre-Council', '🎓', true),
(6775, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'In select patients with large vessel occlusion ischemic stroke and favorable imaging, mechanical thrombectomy may be performed up to how many hours from symptom onset?', '["6 hours only", "72 hours", "Up to 24 hours in select patients with favorable imaging", "1 hour only"]'::jsonb, 2, 'With advanced perfusion imaging selection, mechanical thrombectomy for large vessel occlusion can be extended up to 24 hours in carefully selected patients.', 'Pre-Council', '🎓', true),
(6776, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the classic clinical presentation of subarachnoid hemorrhage?', '["Gradual headache developing over weeks", "Painless vision loss", "Isolated foot drop", "Sudden \"worst headache of life\" (thunderclap headache)"]'::jsonb, 3, 'Subarachnoid hemorrhage, often from a ruptured cerebral aneurysm, classically presents with a sudden, severe "thunderclap" headache described as the worst of the patient''s life.', 'Pre-Council', '🎓', true),
(6777, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which delayed complication of aneurysmal subarachnoid hemorrhage must be monitored for, typically between days 4 and 14 after the bleed?', '["Cerebral vasospasm", "Peripheral neuropathy", "Pulmonary embolism", "Compartment syndrome"]'::jsonb, 0, 'Cerebral vasospasm is a major delayed complication of SAH occurring roughly between days 4 and 14, causing secondary cerebral ischemia and worsened outcomes if untreated.', 'Pre-Council', '🎓', true),
(6778, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which medication is administered to reduce cerebral vasospasm-related ischemia after aneurysmal subarachnoid hemorrhage?', '["Mannitol", "Nimodipine", "Warfarin", "Metoprolol"]'::jsonb, 1, 'Nimodipine, a calcium channel blocker with selective cerebral vasodilating effects, is given after aneurysmal SAH specifically to reduce vasospasm-related ischemic complications.', 'Pre-Council', '🎓', true),
(6779, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The National Institutes of Health Stroke Scale (NIHSS) is used clinically to accomplish which of the following?', '["Measure intracranial pressure directly", "Diagnose brain death", "Quantify stroke severity and neurological deficit", "Grade delirium severity"]'::jsonb, 2, 'The NIHSS is a standardized, validated tool used to quantify the severity of neurological deficits in acute stroke and to track changes over time.', 'Pre-Council', '🎓', true),
(6780, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Xanthochromia (yellow discoloration) of the cerebrospinal fluid on lumbar puncture is most suggestive of which condition?', '["Bacterial meningitis only", "Normal CSF findings", "Guillain-Barre syndrome", "Subarachnoid hemorrhage"]'::jsonb, 3, 'Xanthochromia results from the breakdown of red blood cells in the CSF and is a key finding supporting subarachnoid hemorrhage, especially when CT is negative but suspicion remains high.', 'Pre-Council', '🎓', true),
(6781, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the classic clinical course of an epidural hematoma?', '["Brief loss of consciousness, a lucid interval, then rapid deterioration", "Gradual decline in consciousness over weeks", "No change in level of consciousness", "Immediate death with no lucid period"]'::jsonb, 0, 'Epidural hematomas classically present with a brief initial loss of consciousness followed by a lucid interval, after which the patient rapidly deteriorates as the arterial bleed expands.', 'Pre-Council', '🎓', true),
(6782, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An epidural hematoma is most commonly caused by injury to which vascular structure?', '["Bridging veins", "Middle meningeal artery", "Circle of Willis", "Superior sagittal sinus only"]'::jsonb, 1, 'Epidural hematomas typically result from arterial bleeding, most classically from a tear of the middle meningeal artery associated with a temporal bone fracture.', 'Pre-Council', '🎓', true),
(6783, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the classic CT appearance of an epidural hematoma?', '["Crescent-shaped hyperdensity", "Diffuse cerebral edema only", "Biconvex (lens-shaped) hyperdensity", "Ring-enhancing lesion"]'::jsonb, 2, 'Because dura is tightly adherent to the skull, arterial epidural blood forms a characteristic biconvex, lens-shaped collection on CT.', 'Pre-Council', '🎓', true),
(6784, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A subdural hematoma most commonly results from tearing of which structure?', '["Middle meningeal artery", "Anterior cerebral artery", "Basilar artery", "Bridging veins"]'::jsonb, 3, 'Subdural hematomas arise from venous bleeding, typically from tearing of the bridging veins that traverse the subdural space between the brain surface and dura.', 'Pre-Council', '🎓', true),
(6785, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the classic CT appearance of a subdural hematoma?', '["Crescent-shaped hyperdensity", "Biconvex (lens-shaped) hyperdensity", "Star-shaped lucency", "Round calcified mass"]'::jsonb, 0, 'Because subdural blood spreads freely along the brain surface rather than being confined by dural attachments, it forms a crescent-shaped collection on CT, unlike the biconvex shape of epidural hematomas.', 'Pre-Council', '🎓', true),
(6786, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which population is at highest risk for developing a chronic subdural hematoma, even after seemingly minor trauma?', '["Healthy young athletes", "Elderly patients and those on anticoagulant therapy, due to brain atrophy stretching bridging veins", "Infants exclusively", "Pregnant women"]'::jsonb, 1, 'Age-related brain atrophy stretches the bridging veins, making them more susceptible to tearing with minor trauma; anticoagulation further increases bleeding risk in this population.', 'Pre-Council', '🎓', true),
(6787, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An intracerebral (intraparenchymal) hematoma is most commonly associated with which chronic condition?', '["Diabetes insipidus", "Hypothyroidism", "Chronic hypertension", "Osteoporosis"]'::jsonb, 2, 'Chronic hypertension causes degenerative changes in small penetrating cerebral arteries, making them prone to rupture and spontaneous intracerebral hemorrhage.', 'Pre-Council', '🎓', true),
(6788, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which hematoma type constitutes a true neurosurgical emergency because rapid arterial bleeding can cause herniation within hours?', '["Chronic subdural hematoma", "A small cerebral contusion", "A cephalohematoma", "Epidural hematoma, due to rapid arterial bleeding causing herniation within hours"]'::jsonb, 3, 'Because epidural hematomas typically involve arterial bleeding, they can expand rapidly and cause life-threatening herniation within hours, making immediate surgical evacuation critical.', 'Pre-Council', '🎓', true),
(6789, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The Kellie-Monro (Monro-Kellie) Doctrine states which of the following?', '["The skull is a rigid, non-expansile compartment; an increase in volume of one intracranial component requires a reciprocal decrease in another to keep ICP constant", "The brain can expand infinitely without pressure changes", "CSF volume is fixed and cannot change", "Cerebral blood flow is independent of ICP"]'::jsonb, 0, 'The Monro-Kellie doctrine describes the fixed, non-compliant cranial vault containing brain, blood, and CSF; a rise in one component''s volume must be offset by a decrease in another to keep ICP stable.', 'Pre-Council', '🎓', true),
(6790, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'According to the Monro-Kellie doctrine, approximately what proportion of intracranial volume is occupied by brain tissue?', '["~50%", "~80%", "~30%", "~10%"]'::jsonb, 1, 'Brain tissue makes up roughly 80% of intracranial volume, with blood and CSF each contributing approximately 10%.', 'Pre-Council', '🎓', true),
(6791, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'According to the Monro-Kellie doctrine, once compensatory mechanisms (CSF displacement, venous compression) are exhausted, further small increases in intracranial volume cause what?', '["No change in ICP", "A linear, predictable rise in ICP", "Sharp, exponential rises in ICP", "A decrease in ICP"]'::jsonb, 2, 'Once the brain''s limited compensatory reserve is depleted, the ICP-volume curve becomes steep, so even small additional volume increases cause disproportionately large, exponential rises in ICP.', 'Pre-Council', '🎓', true),
(6792, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Per the Monro-Kellie doctrine, which two components are displaced early to compensate for a growing intracranial mass lesion?', '["Brain tissue only", "Arterial blood only", "Bone remodeling", "CSF displaced into the spinal subarachnoid space and venous blood displaced out of the cranium"]'::jsonb, 3, 'Early compensation for a growing mass occurs through displacement of CSF into the spinal subarachnoid space and reduction of intracranial venous blood volume, before ICP begins to rise significantly.', 'Pre-Council', '🎓', true),
(6793, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An external ventricular drain (EVD) that is leveled too LOW relative to the reference point will most likely cause what?', '["Over-drainage of CSF, risking ventricular collapse and rebleeding", "Under-drainage of CSF with rising ICP", "No effect on drainage", "Immediate infection"]'::jsonb, 0, 'A drainage chamber positioned too low relative to the reference point creates excessive siphoning pressure, leading to over-drainage, ventricular collapse, and risk of rebleeding.', 'Pre-Council', '🎓', true),
(6794, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An external ventricular drain (EVD) that is leveled too HIGH relative to the reference point will most likely cause what?', '["Excessive CSF drainage", "Under-drainage of CSF with risk of rising ICP", "Automatic alarm shutoff", "Immediate hemorrhage"]'::jsonb, 1, 'If the drainage chamber is positioned too high, less CSF will drain because the pressure threshold for drainage is effectively raised, risking inadequate ICP control.', 'Pre-Council', '🎓', true),
(6795, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the most serious infectious complication associated with prolonged external ventricular drain placement?', '["Otitis media", "Pneumonia", "Ventriculitis/meningitis", "Cellulitis limited to the insertion site only"]'::jsonb, 2, 'Because the EVD provides a direct conduit into the CSF space, prolonged catheter dwell time increases the risk of ventriculitis or meningitis, requiring strict sterile technique.', 'Pre-Council', '🎓', true),
(6796, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When assessing CSF drainage from an EVD, the nurse should specifically document which of the following?', '["Only the total volume at the end of the shift", "Odor only", "Temperature of the fluid", "Color, clarity, and amount of drainage hourly, reporting cloudy or blood-tinged fluid"]'::jsonb, 3, 'Regular assessment of CSF color, clarity, and volume allows early detection of infection (cloudy fluid) or rebleeding (blood-tinged fluid), which require prompt reporting.', 'Pre-Council', '🎓', true),
(6797, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A Licox brain tissue oxygen monitor measures which of the following?', '["Brain tissue oxygen tension (PbtO2)", "Intracranial pressure only", "Cerebral blood flow velocity", "Serum oxygen saturation"]'::jsonb, 0, 'The Licox catheter is a direct brain tissue oxygen monitor that measures local PbtO2, providing information about cerebral oxygenation independent of systemic oxygen saturation.', 'Pre-Council', '🎓', true),
(6798, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is considered the normal range for brain tissue oxygen tension (PbtO2) measured by a Licox monitor?', '["60-100 mmHg", "20-40 mmHg", "5-10 mmHg", "100-150 mmHg"]'::jsonb, 1, 'Normal PbtO2 is generally considered to be approximately 20-40 mmHg; values below this range suggest inadequate cerebral tissue oxygenation.', 'Pre-Council', '🎓', true),
(6799, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A PbtO2 value below which threshold on Licox monitoring is generally considered critical and warrants urgent intervention?', '["Above 40 mmHg", "Above 100 mmHg", "Below 15-20 mmHg", "Below 60 mmHg"]'::jsonb, 2, 'A PbtO2 below approximately 15-20 mmHg indicates cerebral tissue ischemia and requires prompt interventions such as optimizing oxygenation, CPP, and hemodynamics.', 'Pre-Council', '🎓', true),
(6800, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Where is the Licox brain tissue oxygen monitoring catheter typically placed?', '["The subarachnoid space over the spine", "Peripheral muscle tissue", "The ventricle, solely for CSF sampling", "Uninjured white matter of the brain, often in the frontal region"]'::jsonb, 3, 'The Licox catheter is inserted into uninjured (or at-risk penumbral) white matter, commonly in the frontal lobe, to monitor local tissue oxygenation rather than global brain function.', 'Pre-Council', '🎓', true),
(6801, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Kernig''s sign is elicited and considered positive when which of the following occurs?', '["Pain and resistance to knee extension when the hip is flexed to 90 degrees", "Involuntary knee flexion when the neck is passively flexed", "Stiffness of the neck on lateral rotation", "Papilledema on fundoscopic exam"]'::jsonb, 0, 'Kernig''s sign is positive when attempting to extend the knee while the hip is flexed to 90 degrees produces pain and resistance, indicating meningeal irritation.', 'Pre-Council', '🎓', true),
(6802, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Brudzinski''s sign is positive when which of the following occurs?', '["Pain on hip flexion with knee extension", "Involuntary flexion of the hips and knees when the examiner passively flexes the patient''s neck", "Dilation of the pupils with light exposure", "Rigid extension of the leg"]'::jsonb, 1, 'A positive Brudzinski''s sign occurs when passive neck flexion causes involuntary flexion of the hips and knees, reflecting meningeal irritation.', 'Pre-Council', '🎓', true),
(6803, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Nuchal rigidity combined with fever and photophobia most strongly suggests which diagnosis?', '["Simple partial seizure", "Myasthenic crisis", "Meningitis", "Toxic epidermal necrolysis syndrome"]'::jsonb, 2, 'The classic triad of nuchal rigidity, fever, and photophobia is highly suggestive of meningeal inflammation, as seen in meningitis.', 'Pre-Council', '🎓', true),
(6804, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Meningeal signs such as Kernig''s and Brudzinski''s signs occur due to which underlying mechanism?', '["Damage to peripheral motor neurons", "Elevated blood glucose", "Cerebellar infarction", "Irritation/inflammation of the meninges causing reflex muscle spasm on stretch"]'::jsonb, 3, 'Inflammation of the meninges causes reflex spasm of paraspinal and hamstring muscles when the meninges are stretched by neck flexion or leg extension, producing these positive signs.', 'Pre-Council', '🎓', true),
(6805, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When bacterial meningitis has not yet been ruled out, what isolation precaution should the nurse initiate?', '["Droplet precautions until bacterial meningitis is ruled out", "No isolation is needed", "Contact precautions only for viral cases", "Airborne precautions are mandatory for all cases"]'::jsonb, 0, 'Droplet precautions are initiated for suspected bacterial meningitis (e.g., Neisseria meningitidis) until the causative organism is identified and the risk of respiratory droplet transmission is excluded.', 'Pre-Council', '🎓', true),
(6806, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How is status epilepticus defined?', '["Any seizure lasting more than 30 seconds", "A single seizure lasting more than 5 minutes or recurrent seizures without return to baseline consciousness between them", "A seizure with only sensory symptoms", "Two seizures occurring in a lifetime"]'::jsonb, 1, 'Status epilepticus is defined as a single seizure lasting longer than 5 minutes, or recurrent seizures occurring without the patient regaining baseline consciousness between episodes.', 'Pre-Council', '🎓', true),
(6807, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the first-line pharmacologic treatment for status epilepticus?', '["Oral phenytoin", "IV mannitol", "IV benzodiazepine (e.g., lorazepam)", "IV vancomycin"]'::jsonb, 2, 'IV benzodiazepines, such as lorazepam or diazepam, are the first-line agents for terminating status epilepticus due to their rapid onset of anticonvulsant action.', 'Pre-Council', '🎓', true),
(6808, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'If benzodiazepines fail to terminate status epilepticus, which second-line agent is appropriate?', '["Additional oral diazepam", "IV insulin", "A beta-blocker infusion", "Fosphenytoin or levetiracetam IV"]'::jsonb, 3, 'When benzodiazepines fail, second-line IV antiepileptics such as fosphenytoin, levetiracetam, or valproate are administered to achieve sustained seizure control.', 'Pre-Council', '🎓', true),
(6809, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Refractory status epilepticus, unresponsive to first- and second-line agents, requires which level of management?', '["Continuous IV anesthetic infusion (e.g., propofol or midazolam) with continuous EEG monitoring", "Discontinuation of all antiepileptic medications", "Immediate lumbar puncture only", "A switch to an oral anticonvulsant"]'::jsonb, 0, 'Refractory status epilepticus requires continuous infusion of anesthetic agents such as propofol, midazolam, or pentobarbital, with continuous EEG monitoring to confirm seizure suppression.', 'Pre-Council', '🎓', true),
(6810, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the priority nursing action during an active generalized tonic-clonic seizure?', '["Restrain the limbs firmly to stop movement", "Protect the patient from injury, turn to the side, and do not restrain or force objects into the mouth", "Insert an oral airway or tongue blade forcibly", "Leave the patient prone and unattended"]'::jsonb, 1, 'During a seizure, the priority is protecting the patient from injury and maintaining airway patency by turning them to the side; restraining limbs or forcing objects into the mouth can cause injury and should be avoided.', 'Pre-Council', '🎓', true),
(6811, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Nonconvulsive status epilepticus is diagnosed by which of the following?', '["Visible tonic-clonic movements", "Elevated white blood cell count", "Continuous EEG showing ongoing seizure activity despite lack of obvious motor convulsions", "MRI alone"]'::jsonb, 2, 'Nonconvulsive status epilepticus presents with altered mental status but without obvious convulsive movements; diagnosis requires continuous EEG to detect ongoing electrical seizure activity.', 'Pre-Council', '🎓', true),
(6812, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'When a new-onset seizure occurs in an ICU patient, which common metabolic causes should be ruled out early?', '["Elevated hemoglobin", "Mild anemia", "A normal potassium level", "Hypoglycemia and electrolyte imbalance (e.g., hyponatremia)"]'::jsonb, 3, 'Hypoglycemia and electrolyte disturbances such as hyponatremia are common, rapidly correctable metabolic causes of new-onset seizures and should be assessed immediately.', 'Pre-Council', '🎓', true),
(6813, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Rectal or intramuscular benzodiazepine administration for a seizing patient is preferred in which situation?', '["IV access is not immediately available", "IV access is readily available", "The patient is fully conscious and cooperative", "Only for pediatric patients"]'::jsonb, 0, 'When IV access cannot be rapidly obtained, rectal or intramuscular benzodiazepines provide an alternative route to promptly terminate an ongoing seizure.', 'Pre-Council', '🎓', true),
(6814, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the underlying pathophysiology of Guillain-Barre syndrome?', '["Autoimmune destruction of neuromuscular junction receptors", "Autoimmune demyelination of peripheral nerves, often triggered post-infection", "Bacterial infection of the meninges", "Degeneration of dopaminergic neurons"]'::jsonb, 1, 'Guillain-Barre syndrome is an acute autoimmune-mediated demyelinating polyneuropathy of the peripheral nervous system, frequently triggered by a preceding infection.', 'Pre-Council', '🎓', true),
(6815, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the classic pattern of weakness progression in Guillain-Barre syndrome?', '["Descending weakness beginning in the face", "Unilateral weakness only", "Ascending, symmetric weakness beginning in the lower extremities", "Weakness confined to one limb"]'::jsonb, 2, 'GBS classically presents with ascending, symmetric weakness that begins distally in the legs and progresses upward, potentially involving respiratory and bulbar muscles.', 'Pre-Council', '🎓', true),
(6816, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which preceding infection is most classically associated with the development of Guillain-Barre syndrome?', '["Common cold (rhinovirus)", "Urinary tract infection", "Malaria", "Campylobacter jejuni gastroenteritis"]'::jsonb, 3, 'Campylobacter jejuni gastroenteritis is the most commonly identified antecedent infection associated with the subsequent development of Guillain-Barre syndrome via molecular mimicry.', 'Pre-Council', '🎓', true),
(6817, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What reflex finding is characteristic of Guillain-Barre syndrome?', '["Diminished or absent deep tendon reflexes", "Hyperactive reflexes with clonus", "A positive Babinski sign", "Normal reflexes throughout"]'::jsonb, 0, 'Progressive loss of deep tendon reflexes (areflexia) is a hallmark clinical finding in Guillain-Barre syndrome, reflecting peripheral nerve involvement.', 'Pre-Council', '🎓', true),
(6818, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the most critical ongoing nursing assessment for a patient with Guillain-Barre syndrome, given the risk of respiratory failure?', '["Daily weight only", "Serial negative inspiratory force (NIF) and vital capacity measurements", "Hourly blood glucose", "Skin turgor assessment"]'::jsonb, 1, 'Because ascending paralysis can progress to involve respiratory muscles, serial NIF and vital capacity measurements are essential to detect impending respiratory failure before it becomes an emergency.', 'Pre-Council', '🎓', true),
(6819, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which findings indicate impending respiratory failure in a patient with Guillain-Barre syndrome, warranting intubation?', '["Vital capacity greater than 60 mL/kg", "NIF more negative than -80 cmH2O", "Vital capacity less than 15-20 mL/kg or NIF less negative than -20 to -25 cmH2O", "A respiratory rate of 14 breaths/min"]'::jsonb, 2, 'A falling vital capacity below approximately 15-20 mL/kg or an NIF that is less negative than -20 to -25 cmH2O signals significant respiratory muscle weakness requiring elective intubation before crisis develops.', 'Pre-Council', '🎓', true),
(6820, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What are the first-line disease-modifying treatments for Guillain-Barre syndrome?', '["High-dose corticosteroids", "Broad-spectrum antibiotics", "Anticoagulation alone", "IV immunoglobulin (IVIG) or plasmapheresis"]'::jsonb, 3, 'IVIG and plasmapheresis are the evidence-based first-line treatments for GBS; corticosteroids have not been shown to be effective and are not recommended as primary therapy.', 'Pre-Council', '🎓', true),
(6821, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Autonomic dysfunction in Guillain-Barre syndrome may present as which of the following?', '["Labile blood pressure and cardiac arrhythmias", "Stable vital signs unaffected by the disease", "Hypertension exclusively, with no other changes", "Bradycardia is never seen in GBS"]'::jsonb, 0, 'GBS can affect autonomic nerve fibers, causing labile blood pressure, tachycardia or bradycardia, and cardiac arrhythmias that require close hemodynamic monitoring.', 'Pre-Council', '🎓', true),
(6822, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the underlying pathophysiology of Myasthenia Gravis?', '["Demyelination of peripheral nerves", "Autoantibodies against acetylcholine receptors at the neuromuscular junction", "Autoantibodies against myelin basic protein in the CNS", "Toxin-mediated blockade of inhibitory neurotransmitters"]'::jsonb, 1, 'Myasthenia Gravis is an autoimmune disease in which antibodies attack acetylcholine receptors at the postsynaptic neuromuscular junction, impairing neuromuscular transmission.', 'Pre-Council', '🎓', true),
(6823, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the hallmark clinical feature of Myasthenia Gravis?', '["Weakness that is constant and unaffected by rest", "Ascending, symmetric paralysis", "Fluctuating muscle weakness that worsens with activity and improves with rest", "Loss of sensation only"]'::jsonb, 2, 'MG is characterized by fatigable, fluctuating muscle weakness that worsens with sustained activity and improves with rest, distinguishing it from other neuromuscular disorders.', 'Pre-Council', '🎓', true),
(6824, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What are common initial presenting symptoms of Myasthenia Gravis?', '["Foot drop", "Urinary retention", "Severe headache", "Ptosis and diplopia"]'::jsonb, 3, 'Ocular symptoms such as ptosis (drooping eyelids) and diplopia (double vision) are the most common initial presentation of Myasthenia Gravis, reflecting early extraocular muscle involvement.', 'Pre-Council', '🎓', true),
(6825, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which bedside diagnostic test has historically been used to confirm Myasthenia Gravis by temporarily improving muscle weakness?', '["Edrophonium (Tensilon) test", "Kernig''s test", "Apnea test", "Romberg test"]'::jsonb, 0, 'The edrophonium (Tensilon) test involves administering a short-acting acetylcholinesterase inhibitor; a transient improvement in strength supports a diagnosis of Myasthenia Gravis.', 'Pre-Council', '🎓', true),
(6826, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A myasthenic crisis is typically precipitated by which of the following?', '["Excessive anticholinesterase medication", "Undertreatment, infection, stress, or medication noncompliance causing worsening weakness", "Hyperkalemia alone", "Simple sleep deprivation"]'::jsonb, 1, 'Myasthenic crisis occurs when disease control is inadequate, often triggered by infection, physical or emotional stress, surgery, or missed medication doses, leading to severe generalized weakness including respiratory muscles.', 'Pre-Council', '🎓', true),
(6827, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A cholinergic crisis in a patient with Myasthenia Gravis results from which of the following?', '["Insufficient medication dosing", "Autoimmune flare unrelated to medication", "Excessive acetylcholinesterase inhibitor (e.g., pyridostigmine) causing SLUDGE symptoms and muscle weakness", "Viral myocarditis"]'::jsonb, 2, 'Cholinergic crisis results from excessive anticholinesterase medication, causing muscarinic (SLUDGE: salivation, lacrimation, urination, diarrhea, GI upset, emesis) and nicotinic effects including profound muscle weakness.', 'Pre-Council', '🎓', true),
(6828, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How does the Tensilon (edrophonium) test differentiate myasthenic crisis from cholinergic crisis?', '["It has an identical effect in both crises", "It only diagnoses cholinergic crisis", "It has no clinical utility in crisis differentiation", "It improves weakness in myasthenic crisis but worsens weakness in cholinergic crisis"]'::jsonb, 3, 'Because edrophonium is itself a cholinesterase inhibitor, it transiently improves strength in myasthenic crisis (too little acetylcholine effect) but worsens weakness in cholinergic crisis (already excessive acetylcholine effect).', 'Pre-Council', '🎓', true),
(6829, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the antidote for a cholinergic crisis caused by anticholinesterase medication overdose?', '["Atropine", "Naloxone", "Flumazenil", "Protamine sulfate"]'::jsonb, 0, 'Atropine, an anticholinergic agent, is used to counteract the excessive muscarinic effects of a cholinergic crisis caused by anticholinesterase overdose.', 'Pre-Council', '🎓', true),
(6830, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What organism causes tetanus?', '["Clostridium botulinum", "Clostridium tetani", "Neisseria meningitidis", "Listeria monocytogenes"]'::jsonb, 1, 'Tetanus is caused by Clostridium tetani, an anaerobic, spore-forming bacterium that produces the neurotoxin tetanospasmin, typically entering through a contaminated wound.', 'Pre-Council', '🎓', true),
(6831, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the mechanism of action of the tetanospasmin toxin produced in tetanus?', '["Blocks acetylcholine release at the neuromuscular junction, causing flaccid paralysis", "Destroys the myelin sheath", "Blocks release of inhibitory neurotransmitters (GABA/glycine), causing sustained muscle contraction", "Causes direct bacterial invasion of muscle tissue"]'::jsonb, 2, 'Tetanospasmin blocks the release of inhibitory neurotransmitters GABA and glycine in the spinal cord, resulting in unopposed excitatory input and sustained, painful muscle contractions.', 'Pre-Council', '🎓', true),
(6832, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is a classic early sign of tetanus infection?', '["Ptosis", "Ascending flaccid paralysis", "Foot drop", "Trismus (lockjaw)"]'::jsonb, 3, 'Trismus, or lockjaw, caused by sustained masseter muscle spasm, is a classic early presenting sign of tetanus.', 'Pre-Council', '🎓', true),
(6833, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The characteristic facial expression caused by sustained facial muscle spasm in tetanus is known as what?', '["Risus sardonicus", "Mask-like facies of Parkinsonism", "Bell''s palsy droop", "\"Myasthenic snarl\""]'::jsonb, 0, 'Risus sardonicus is the sustained, sardonic grinning expression caused by spasm of the facial muscles in tetanus.', 'Pre-Council', '🎓', true),
(6834, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What environmental management strategy is important for an ICU patient with severe tetanus to reduce spasm triggers?', '["Bright lighting and frequent stimulation", "A quiet, dimly lit, low-stimulation environment minimizing sudden noise and touch", "Loud, continuous monitoring alarms left unmuted", "Frequent unscheduled procedures"]'::jsonb, 1, 'Because tetanic spasms can be triggered by sudden sensory stimuli, a quiet, dimly lit, low-stimulation environment with minimized noise and touch helps reduce the frequency and severity of spasms.', 'Pre-Council', '🎓', true),
(6835, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the preferred antibiotic for treating tetanus?', '["Vancomycin", "Ceftriaxone", "Metronidazole", "Fluconazole"]'::jsonb, 2, 'Metronidazole is the preferred antibiotic for tetanus, as it effectively targets the anaerobic Clostridium tetani and halts further toxin production.', 'Pre-Council', '🎓', true),
(6836, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the correct distinction between a seizure and a convulsion?', '["A convulsion always indicates epilepsy while a seizure does not", "The terms are interchangeable with no clinical distinction", "A convulsion is always non-epileptic in origin", "A seizure is abnormal electrical brain activity, which may or may not produce visible motor convulsions"]'::jsonb, 3, 'A seizure refers to abnormal, excessive electrical brain activity, which may present with visible motor convulsions or, in nonconvulsive seizures, with no visible motor activity at all.', 'Pre-Council', '🎓', true),
(6837, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An aura that a patient experiences before a larger seizure event represents which of the following?', '["A simple partial (focal) seizure that may signal the onset of a larger seizure", "Postictal confusion", "A type of syncope", "A symptom of cholinergic crisis"]'::jsonb, 0, 'An aura is itself a simple focal seizure, often involving sensory or psychic phenomena, that can precede and signal the onset of a secondarily generalized seizure.', 'Pre-Council', '🎓', true),
(6838, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'The postictal state following a seizure is characterized by which of the following?', '["Immediate full alertness following the seizure", "Transient confusion, drowsiness, or focal weakness (Todd''s paralysis) following a seizure", "Permanent paralysis", "Absence of any recovery period"]'::jsonb, 1, 'The postictal period is a normal recovery phase after a seizure, marked by transient confusion, drowsiness, or sometimes focal weakness (Todd''s paralysis) that resolves over minutes to hours.', 'Pre-Council', '🎓', true),
(6839, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is an important safety measure to implement for a patient having a generalized tonic-clonic seizure in an ICU bed?', '["Immediately administer oral medication", "Restrain all extremities tightly", "Pad the side rails and ensure bed rails are raised", "Sit the patient upright immediately"]'::jsonb, 2, 'Padding the side rails and keeping the bed rails raised helps prevent injury from involuntary limb movements during a tonic-clonic seizure.', 'Pre-Council', '🎓', true),
(6840, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'An unresponsive patient shows no abnormal movements, and continuous EEG shows a normal background without epileptiform activity. This clinical picture is best described as what?', '["An active tonic-clonic seizure", "Nonconvulsive status epilepticus", "A myoclonic seizure", "Unconsciousness/coma without seizure activity"]'::jsonb, 3, 'Unresponsiveness without abnormal movements and with a normal EEG background indicates coma or unconsciousness from a cause other than ongoing seizure activity.', 'Pre-Council', '🎓', true),
(6841, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A patient exhibits rhythmic jerking of all four limbs with impaired awareness that correlates with epileptiform discharges on EEG. This is best classified as which of the following?', '["A convulsive seizure", "A simple faint (vasovagal syncope)", "Rigors from fever", "Decerebrate posturing only"]'::jsonb, 0, 'Rhythmic limb jerking with impaired awareness and correlating epileptiform EEG discharges confirms a true convulsive seizure, distinguishing it from nonepileptic mimics.', 'Pre-Council', '🎓', true),
(6842, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Shivering-like rigors from fever can sometimes mimic a seizure. What is the key clinical differentiator?', '["Rigors always cause loss of consciousness", "Rigors do not show epileptiform activity on EEG and consciousness is typically preserved", "Rigors are always followed by a postictal state", "Rigors cannot be distinguished clinically from seizures"]'::jsonb, 1, 'Unlike true seizures, febrile rigors do not correlate with epileptiform EEG activity, and the patient typically remains conscious and able to interact during the episode.', 'Pre-Council', '🎓', true),
(6843, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the most reliable way to distinguish a true epileptic seizure from a psychogenic non-epileptic event (pseudoseizure)?', '["Duration of the event alone", "Whether the patient appears embarrassed afterward", "Continuous video-EEG monitoring correlating clinical events with electrical activity", "The time of day the event occurs"]'::jsonb, 2, 'Continuous video-EEG monitoring, correlating the observed clinical event with simultaneous electrical brain activity, is the gold-standard method to distinguish epileptic seizures from psychogenic non-epileptic events.', 'Pre-Council', '🎓', true),
(6844, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What are the three recognized subtypes of ICU delirium?', '["Acute, chronic, and terminal", "Mild, moderate, and severe", "Reversible, irreversible, and cyclic", "Hyperactive, hypoactive, and mixed"]'::jsonb, 3, 'ICU delirium is classified into hyperactive (agitated), hypoactive (withdrawn/lethargic), and mixed subtypes, which alternate between the two presentations.', 'Pre-Council', '🎓', true),
(6845, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which subtype of delirium is most common in the ICU yet most frequently missed by clinicians?', '["Hypoactive delirium", "Hyperactive delirium", "Mixed delirium", "None of the subtypes are commonly missed"]'::jsonb, 0, 'Hypoactive delirium is the most prevalent subtype in critically ill patients but is often underrecognized because its quiet, withdrawn presentation can be mistaken for fatigue, depression, or sedation.', 'Pre-Council', '🎓', true),
(6846, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which clinical features characterize hyperactive delirium?', '["Withdrawal, lethargy, and decreased responsiveness", "Agitation, restlessness, combativeness, and hallucinations", "Normal alertness with no symptoms", "Isolated memory loss only"]'::jsonb, 1, 'Hyperactive delirium presents with overt agitation, restlessness, combativeness, and sometimes hallucinations or delusions, making it more readily recognized than hypoactive delirium.', 'Pre-Council', '🎓', true),
(6847, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which clinical features characterize hypoactive delirium?', '["Agitation and combativeness", "Seizure activity", "Lethargy, reduced responsiveness, and withdrawal, appearing calm or sedated", "Fixed and dilated pupils"]'::jsonb, 2, 'Hypoactive delirium presents with lethargy, decreased responsiveness, and withdrawal, and the patient may appear falsely calm or simply sedated, contributing to underdiagnosis.', 'Pre-Council', '🎓', true),
(6848, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which factors are major risk factors for the development of ICU delirium?', '["Young age and good baseline cognition", "Early mobilization", "Family presence at the bedside", "Advanced age, mechanical ventilation, benzodiazepine use, immobility, and sleep deprivation"]'::jsonb, 3, 'Advanced age, mechanical ventilation, benzodiazepine exposure, immobility, and sleep deprivation are among the most significant, well-established risk factors for ICU delirium.', 'Pre-Council', '🎓', true),
(6849, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How is delirium best defined?', '["An acute, fluctuating disturbance of attention and awareness with cognitive change, not better explained by pre-existing dementia", "A chronic, progressive, irreversible decline in cognition", "A permanent psychiatric diagnosis", "A normal response to ICU admission requiring no intervention"]'::jsonb, 0, 'Delirium is an acute, fluctuating disturbance of attention and awareness accompanied by additional cognitive change that is not better accounted for by a pre-existing or evolving dementia.', 'Pre-Council', '🎓', true),
(6850, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why is pre-existing cognitive impairment (dementia) considered a risk factor for ICU delirium?', '["It has no relationship to delirium risk", "It lowers cognitive reserve, making the brain more vulnerable to acute insults", "It guarantees delirium will not occur", "It only affects hyperactive delirium risk"]'::jsonb, 1, 'Reduced baseline cognitive reserve in patients with dementia makes the brain more vulnerable to decompensation from acute physiologic stressors, increasing delirium risk.', 'Pre-Council', '🎓', true),
(6851, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'ICU delirium is associated with which of the following patient outcomes?', '["Shorter length of stay", "No effect on outcomes", "Longer ICU/hospital stay, increased mortality, and long-term cognitive impairment", "Improved long-term memory"]'::jsonb, 2, 'ICU delirium is independently associated with prolonged length of stay, increased mortality, and long-term cognitive impairment even after discharge.', 'Pre-Council', '🎓', true),
(6852, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Sepsis and hypoxia contribute to the development of delirium primarily through which mechanism?', '["Direct mechanical brain trauma", "Autoimmune demyelination", "Elevated growth hormone", "Systemic inflammation and impaired cerebral oxygen delivery"]'::jsonb, 3, 'Sepsis and hypoxia trigger systemic inflammation and impair oxygen delivery to the brain, both of which are believed to contribute to the pathophysiology of delirium.', 'Pre-Council', '🎓', true),
(6853, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which sedative class is most strongly associated with increased risk of delirium in ICU patients?', '["Benzodiazepines", "Dexmedetomidine", "Acetaminophen", "Topical anesthetics"]'::jsonb, 0, 'Benzodiazepines are consistently associated with a higher risk of developing ICU delirium compared to alternative sedatives such as dexmedetomidine.', 'Pre-Council', '🎓', true),
(6854, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which standardized tool is most widely used to assess for delirium in mechanically ventilated ICU patients?', '["Glasgow Coma Scale", "CAM-ICU (Confusion Assessment Method for the ICU)", "NIHSS", "APACHE II"]'::jsonb, 1, 'The CAM-ICU is a validated, standardized bedside tool specifically designed to assess for delirium in critically ill patients, including those who are mechanically ventilated and unable to speak.', 'Pre-Council', '🎓', true),
(6855, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'A CAM-ICU assessment is considered positive when which combination of features is present?', '["Feature 1 alone", "All four features must always be present simultaneously", "Feature 1 (acute onset/fluctuating course) AND Feature 2 (inattention) AND either Feature 3 (altered level of consciousness) OR Feature 4 (disorganized thinking)", "Feature 4 alone"]'::jsonb, 2, 'A positive CAM-ICU requires Features 1 and 2 to both be present, plus either Feature 3 or Feature 4, reflecting the core diagnostic criteria for delirium.', 'Pre-Council', '🎓', true),
(6856, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Before performing a CAM-ICU assessment, the nurse must first assess which of the following?', '["Blood pressure trend", "Urine output", "Pain score exclusively", "Level of sedation/arousal using a tool such as the Richmond Agitation-Sedation Scale (RASS)"]'::jsonb, 3, 'Sedation level must be assessed with a tool such as RASS before CAM-ICU testing, because a patient who is too deeply sedated cannot be meaningfully assessed for delirium.', 'Pre-Council', '🎓', true),
(6857, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why can a patient with a RASS score of -4 or -5 not be assessed for delirium at that time?', '["The patient is too deeply sedated/unarousable to participate in attention testing", "The CAM-ICU is invalid in ventilated patients", "RASS has no relation to CAM-ICU assessment", "Delirium cannot occur at this level of sedation"]'::jsonb, 0, 'A RASS of -4 or -5 indicates deep sedation or unresponsiveness, meaning the patient cannot participate in the attention and cognition testing required for a valid CAM-ICU assessment.', 'Pre-Council', '🎓', true),
(6858, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which NANDA nursing diagnosis is most appropriate for a mechanically ventilated patient exhibiting acute delirium?', '["Impaired Physical Mobility related to fracture", "Acute Confusion related to the ICU environment and critical illness", "Deficient Fluid Volume related to hemorrhage", "Risk for Aspiration related to dysphagia only"]'::jsonb, 1, 'Acute Confusion, reflecting the abrupt onset of disturbed consciousness, attention, cognition, and perception related to critical illness and the ICU environment, is the appropriate diagnosis for delirium.', 'Pre-Council', '🎓', true),
(6859, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which is an appropriate expected outcome statement for a patient with the nursing diagnosis Acute Confusion (delirium)?', '["Patient will remain sedated continuously throughout the ICU stay", "Patient will have no further vital sign monitoring", "Patient will demonstrate improved orientation and attention with resolution of fluctuating symptoms by ICU discharge", "Patient will be restrained for the duration of admission"]'::jsonb, 2, 'An appropriate, measurable outcome for Acute Confusion focuses on improvement in orientation and attention with resolution of fluctuating symptoms, reflecting recovery from delirium.', 'Pre-Council', '🎓', true),
(6860, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which additional NANDA nursing diagnosis is applicable to a delirious patient at risk of self-extubation or falls?', '["Impaired Urinary Elimination", "Deficient Knowledge", "Sexual Dysfunction", "Risk for Injury"]'::jsonb, 3, 'Delirious patients with impaired judgment and attention are at increased risk for self-harm, such as accidental self-extubation or falls, making Risk for Injury an appropriate diagnosis.', 'Pre-Council', '🎓', true),
(6861, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How does the Intensive Care Delirium Screening Checklist (ICDSC) differ from the CAM-ICU?', '["It uses an 8-item checklist scored over a full shift rather than a single point-in-time binary assessment", "It can only be used in non-ventilated patients", "It assesses only motor symptoms", "It replaces the need for sedation assessment"]'::jsonb, 0, 'The ICDSC is an 8-item checklist that clinicians score based on observations over an entire shift, in contrast to the CAM-ICU, which provides a binary positive/negative result at a single assessment point.', 'Pre-Council', '🎓', true),
(6862, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'During CAM-ICU attention testing (e.g., the letters vigilance test), which finding indicates inattention?', '["The patient correctly squeezes on every \"A\" with no errors", "The patient makes more than 2 errors squeezing the hand only on the letter \"A\"", "The patient is fully alert and oriented", "The patient has a normal respiratory rate"]'::jsonb, 1, 'During the letters attention test, more than 2 errors (failing to squeeze on "A" or squeezing on a non-"A" letter) indicates inattention, supporting Feature 2 of the CAM-ICU.', 'Pre-Council', '🎓', true),
(6863, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the recommended frequency for delirium screening in critically ill ICU patients per best-practice bundles?', '["Once per hospital admission only", "Only when the family requests it", "At least once per nursing shift (or per unit protocol)", "Only after discharge"]'::jsonb, 2, 'Best-practice ICU bundles recommend routine delirium screening at least once per nursing shift to allow for early detection and prompt intervention.', 'Pre-Council', '🎓', true),
(6864, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which component of the ABCDEF bundle specifically addresses early physical activity to help reduce delirium and ICU-acquired weakness?', '["Family engagement only", "Choice of sedation", "Both spontaneous awakening and breathing trials", "Early mobility and exercise"]'::jsonb, 3, 'The "E" in the ABCDEF bundle stands for Early mobility and exercise, which reduces both delirium duration and ICU-acquired weakness.', 'Pre-Council', '🎓', true),
(6865, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which non-pharmacologic strategies help prevent or reduce ICU delirium?', '["Frequent reorientation, promoting normal sleep-wake cycles, minimizing nighttime noise/light, and early mobilization", "Continuous deep sedation", "Restricting family visitation", "Maximizing environmental stimulation at night"]'::jsonb, 0, 'Frequent reorientation, promotion of normal sleep-wake cycles, minimizing nighttime disruptions, and early mobilization are core evidence-based non-pharmacologic delirium prevention strategies.', 'Pre-Council', '🎓', true),
(6866, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Providing patients with their glasses and hearing aids helps prevent delirium primarily through which mechanism?', '["Curing the underlying infection", "Reducing sensory deprivation/misperception that can precipitate confusion", "Replacing the need for reorientation", "Lowering blood pressure"]'::jsonb, 1, 'Uncorrected sensory impairment can lead to misperception and disorientation; providing glasses and hearing aids reduces sensory deprivation, a modifiable risk factor for delirium.', 'Pre-Council', '🎓', true),
(6867, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why is minimizing physical restraints and invasive tethers (catheters, lines) important in delirium prevention?', '["Restraints reduce delirium risk", "Tethers have no effect on delirium", "Restraints and tethers increase agitation, discomfort, and delirium risk", "Restraints improve sleep quality"]'::jsonb, 2, 'Physical restraints and unnecessary tethers increase patient discomfort and agitation and are themselves risk factors for developing or worsening delirium.', 'Pre-Council', '🎓', true),
(6868, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which strategy best promotes a normal day-night cycle for ICU patients to help prevent delirium?', '["Continuous bright lighting 24 hours a day", "Performing all procedures at night", "Eliminating clocks and calendars", "Clustering care, dimming lights at night, and maximizing natural light during the day"]'::jsonb, 3, 'Clustering nursing care, dimming lights at night, and maximizing natural light exposure during the day helps preserve circadian rhythm and reduce delirium risk.', 'Pre-Council', '🎓', true),
(6869, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why is family engagement encouraged as part of delirium prevention strategies?', '["Familiar voices and presence can aid reorientation and reduce patient anxiety", "Family presence increases delirium risk", "Visitors should be restricted to reduce confusion", "Family involvement has no evidence base"]'::jsonb, 0, 'The presence of familiar family members can help reorient the patient, provide comfort, and reduce anxiety, all of which support delirium prevention.', 'Pre-Council', '🎓', true),
(6870, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How do paired spontaneous awakening trials (SAT) and spontaneous breathing trials (SBT) help reduce delirium?', '["Increasing sedative dosing", "Minimizing cumulative sedative exposure and allowing earlier assessment of neurologic status", "Prolonging mechanical ventilation", "Eliminating the need for pain assessment"]'::jsonb, 1, 'Daily SAT/SBT pairing minimizes cumulative sedative exposure and allows earlier, more accurate neurologic assessment, both of which reduce delirium duration and ventilator days.', 'Pre-Council', '🎓', true),
(6871, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which activities represent appropriate cognitive stimulation for delirium prevention?', '["Complete sensory deprivation", "Prolonged isolation", "Orientation boards, clocks/calendars, and engaging conversation", "Continuous television without interaction"]'::jsonb, 2, 'Providing orientation boards, visible clocks and calendars, and engaging in meaningful conversation helps maintain cognitive stimulation and orientation, reducing delirium risk.', 'Pre-Council', '🎓', true),
(6872, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the first step in the pharmacologic management approach to ICU delirium?', '["Immediately start high-dose benzodiazepines", "Start antipsychotics for all patients regardless of cause", "Sedate to RASS -5 to prevent movement", "Identify and treat underlying reversible causes (pain, hypoxia, infection, metabolic derangement) before adding antipsychotics"]'::jsonb, 3, 'Effective delirium management begins with identifying and correcting reversible contributing causes, such as pain, hypoxia, infection, or metabolic derangement, before considering pharmacologic symptom control.', 'Pre-Council', '🎓', true),
(6873, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which medication class is generally avoided in ICU delirium management (except in cases of alcohol or benzodiazepine withdrawal) because it worsens delirium?', '["Benzodiazepines", "Dexmedetomidine", "Antipsychotics", "Opioids given at appropriate analgesic doses"]'::jsonb, 0, 'Benzodiazepines are generally avoided in delirium management because they can worsen or precipitate delirium; an exception is delirium related to alcohol or benzodiazepine withdrawal.', 'Pre-Council', '🎓', true),
(6874, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which antipsychotic is commonly used for symptom management of severe agitation associated with ICU delirium?', '["Metformin", "Haloperidol", "Furosemide", "Heparin"]'::jsonb, 1, 'Haloperidol is a commonly used antipsychotic for managing severe agitation associated with delirium, although it does not treat the underlying cause and requires cardiac monitoring.', 'Pre-Council', '🎓', true),
(6875, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which sedative agent is preferred over benzodiazepines in mechanically ventilated ICU patients, in part due to its lower associated delirium risk?', '["Lorazepam", "Midazolam", "Dexmedetomidine", "Diazepam"]'::jsonb, 2, 'Dexmedetomidine, an alpha-2 agonist, is associated with a lower incidence of delirium compared with benzodiazepine sedation and is often preferred in mechanically ventilated patients.', 'Pre-Council', '🎓', true),
(6876, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What important cardiac monitoring consideration is associated with administering haloperidol?', '["Monitor for hyperkalemia only", "No cardiac monitoring is needed", "Monitor for bradypnea exclusively", "QT interval prolongation risk requiring ECG monitoring"]'::jsonb, 3, 'Haloperidol carries a risk of QT interval prolongation and torsades de pointes, so baseline and ongoing ECG monitoring is recommended, especially with higher doses or IV administration.', 'Pre-Council', '🎓', true),
(6877, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What does current evidence indicate regarding routine prophylactic antipsychotic use to PREVENT ICU delirium?', '["Evidence does not support routine prophylactic antipsychotic use for prevention; treatment is generally reserved for significant agitation/distress", "Antipsychotics are proven to prevent delirium in all patients", "Antipsychotics should replace all non-pharmacologic measures", "Antipsychotics have no side effects and should be used liberally"]'::jsonb, 0, 'Current evidence does not support routine prophylactic antipsychotic administration to prevent delirium; pharmacologic agents are generally reserved for patients with significant agitation or distress after non-pharmacologic measures are optimized.', 'Pre-Council', '🎓', true),
(6878, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which analgesic strategy helps reduce delirium risk in the ICU?', '["Withholding all analgesia to preserve alertness", "Adequate pain control using validated pain scales, preferring non-opioid adjuncts when possible to minimize opioid burden", "Using benzodiazepines as primary analgesics", "Ignoring pain assessment in sedated patients"]'::jsonb, 1, 'Untreated pain is itself a risk factor for delirium; using validated pain scales to guide adequate analgesia, with judicious use of opioid-sparing adjuncts, helps reduce delirium risk.', 'Pre-Council', '🎓', true),
(6879, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the mechanism of action of dexmedetomidine?', '["A nonselective beta-blocker", "A GABA-A receptor agonist", "A selective alpha-2 adrenergic agonist producing sedation without significant respiratory depression", "An acetylcholinesterase inhibitor"]'::jsonb, 2, 'Dexmedetomidine is a selective alpha-2 adrenergic agonist that provides sedation and analgesia with minimal respiratory depression, distinguishing it from GABA-mediated sedatives like benzodiazepines.', 'Pre-Council', '🎓', true),
(6880, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Why are elderly ICU patients at higher risk for developing delirium?', '["Elderly patients have increased cognitive reserve", "Age has no bearing on delirium risk", "Elderly patients metabolize sedatives faster", "Reduced cognitive reserve, polypharmacy, sensory impairment, and age-related neurochemical changes"]'::jsonb, 3, 'Aging is associated with reduced cognitive reserve, higher rates of polypharmacy, sensory impairment, and neurochemical changes that collectively increase vulnerability to delirium during critical illness.', 'Pre-Council', '🎓', true),
(6881, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Geriatric ICU patients more often present with which delirium subtype, which is easily misattributed to other causes?', '["Hypoactive delirium, which is easily mistaken for depression or fatigue", "Exclusively hyperactive delirium", "No differences in delirium presentation from younger adults", "Delirium presents identically to dementia with no distinguishing features"]'::jsonb, 0, 'Older adults more frequently present with hypoactive delirium, which is often mistaken for depression, fatigue, or simply being a "quiet" patient, contributing to underrecognition.', 'Pre-Council', '🎓', true),
(6882, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which medication class should be used cautiously or avoided in elderly ICU patients due to anticholinergic burden worsening confusion?', '["Dexmedetomidine", "Anticholinergic medications (e.g., diphenhydramine)", "Acetaminophen", "Normal saline"]'::jsonb, 1, 'Anticholinergic medications, such as diphenhydramine, can significantly worsen confusion and precipitate or exacerbate delirium in elderly patients and should generally be avoided.', 'Pre-Council', '🎓', true),
(6883, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is a key distinguishing feature between delirium and dementia in an elderly patient?', '["Both always have an identical acute onset", "Dementia always resolves within days", "Delirium has an acute onset and fluctuating course; dementia has a gradual, progressive onset", "Delirium never affects attention"]'::jsonb, 2, 'Delirium is distinguished from dementia by its acute onset and fluctuating course, along with prominent inattention, whereas dementia develops gradually over months to years.', 'Pre-Council', '🎓', true),
(6884, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What geriatric-specific consideration should guide medication dosing when managing delirium?', '["Use standard adult doses without adjustment", "Avoid all medications regardless of severity", "Double standard doses for faster effect", "Start with lower doses and titrate slowly due to altered pharmacokinetics/pharmacodynamics"]'::jsonb, 3, 'Age-related changes in drug metabolism, distribution, and clearance mean that elderly patients typically require lower starting doses with slow, careful titration to avoid adverse effects.', 'Pre-Council', '🎓', true),
(6885, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How is Toxic Epidermal Necrolysis Syndrome (TENS) best classified?', '["A severe, life-threatening mucocutaneous drug reaction with widespread epidermal detachment", "A viral exanthem", "A bacterial skin infection", "A chronic autoimmune skin condition unrelated to medications"]'::jsonb, 0, 'TENS is a rare but life-threatening mucocutaneous reaction, most often triggered by medications, characterized by widespread epidermal necrosis and detachment.', 'Pre-Council', '🎓', true),
(6886, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'How is TENS distinguished from Stevens-Johnson Syndrome (SJS)?', '["Causative organism", "Percentage of body surface area with epidermal detachment (TEN greater than 30%, SJS less than 10%)", "Patient age only", "Presence of fever"]'::jsonb, 1, 'TENS and SJS exist on a spectrum of the same disease process, distinguished primarily by the percentage of body surface area with epidermal detachment: TEN affects greater than 30%, SJS less than 10%, with 10-30% classified as overlap.', 'Pre-Council', '🎓', true),
(6887, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the most common trigger for TENS?', '["Sunburn", "Viral upper respiratory infection", "Medications (e.g., sulfonamides, anticonvulsants, allopurinol)", "Insect bites"]'::jsonb, 2, 'TENS is most commonly triggered by medications, including sulfonamide antibiotics, anticonvulsants such as phenytoin and carbamazepine, allopurinol, and certain NSAIDs.', 'Pre-Council', '🎓', true),
(6888, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the most important first intervention in suspected TENS?', '["Immediate skin grafting", "Administering more of the suspected drug at a lower dose", "Delaying treatment until biopsy confirms the diagnosis", "Immediate discontinuation of the causative/offending medication"]'::jsonb, 3, 'Prompt identification and discontinuation of the offending medication is the single most important intervention, as continued exposure worsens prognosis and mortality.', 'Pre-Council', '🎓', true),
(6889, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is Nikolsky''s sign?', '["Skin sloughs/separates with gentle lateral pressure, indicating epidermal detachment", "Involuntary knee flexion with neck flexion", "Pain with knee extension when the hip is flexed", "Ipsilateral pupil dilation"]'::jsonb, 0, 'Nikolsky''s sign is positive when gentle lateral pressure on the skin causes the epidermis to slough off, indicating significant epidermal-dermal separation as seen in TENS.', 'Pre-Council', '🎓', true),
(6890, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Because of extensive skin loss, TENS patients are managed most similarly to which other critical care population?', '["Uncomplicated cellulitis patients", "Major burn patients", "Stable post-operative orthopedic patients", "Chronic wound outpatients"]'::jsonb, 1, 'The extensive skin loss, fluid shifts, and infection risk in TENS closely parallel major burn injury, so patients are often managed in a burn unit using burn-care principles.', 'Pre-Council', '🎓', true),
(6891, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the priority fluid management consideration for a TENS patient with extensive skin loss?', '["Fluid restriction to prevent edema", "No intravenous fluids are required", "Aggressive fluid resuscitation to replace massive insensible/exudative fluid losses, similar to burn resuscitation", "Oral fluids only"]'::jsonb, 2, 'Loss of the skin barrier causes massive insensible and exudative fluid losses, requiring aggressive IV fluid resuscitation similar to that used for major burns.', 'Pre-Council', '🎓', true),
(6892, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'TENS patients are at high risk for which serious complication due to loss of the protective skin barrier?', '["Osteoporosis", "Chronic kidney disease", "Peripheral neuropathy", "Sepsis/infection"]'::jsonb, 3, 'Because the skin''s protective barrier is compromised over a large surface area, TENS patients are at very high risk of bacterial invasion and sepsis, a leading cause of death in this condition.', 'Pre-Council', '🎓', true),
(6893, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Because ocular involvement is common in TENS, what is an appropriate management strategy?', '["Early ophthalmology consultation and lubricating/prophylactic eye care to prevent scarring and vision loss", "No eye care is needed", "Immediate enucleation", "Patching both eyes shut permanently"]'::jsonb, 0, 'Mucosal involvement of the eyes is common in TENS and can cause permanent scarring and vision loss; early ophthalmology consultation with prophylactic lubrication and care is essential.', 'Pre-Council', '🎓', true),
(6894, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'What is the purpose of the SCORTEN score in TENS management?', '["Diagnose the causative drug", "Predict mortality risk/prognosis based on clinical and laboratory criteria", "Measure intracranial pressure", "Grade delirium severity"]'::jsonb, 1, 'SCORTEN is a validated severity-of-illness scoring system that uses clinical and laboratory criteria to predict mortality risk in patients with TEN/SJS.', 'Pre-Council', '🎓', true),
(6895, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which NANDA nursing diagnosis is the primary concern for a patient with TENS related to extensive epidermal loss?', '["Impaired Physical Mobility related to fracture", "Disturbed Thought Processes related to head injury", "Impaired Skin Integrity related to epidermal detachment", "Decreased Cardiac Output related to arrhythmia"]'::jsonb, 2, 'Impaired Skin Integrity directly reflects the widespread epidermal detachment that is the primary pathophysiologic problem in TENS.', 'Pre-Council', '🎓', true),
(6896, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which NANDA nursing diagnosis addresses infection risk in a patient with TENS?', '["Risk for Constipation", "Deficient Knowledge related to medication regimen only", "Impaired Gas Exchange related to pneumothorax", "Risk for Infection related to loss of protective skin barrier"]'::jsonb, 3, 'With the skin''s protective barrier compromised over a large body surface area, Risk for Infection is a priority nursing diagnosis in TENS due to the high risk of bacterial invasion and sepsis.', 'Pre-Council', '🎓', true),
(6897, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which NANDA nursing diagnosis addresses fluid status in a TENS patient with extensive exudative fluid losses?', '["Risk for Deficient Fluid Volume related to fluid loss through denuded skin", "Excess Fluid Volume related to renal failure", "Risk for Electrolyte Imbalance is not applicable in TENS", "Fluid Volume status is unrelated to skin integrity"]'::jsonb, 0, 'Massive fluid and protein losses through denuded skin place TENS patients at high risk for fluid volume deficit, similar to major burn patients, making this an appropriate priority diagnosis.', 'Pre-Council', '🎓', true),
(6898, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which is an appropriate expected outcome for a TENS patient with the nursing diagnosis Acute Pain?', '["Patient will be pain-free with no interventions", "Patient will report pain controlled to an acceptable level using a validated pain scale", "Patient will refuse all analgesia", "Pain assessment is unnecessary"]'::jsonb, 1, 'A realistic, measurable outcome for Acute Pain in TENS is achieving pain control to an acceptable level as measured by a validated pain scale, given the severe pain from extensive skin loss.', 'Pre-Council', '🎓', true),
(6899, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which is an appropriate expected outcome for the NANDA diagnosis Risk for Infection in a TENS patient?', '["Patient will develop expected fever as a normal response", "Wound cultures are not needed", "Patient will remain free of signs/symptoms of infection (no fever, purulent drainage, or rising WBC) throughout hospitalization", "Infection risk cannot be monitored"]'::jsonb, 2, 'The expected outcome for Risk for Infection is the absence of signs and symptoms of infection, such as fever, purulent drainage, or rising white blood cell count, throughout the hospital course.', 'Pre-Council', '🎓', true),
(6900, 'Neurology', 'CCN Curriculum — Fundamentals of Critical Care Nursing I', 'Which NANDA nursing diagnosis addresses thermoregulation risk in TENS due to loss of the skin''s insulating and barrier function?', '["Risk for Aspiration", "Impaired Urinary Elimination", "Decreased Cardiac Tissue Perfusion", "Risk for Imbalanced Body Temperature"]'::jsonb, 3, 'Extensive skin loss impairs the body''s normal thermoregulatory barrier, placing TENS patients at risk for hypothermia and heat loss, making Risk for Imbalanced Body Temperature an appropriate diagnosis.', 'Pre-Council', '🎓', true);
